export const SPICES = {
  /* ── EXISTING CLASSICS (22) ── */
  cumin:{id:"cumin",name:"Cumin",icon:"🌿",origin:"Eastern Mediterranean — spread along the Silk Road",region:"middleeast",flavor:["warm","earthy"],intensity:2,form:"Seed or ground",summary:"The backbone of a thousand spice blends, with a deep, dusty warmth.",what:"One of the world's oldest cultivated spices — seeds found in Egyptian tombs. Raw it's acrid; toasted it transforms into something nutty, smoky, and essential.",when:"Bloom whole seeds in hot oil at the start of dals and curries. Add ground to Mexican salsas, chili, and rubs. Toast and grind your own when you want the full effect.",tip:"Toast whole seeds in a dry pan until they smell like brown butter — 60 to 90 seconds.",pairings:["coriander","turmeric","aleppo","fenugreek","mustard"],cuisines:["Indian","Mexican","Middle Eastern","North African","Ethiopian"],nanaNote:"Ground cumin from a jar open two years is dust. Toast your own seeds."},

  coriander:{id:"coriander",name:"Coriander",icon:"🌱",origin:"Southern Europe and the Middle East",region:"europe",flavor:["warm","bright","floral"],intensity:1,form:"Seed or ground",summary:"Quietly floral and citrusy — the spice that makes other spices make sense.",what:"The dried seed of the cilantro plant, tasting almost nothing like the leaf. Warm and gently citrusy with a slightly floral quality that softens heavier spices.",when:"Use whenever cumin is called for — they're natural partners. Essential in garam masala, dukkah, and North African blends.",tip:"Crack whole seeds lightly in a mortar before braises — they release flavour slowly through a long cook.",pairings:["cumin","turmeric","cardamom","fennel","mustard"],cuisines:["Indian","Middle Eastern","North African","Ethiopian","Thai"],nanaNote:"The most polite spice in the rack. Always useful, never a fuss."},

  turmeric:{id:"turmeric",name:"Turmeric",icon:"🟡",origin:"South Asia — cultivated for over 4,000 years",region:"southasia",flavor:["warm","earthy"],intensity:2,form:"Ground (fresh rhizome less common)",summary:"Ancient gold — earthy, slightly bitter, and the colour of the sun.",what:"Stains everything it touches. Earthy and mildly bitter with a faint peppery warmth. Its power is as much visual as culinary.",when:"Bloom in fat at the start of a curry. Add to rice cooking water for golden pilaf. A pinch in scrambled eggs is worth doing once.",tip:"Curcumin is fat-soluble — cook in oil or fat to unlock both flavour and its properties.",pairings:["cumin","coriander","fenugreek","mustard","ginger_powder"],cuisines:["Indian","Sri Lankan","Malaysian","Persian","Middle Eastern"],nanaNote:"Wear an apron. And old shoes. I'm serious, dear."},

  cinnamon:{id:"cinnamon",name:"Cinnamon",icon:"🪵",origin:"Sri Lanka — true cinnamon still primarily from there",region:"southasia",flavor:["warm","floral"],intensity:2,form:"Stick or ground",summary:"Sweet warmth with a gentle edge — equally at home in a tagine or a tart.",what:"Two cinnamons: Ceylon is delicate and floral; cassia is harder and aggressively sweet. Ceylon for savoury and subtle sweet; cassia holds up in bold spiced drinks.",when:"Whole sticks in braising liquids and rice. Ground in spice blends, pastries, and porridges.",tip:"A whole stick in a braise gives a quieter, more integrated flavour than ground. Remove before serving.",pairings:["cardamom","allspice","cloves","star_anise","coriander"],cuisines:["Middle Eastern","South Asian","Mexican","Greek","Moroccan"],nanaNote:"Buy the good Ceylon kind at least once. The difference will rearrange your understanding of what cinnamon is."},

  cardamom:{id:"cardamom",name:"Cardamom",icon:"💚",origin:"Western Ghats of India; also cultivated in Guatemala",region:"southasia",flavor:["floral","warm"],intensity:2,form:"Pod, seed, or ground",summary:"The queen of spices — floral, menthol, and impossibly complex.",what:"Green cardamom pods hold seeds with an aroma simultaneously floral, citrusy, herby, and coolly mentholated. Black cardamom is smoky and camphor-like, used in savoury dishes.",when:"Crack green pods and add to coffee, chai, rice, and biryanis. Use black cardamom in north Indian braises.",tip:"Pre-ground cardamom is a significant downgrade. Buy whole pods, crack them, grind the seeds fresh.",pairings:["cinnamon","cloves","saffron","star_anise","coriander"],cuisines:["Indian","Middle Eastern","Ethiopian","Scandinavian","Moroccan"],nanaNote:"A pinch in your morning coffee. You'll wonder how you drank it without."},

  saffron:{id:"saffron",name:"Saffron",icon:"🌺",origin:"Persia — hand-harvested from Crocus sativus flowers",region:"middleeast",flavor:["floral","bright"],intensity:1,form:"Thread",summary:"The world's most expensive spice — honeyed, metallic, and like nothing else.",what:"Each thread is a dried stigma from a crocus flower — 75,000 flowers per pound. Honey-sweet and slightly metallic with an underlying floral quality.",when:"Steep threads in warm water or stock for 20 minutes before using. Essential in paella, risotto Milanese, Persian rice.",tip:"Two good pinches (about 30 threads) for 4 portions. Always steep first.",pairings:["cardamom","cinnamon","mace","fennel","dried_lime"],cuisines:["Persian","Spanish","Moroccan","Italian","Indian"],nanaNote:"Don't rush it, and don't use too much. Saffron rewards patience and punishes greed."},

  smoked_paprika:{id:"smoked_paprika",name:"Smoked Paprika",icon:"🌶",origin:"La Vera valley, Spain — smoke-dried over oak",region:"europe",flavor:["smoky","warm"],intensity:2,form:"Ground",summary:"Campfire in a jar — the spice that smells like something's been cooking all day.",what:"Made from peppers smoke-dried slowly over oak wood. Deep powder smelling of woodsmoke, tasting of sweet pepper with real barbecue depth. Available sweet, bittersweet, and hot.",when:"Rub onto chicken, pork, or fish before grilling. Stir into aioli and hummus. Essential in Spanish chorizo, patatas bravas, and paella.",tip:"Bloom briefly in hot oil — 20 to 30 seconds — and the smokiness deepens significantly.",pairings:["cumin","aleppo","fennel","mustard","coriander"],cuisines:["Spanish","Portuguese","Turkish","Moroccan","American BBQ"],nanaNote:"The Hungarian stuff is wonderful too, but try the Spanish smoked version first."},

  sumac:{id:"sumac",name:"Sumac",icon:"🔴",origin:"Middle East and Mediterranean — dried berry of Rhus coriaria",region:"middleeast",flavor:["bright"],intensity:1,form:"Ground (coarse, slightly damp)",summary:"Sour, ruby-red, and what the Middle East uses instead of lemon.",what:"Made from dried berries ground into a coarse, slightly tacky powder. Tart and fruity — like lemon but rounder, with a subtle astringency.",when:"Sprinkle over hummus, fattoush, grilled meat, and eggs. Use anywhere you'd reach for lemon but want something more complex.",tip:"Sumac doesn't like heat — its sour notes cook off. Use as a finishing spice, sprinkled at the table.",pairings:["za_atar","aleppo","cumin","coriander","dried_lime"],cuisines:["Lebanese","Turkish","Syrian","Persian","Israeli"],nanaNote:"Keep a small bowl of it on the table, the way some people keep salt."},

  aleppo:{id:"aleppo",name:"Aleppo Pepper",icon:"🫙",origin:"Aleppo, Syria — also grown in Turkey as pul biber",region:"middleeast",flavor:["smoky","warm","bright"],intensity:2,form:"Coarse flakes",summary:"Mild, oily, fruity heat — the chili that tastes of sun-dried tomatoes and dried cherries.",what:"Dried and semi-cured giving the flakes an oily texture and complex fruity flavour. Heat builds slowly. Elements of raisins, tomato, and a hint of cumin.",when:"Scatter over hummus or labneh with olive oil. Use as a finishing pepper over eggs, pasta, pizza. Bloom in oil as a base for sauces.",tip:"Store in the fridge after opening — the oil content makes it prone to rancidity at room temperature.",pairings:["sumac","cumin","smoked_paprika","za_atar","coriander"],cuisines:["Syrian","Turkish","Lebanese","Greek","Italian"],nanaNote:"If you can only add one spice to your rack this year, make it this one."},

  sichuan_pepper:{id:"sichuan_pepper",name:"Sichuan Pepper",icon:"🟣",origin:"Sichuan, China — not a true pepper (Zanthoxylum genus)",region:"eastasia",flavor:["floral","bright","pungent"],intensity:3,form:"Whole berry or ground",summary:"Citrusy, electric, and numbing — the tingle that defines Sichuan cuisine.",what:"Unrelated to black or chili peppers. Its primary compound literally causes a tingling, numbing sensation. Combined with chili it creates the legendary mala (numb-spicy) effect.",when:"Toast lightly and grind for spice rubs, especially duck and pork. Add to Sichuan chili oil. Use in mapo tofu and dan dan noodles.",tip:"Toast briefly over low heat and grind coarse — numbing compounds volatilize with too much heat.",pairings:["star_anise","cumin","gochugaru","cloves","cinnamon"],cuisines:["Sichuan Chinese","Hunanese","Taiwanese"],nanaNote:"It will make your lips tingle the first time. This is correct. Don't panic."},

  star_anise:{id:"star_anise",name:"Star Anise",icon:"⭐",origin:"Northeastern Vietnam and southwestern China",region:"eastasia",flavor:["warm","floral"],intensity:3,form:"Whole star or ground",summary:"Assertive licorice warmth — the spice that makes pho taste like pho.",what:"Dried fruit of a small tree, shaped like an eight-pointed star. More intense and warmer than fennel. Essential to Chinese five-spice.",when:"Add whole to braising liquids, pho broth, mulled wine. A single star is usually enough.",tip:"One star contains an enormous amount of flavour. Overdoing it turns a dish medicinal.",pairings:["cinnamon","sichuan_pepper","cloves","cardamom","fennel"],cuisines:["Chinese","Vietnamese","Indian","French","Indonesian"],nanaNote:"That warm, sweet, faintly exotic smell when pho broth is right — that's star anise."},

  fenugreek:{id:"fenugreek",name:"Fenugreek",icon:"🍀",origin:"Mediterranean and South Asia — one of the oldest recorded spices",region:"southasia",flavor:["warm","earthy"],intensity:3,form:"Seed or ground; leaves (kasuri methi) dried",summary:"Bitter, maple-scented, and alarmingly powerful when overused.",what:"Smells uncannily like maple syrup — used in artificial maple flavouring. Raw the seed is bitter and harsh. Cooked carefully, bitterness softens into something nutty and deeply savoury.",when:"Bloom seeds in hot oil at the start of Indian curries and dals. Add sparingly to spice blends.",tip:"Use less than you think. Start with a quarter teaspoon and build from there.",pairings:["cumin","turmeric","coriander","mustard","cardamom"],cuisines:["Indian","Ethiopian","Egyptian","Yemeni"],nanaNote:"It smells like pancakes and tastes like a lesson in humility. Use less than you planned."},

  fennel:{id:"fennel",name:"Fennel Seed",icon:"🌿",origin:"Mediterranean basin — cultivated since antiquity",region:"europe",flavor:["floral","bright"],intensity:1,form:"Whole seed or ground",summary:"Gently anise-flavoured, sweet, and the digestive spice of the Mediterranean.",what:"Lighter and sweeter anise flavour than star anise. In Indian cuisine seeds are eaten raw after meals as a breath freshener. In Italian cooking they define pork sausages.",when:"Toast and grind for pork rubs and Italian sausage. Add whole seeds to fish dishes and tomato sauces.",tip:"Chew a fennel seed — you'll immediately understand its role as a palate cleanser.",pairings:["coriander","star_anise","saffron","aleppo","smoked_paprika"],cuisines:["Italian","Indian","French Provençal","Greek","Scandinavian"],nanaNote:"Keep a small dish of them by the door. Your guests will reach for them without knowing why."},

  mustard:{id:"mustard",name:"Mustard Seed",icon:"🔵",origin:"Europe and Asia — three species, all ancient",region:"europe",flavor:["pungent"],intensity:3,form:"Whole seed (black/brown/yellow), ground, or prepared",summary:"Inert until cracked — then pungent, sharp, and alive.",what:"Whole seeds are almost flavourless until cracked, ground, or bloomed in hot oil — then an enzyme reaction creates powerful pungent compounds. Black and brown seeds are more intense than yellow.",when:"Pop whole black seeds in hot oil at the start of South Indian curries. Use yellow seeds in European pickles.",tip:"When blooming whole seeds in oil, cover the pan — they pop and spit. Done when popping slows to one per second.",pairings:["turmeric","fenugreek","coriander","cumin","cinnamon"],cuisines:["Indian","French","German","British","Scandinavian"],nanaNote:"The popping step sounds violent. It is. Keep the lid on."},

  cloves:{id:"cloves",name:"Cloves",icon:"🌰",origin:"Maluku Islands, Indonesia — once traded like currency",region:"eastasia",flavor:["warm","pungent"],intensity:3,form:"Whole dried bud or ground",summary:"Intensely warm and numbing — a little is magnificent, too much is overwhelming.",what:"Dried flower buds whose active compound eugenol is literally a dental anaesthetic. The flavour is distinctive, sweet, and almost medicinal.",when:"Stud an onion and add to stocks and braises. Add whole to pickling brines and mulled wine. Use ground very sparingly.",tip:"A single clove in a large pot of stock is usually enough. Ground cloves are roughly three times stronger by weight.",pairings:["cinnamon","star_anise","cardamom","allspice","black_pepper"],cuisines:["Indonesian","Indian","Moroccan","European","Caribbean"],nanaNote:"One clove in a braise. That's all. I mean it."},

  allspice:{id:"allspice",name:"Allspice",icon:"🫐",origin:"Jamaica and Central America — the only major spice grown exclusively in the Western Hemisphere",region:"northamerica",flavor:["warm"],intensity:2,form:"Whole berry or ground",summary:"Clove, cinnamon, and nutmeg in one berry — the foundation of Caribbean cooking.",what:"Dried berry of the Jamaican pepper tree, genuinely tasting like a blend of clove, cinnamon, and nutmeg. Defining spice of jerk seasoning and Scandinavian pickling.",when:"Essential in jerk marinades. Add to brines for pickling. Stir into Moroccan-inspired lamb dishes. Use in holiday baking.",tip:"Ground allspice loses vibrancy quickly — buy in small quantities and replenish often.",pairings:["cinnamon","cloves","gochugaru","smoked_paprika","cardamom"],cuisines:["Jamaican","Caribbean","Levantine","Scandinavian","Moroccan"],nanaNote:"Three berries in a pot of stock. It will take you somewhere."},

  nigella:{id:"nigella",name:"Nigella Seed",icon:"⚫",origin:"Southwest Asia and the Mediterranean",region:"middleeast",flavor:["pungent","warm"],intensity:2,form:"Whole seed",summary:"Peppery, slightly onion-like, with a mysterious herby depth.",what:"Also called black seed, kalonji, or black onion seed. Small black seeds with a complex flavour: peppery, faintly bitter, vaguely herbal. They crunch pleasantly and deliver flavour in little bursts.",when:"Scatter over flatbreads and naan before baking. Sprinkle over cheese, yogurt, and salads. Use in the Bengali five-spice blend panch phoron.",tip:"Nigella doesn't really need toasting — the seed is already fully flavoured.",pairings:["cumin","coriander","mustard","fenugreek","fennel"],cuisines:["South Asian","Middle Eastern","Turkish","Egyptian","Israeli"],nanaNote:"Beautiful seeds. Don't hide them. Put them somewhere they'll be seen."},

  gochugaru:{id:"gochugaru",name:"Gochugaru",icon:"🌶",origin:"Korea — essential to the cuisine since the 16th century",region:"eastasia",flavor:["smoky","bright"],intensity:2,form:"Coarse flakes or fine powder",summary:"Fruity, lightly smoky Korean chili flakes — heat with real flavour.",what:"Sun-dried Korean chili ground into coarse flakes with genuine fruity sweetness, mild smokiness, and brick-red colour. The base of kimchi and countless Korean preparations.",when:"Essential for kimchi paste. Stir into Korean sauces and stews. Bloom in oil for a base sauce.",tip:"Coarse gochugaru is best for kimchi; fine powder is better for sauces. Stock both if you cook Korean food regularly.",pairings:["sichuan_pepper","allspice","smoked_paprika","aleppo","cumin"],cuisines:["Korean"],nanaNote:"There is no true substitution for this. Order it online if you can't find it locally."},

  dried_lime:{id:"dried_lime",name:"Dried Lime (Loomi)",icon:"🟤",origin:"Persia and the Gulf — limes boiled in brine then sun-dried",region:"middleeast",flavor:["bright","floral"],intensity:2,form:"Whole dried fruit, cracked, or ground",summary:"Sour, earthy, and faintly fermented — the souring agent of the Persian Gulf.",what:"Made by boiling fresh limes in salted water then sun-drying until hollow. Intensely sour, slightly fermented, with a depth fresh lemon juice can never replicate.",when:"Pierce whole and add to rice and stews. Crack open and add to Persian soups, Gulf fish dishes, and lamb braises.",tip:"Pierce two or three times with a skewer before adding to a pot for full flavour extraction.",pairings:["saffron","sumac","cumin","turmeric","cardamom"],cuisines:["Persian","Iraqi","Kuwaiti","Bahraini","Gulf Arab"],nanaNote:"I wish more people knew this one. It takes a braise somewhere no lemon can reach."},

  mace:{id:"mace",name:"Mace",icon:"🌸",origin:"Banda Islands, Indonesia — the lacy covering of the nutmeg seed",region:"eastasia",flavor:["floral","warm"],intensity:2,form:"Blade (whole) or ground",summary:"Nutmeg's more delicate, floral sibling — refined and elegant.",what:"The lacy red aril that wraps around the nutmeg seed. Similar to nutmeg but distinctly more floral, lighter, and less intense. Experienced cooks reach for it when nutmeg would be too heavy-handed.",when:"Use in béchamel where nutmeg would be too assertive. Add to fish dishes, potted meats, and English spiced cakes.",tip:"Steep a whole blade in a cream sauce for 5 minutes, then remove — the nuanced flavour it provides beats ground.",pairings:["cardamom","cinnamon","saffron","cloves","fennel"],cuisines:["Indonesian","Indian","Dutch","British","Moroccan"],nanaNote:"People overlook it because they don't know what it is. That's their loss."},

  za_atar:{id:"za_atar",name:"Za'atar",icon:"🌿",origin:"Levant — the blend varies by family and by country",region:"middleeast",flavor:["blend","bright","earthy"],intensity:1,form:"Blend (dried thyme, sumac, sesame, salt)",summary:"The Levant's most essential blend — herby, tangy, nutty, and completely versatile.",what:"Za'atar is both a wild herb and the blend made from it — dried thyme or oregano, sumac, toasted sesame seeds, and salt. Every family and country has a different ratio.",when:"Mix with good olive oil and use as a dip for fresh bread. Spread on flatbread before baking. Rub onto chicken with olive oil and roast.",tip:"The key is olive oil. Za'atar on its own is dry and powdery; mixed with olive oil it becomes something remarkable.",pairings:["sumac","aleppo","coriander","fennel","nigella"],cuisines:["Lebanese","Palestinian","Syrian","Israeli","Jordanian"],nanaNote:"A bowl of za'atar, a drizzle of oil, and good bread. That's a meal."},

  ras_el_hanout:{id:"ras_el_hanout",name:"Ras el Hanout",icon:"✨",origin:"North Africa — the name means 'head of the shop'",region:"africa",flavor:["blend","warm","floral"],intensity:2,form:"Blend (up to 100 spices)",summary:"North Africa's greatest spice blend — warm, floral, complex, and impossible to replicate exactly.",what:"A spice merchant's flex containing anywhere from 10 to over 100 spices. Common components include cumin, coriander, cinnamon, cardamom, turmeric, cloves, ginger, and rose petals.",when:"Rub onto lamb and chicken before roasting. Stir into vegetable tagines, couscous, and lentil soups.",tip:"Quality varies enormously. Taste yours before cooking — if it smells stale, it probably is.",pairings:["cinnamon","coriander","cumin","cardamom","allspice"],cuisines:["Moroccan","Algerian","Tunisian","Libyan","Senegalese"],nanaNote:"No two batches are ever quite alike. That's the beauty of it."},

  /* ── PEPPERS & CHILIES ── */
  black_pepper:{id:"black_pepper",name:"Black Pepper",icon:"⚫",origin:"Kerala, India — the most traded spice in history",region:"southasia",flavor:["pungent","warm"],intensity:2,form:"Whole peppercorn or ground",summary:"The spice that built trade routes — sharp, woody, and quietly essential to almost everything.",what:"Dried unripe fruit of Piper nigrum, briefly boiled then sun-dried. The heat comes from piperine, which also enhances absorption of other compounds. Freshly ground is categorically different from pre-ground.",when:"Finish nearly every savoury dish. Bloom cracked peppercorns in butter for steak au poivre. Add whole to stocks and braises.",tip:"Grind fresh at the table. Pre-ground pepper loses most of its aroma within days.",pairings:["coriander","cumin","cardamom","cloves","allspice"],cuisines:["Global — universal"],nanaNote:"If your pepper grinder has never been refilled, that's the problem. Not the recipe."},

  white_pepper:{id:"white_pepper",name:"White Pepper",icon:"⬜",origin:"Southeast Asia and India — black pepper with hull removed",region:"southasia",flavor:["pungent","earthy"],intensity:2,form:"Whole berry or ground",summary:"Earthier and mustier than black — the choice when heat matters more than aroma.",what:"Black pepper with the outer hull soaked and removed. Sharper and more straightforwardly hot with an earthy, slightly fermented quality. Essential in Chinese cooking for its distinctive character.",when:"Use in white sauces where black specks would show. Essential in Swedish meatballs, Chinese stir-fries, and egg dishes.",tip:"White pepper's heat is more immediate and fades faster than black pepper's. Add later in cooking for full effect.",pairings:["ginger_powder","sichuan_pepper","star_anise","fennel","coriander"],cuisines:["Chinese","Swedish","French","Thai","Vietnamese"],nanaNote:"Don't substitute black pepper in Chinese recipes that call for white. The flavour is genuinely different."},

  long_pepper:{id:"long_pepper",name:"Long Pepper",icon:"🟫",origin:"Northeast India and Nepal — the pepper of the ancient world",region:"southasia",flavor:["warm","pungent","floral"],intensity:3,form:"Whole spike or ground",summary:"The original pepper of antiquity — hotter than black, sweeter, with notes of cardamom and ginger.",what:"Long pepper ruled European spice markets before black pepper displaced it in the 17th century. The dried catkin of Piper longum — pungent heat up front, with sweetness, warm spice, and a floral finish.",when:"Grind over cured meats, game, and rich braises. Use in Ethiopian berbere and medieval-inspired blends. A revelation over chocolate.",tip:"Grind it fine — coarsely ground can be gritty and woody. Works beautifully with black pepper in a blend.",pairings:["black_pepper","cinnamon","cardamom","cloves","ginger_powder"],cuisines:["Ethiopian","South Asian (historical)","Moroccan","Medieval European"],nanaNote:"It's what pepper tasted like before we forgot it. Worth trying at least once."},

  pink_peppercorn:{id:"pink_peppercorn",name:"Pink Peppercorn",icon:"🔴",origin:"Brazil and the Caribbean — not a true pepper (Schinus terebinthifolius)",region:"southamerica",flavor:["floral","bright","pungent"],intensity:1,form:"Whole dried berry",summary:"Delicate, resinous, and faintly fruity — a peppercorn that's more about perfume than heat.",what:"Dried berries of the Brazilian pepper tree, entirely unrelated to true pepper. Mild, aromatic, and slightly resinous with a gentle heat. Beautiful to look at and elegant in flavour.",when:"Crush over fish carpaccio, scallops, soft cheeses, and desserts. Add to beurre blanc and butter sauces. Mix with black and white peppercorns for a visual blend.",tip:"Don't substitute for black pepper — they serve completely different purposes.",pairings:["black_pepper","white_pepper","saffron","lavender_culinary","fennel"],cuisines:["French nouvelle","Brazilian","Californian","Scandinavian"],nanaNote:"Pretty enough to feel decadent, gentle enough not to overwhelm."},

  cubeb_pepper:{id:"cubeb_pepper",name:"Cubeb Pepper",icon:"🟤",origin:"Java, Indonesia — traded via Arab merchants for centuries",region:"oceania",flavor:["pungent","floral","warm"],intensity:2,form:"Whole berry or ground",summary:"Medieval Europe's forgotten pepper — piney, eucalyptus-scented, with allspice undertones.",what:"Piper cubeba looks like black pepper with a tiny tail. Pungent like black pepper but with distinctly aromatic, almost camphor-like qualities. Used heavily in medieval European cooking and still essential in North African blends.",when:"Use in Moroccan ras el hanout. Crush over game meats, lamb, and charcuterie. Experiment in medieval or historical dishes.",tip:"Use sparingly — camphor-like qualities can overwhelm. Half the amount of black pepper you'd use is a good starting point.",pairings:["grains_of_paradise","long_pepper","black_pepper","allspice","cinnamon"],cuisines:["North African","Moroccan","Medieval European","Indonesian"],nanaNote:"Few people use it anymore. That makes it more interesting, not less."},

  grains_of_paradise:{id:"grains_of_paradise",name:"Grains of Paradise",icon:"🟠",origin:"West Africa — the Guinea pepper coast (modern Ghana, Nigeria)",region:"africa",flavor:["pungent","warm","bright"],intensity:2,form:"Whole seed or ground",summary:"West Africa's native pepper — gingery, peppery, citrusy, and vastly underused outside its homeland.",what:"Seeds of Aframomum melegueta, a plant related to cardamom, with a flavour bridging black pepper, ginger, and citrus. Medieval Europeans used them as a black pepper substitute.",when:"Grind over lamb, pork, and game birds. Add to spice rubs with sumac and coriander. Use in craft cocktails and mulled wine. Essential in berbere.",tip:"Grind fresh — the citrus and pepper notes are highly volatile and fade quickly in pre-ground form.",pairings:["cubeb_pepper","long_pepper","coriander","cardamom","cinnamon"],cuisines:["West African","Ethiopian","North African","Craft beverages"],nanaNote:"It grows in the same family as cardamom and tastes like it went on an adventure."},

  urfa_biber:{id:"urfa_biber",name:"Urfa Biber",icon:"🟤",origin:"Urfa, southeastern Turkey — a semi-dried, oil-cured chili",region:"middleeast",flavor:["smoky","warm","earthy"],intensity:2,form:"Oily dried flakes",summary:"Smoky, raisin-dark, and complex — the chili that tastes of dried fruit and slow fire.",what:"Dried in a two-step process: sun-dried by day, then wrapped at night to sweat. The result is an oily, dark, almost chocolatey character with notes of raisins, coffee, and gentle heat.",when:"Sprinkle over labneh, hummus, or yogurt with olive oil. Fold into chocolate brownies for surprising depth. Finishing pepper on lamb and eggplant.",tip:"Store refrigerated — high oil content means it goes rancid faster than most dried chilies.",pairings:["aleppo","sumac","smoked_paprika","cumin","nigella"],cuisines:["Turkish","Syrian","Lebanese","Modern fusion"],nanaNote:"It looks like dried fruit. It tastes like something between a spice and a condiment."},

  kashmiri_chili:{id:"kashmiri_chili",name:"Kashmiri Chili",icon:"❤️",origin:"Kashmir Valley, India — grown for colour as much as heat",region:"southasia",flavor:["smoky","bright"],intensity:1,form:"Whole dried pod or ground",summary:"Mild, brilliantly red, and the secret to tandoori's spectacular colour.",what:"Prized primarily for its vivid red colour and very mild heat. Ground Kashmiri chili gives Indian curries and marinades their characteristic deep red hue without the fire of other chilies.",when:"Essential in tandoori marinades, rogan josh, and butter chicken. Add to curry powders when you want colour without heat.",tip:"Use generously — because the heat is mild, you can add enough for real colour. Two tablespoons where you'd use half a teaspoon of cayenne.",pairings:["cumin","coriander","turmeric","garam_masala","fenugreek"],cuisines:["Kashmiri","North Indian","Pakistani","Punjabi"],nanaNote:"It's the reason restaurant Indian food looks so spectacular. The secret is often just this, and enough of it."},

  chipotle:{id:"chipotle",name:"Chipotle Powder",icon:"💨",origin:"Mexico — dried, smoke-cured jalapeño",region:"northamerica",flavor:["smoky","warm"],intensity:2,form:"Ground powder or dried whole pod",summary:"Jalapeño's smoky, concentrated alter ego — heat wrapped in woodsmoke.",what:"A jalapeño that's been dried and smoked over pecan wood until transformed. The fresh vegetable heat becomes richer, deeper, and smokier.",when:"Add to chili, BBQ rubs, and mole sauces. Stir into mayonnaise. A pinch in chocolate puddings is extraordinary.",tip:"The powder loses smokiness faster than whole dried chipotles. Buy smaller quantities.",pairings:["ancho","cumin","smoked_paprika","coriander","garlic_powder"],cuisines:["Mexican","Tex-Mex","American BBQ","Southwestern"],nanaNote:"It's what happens when a jalapeño slows down. Better for it, I think."},

  ancho:{id:"ancho",name:"Ancho Powder",icon:"🟥",origin:"Mexico — dried poblano pepper",region:"northamerica",flavor:["warm","earthy","smoky"],intensity:1,form:"Whole dried pod or ground",summary:"Mild, earthy, and faintly sweet — the workhorse chili of Mexican cooking.",what:"The dried form of the poblano pepper, one of the 'holy trinity' of Mexican dried chilies. Rich and earthy with notes of dried fruit, chocolate, and raisins. Mild enough to use generously.",when:"Soak whole pods and blend into mole, adobo sauces, and enchilada sauces. Essential in authentic mole negro.",tip:"Toast whole pods in a dry pan for 30 seconds per side before soaking — it deepens the flavour significantly.",pairings:["chipotle","mulato","cumin","cinnamon","smoked_paprika"],cuisines:["Mexican","Tex-Mex","Southwestern"],nanaNote:"It's the starting point for mole, which means it's the starting point for greatness."},

  guajillo:{id:"guajillo",name:"Guajillo",icon:"🌿",origin:"Mexico — dried mirasol chili",region:"northamerica",flavor:["bright","warm"],intensity:2,form:"Whole dried pod or ground",summary:"Tangy, slightly tart, and bright — Mexico's most widely used dried chili.",what:"Dried mirasol chili — tangy rather than deeply earthy, with moderate heat and a slight berrylike, slightly tannic quality. Along with ancho, forms the backbone of countless Mexican sauces.",when:"Soak and blend into red enchilada sauce, birria, tamale filling, and pozole. Use ground in spice rubs.",tip:"The leathery skin takes longer to rehydrate. Soak in boiling water for at least 20 minutes, then discard the soaking water which can be bitter.",pairings:["ancho","chipotle","cumin","dried_oregano","black_pepper"],cuisines:["Mexican","Oaxacan","Central Mexican"],nanaNote:"Learn the three Mexican dried chilies — ancho, guajillo, pasilla — and you'll understand half of Mexican cooking."},

  chile_de_arbol:{id:"chile_de_arbol",name:"Chile de Árbol",icon:"🔥",origin:"Mexico — the tree chili",region:"northamerica",flavor:["smoky","pungent"],intensity:3,form:"Whole dried pod or ground",summary:"Small, fierce, and nutty — the dried chili that bites back.",what:"Small, thin, and bright red-orange. The heat is significant and fairly immediate, with a nutty, slightly smoky flavour that develops when toasted.",when:"Toast whole and add to salsa roja, chili oils, and dried spice blends. A staple in Mexican table salsas.",tip:"Wear gloves when handling. Remove seeds for less heat, keep them for maximum fire.",pairings:["guajillo","ancho","cumin","garlic_powder","dried_oregano"],cuisines:["Mexican","Tex-Mex"],nanaNote:"These are the ones in little jars at Mexican restaurants. Now you know what to buy."},

  pasilla:{id:"pasilla",name:"Pasilla",icon:"🟤",origin:"Mexico — dried chilaca chili",region:"northamerica",flavor:["earthy","warm"],intensity:1,form:"Whole dried pod or ground",summary:"Long, dark, and subtly earthy — the most understated of Mexico's holy trinity.",what:"Dried chilaca, long and very dark brown-black, earthy with notes of dried fruit and chocolate. 'Pasilla' means 'little raisin' in Spanish, an apt description. Its heat is mild.",when:"Essential in mole negro and oaxaqueño. Add to complex dried chili sauces. Best combined with guajillo and ancho.",tip:"Its dark colour deepens sauces beautifully. Toast and soak — it's one of the thicker-skinned dried chilies.",pairings:["ancho","guajillo","cumin","cinnamon","mulato"],cuisines:["Oaxacan","Mexican"],nanaNote:"It's the subtle one in a cast of strong characters. Don't skip it."},

  cayenne:{id:"cayenne",name:"Cayenne Pepper",icon:"🌶",origin:"French Guiana — now grown worldwide",region:"southamerica",flavor:["pungent","smoky"],intensity:3,form:"Ground powder",summary:"Pure, direct heat — the default fiery spice of Western kitchens.",what:"Ground dried cayenne chili at 30,000–50,000 Scoville. Mostly heat with relatively little complexity — a reliable tool for adding fire without changing a dish's character.",when:"Add sparingly to anything needing heat. Bloom in oil to activate the capsaicin. Essential in Cajun seasoning, hot sauces, and curry powders.",tip:"Its heat is bright and fast rather than lingering. For a slow burn, combine with black or long pepper.",pairings:["smoked_paprika","cumin","black_pepper","garlic_powder","dried_oregano"],cuisines:["Global — universal heat source"],nanaNote:"The most honest spice in the rack. It does one thing, and it does it without apology."},

  espelette:{id:"espelette",name:"Espelette Pepper",icon:"🇫🇷",origin:"Espelette, French Basque Country — AOC designation since 2000",region:"europe",flavor:["warm","bright","smoky"],intensity:1,form:"Ground powder",summary:"France's favourite chili — mild, fruity, and so civilised it has an AOC.",what:"Piment d'Espelette is a mildly hot chili grown in a small area of the Basque region. Fruity, almost sweet character with very manageable heat. The Basque use it where others might use black pepper.",when:"Sprinkle over eggs, cheese, grilled fish. Use in Basque piperade and chicken Basquaise. Stir into aioli and vinaigrettes.",tip:"It's expensive for a reason — the AOC designation ensures quality. Don't confuse with generic 'Basque pepper.'",pairings:["smoked_paprika","aleppo","fennel","dried_tarragon","dried_thyme"],cuisines:["Basque","French","Spanish"],nanaNote:"The most polite chili I've ever met. Very French."},

  bird_eye:{id:"bird_eye",name:"Bird's Eye Chili (Dried)",icon:"🌶",origin:"Thailand and Southeast Asia — now grown throughout the tropics",region:"oceania",flavor:["pungent","smoky"],intensity:3,form:"Whole dried or crushed flakes",summary:"Tiny, fierce, and unapologetic — Southeast Asia's essential heat source.",what:"Small, slender, and exceptionally hot (50,000–100,000 Scoville). Dried, they concentrate that fire with less of the fresh vegetable character. The default heat in Thai cooking.",when:"Crush whole into curries, stir-fries, and chili oils. Add to Thai larb, som tum, and curry pastes.",tip:"One dried bird's eye is typically enough for a dish serving four. They vary enormously in heat — taste and adjust.",pairings:["lemongrass_dried","galangal","makrut_lime_leaf","gochugaru","sichuan_pepper"],cuisines:["Thai","Vietnamese","Indonesian","Malaysian","Filipino"],nanaNote:"Respect it. Even dried, it will get in your eyes if you're careless."},

  mulato:{id:"mulato",name:"Mulato Chili",icon:"⬛",origin:"Mexico — a poblano variety dried to near-black colour",region:"northamerica",flavor:["earthy","warm"],intensity:2,form:"Whole dried pod or ground",summary:"Chocolatey, complex, and almost black — the third member of mole's holy trinity.",what:"A specific dried poblano variety, darker and earthier than ancho with distinct chocolate and dried cherry notes. One of the three essential chilies in authentic mole negro.",when:"Essential in mole negro. Toast and soak before blending. Add to braises for dark, complex depth.",tip:"The difference between ancho and mulato is subtle but real — mulato is darker and earthier. If a recipe specifies mulato, the swap matters.",pairings:["ancho","pasilla","cinnamon","cumin","chipotle"],cuisines:["Oaxacan","Mexican"],nanaNote:"One of the three spices that goes into a proper mole. You can't shortcut its chilies."},

  aji_amarillo:{id:"aji_amarillo",name:"Ají Amarillo",icon:"🟡",origin:"Peru — the most important chili in Peruvian cuisine",region:"southamerica",flavor:["bright","warm","floral"],intensity:2,form:"Paste, dried powder, or frozen",summary:"Bright, fruity, and moderately hot — the soul of Peruvian cooking.",what:"Bright orange-yellow with moderate heat and unusually fruity, almost tropical flavour — notes of mango, passion fruit, and citrus. Arguably the most important ingredient in Peruvian cuisine.",when:"Essential in ceviche leche de tigre. Use in ají de gallina, papa a la huancaína, and causa rellena.",tip:"Fresh or frozen is best, but paste is widely available. Dried powder is a more distant substitute.",pairings:["aji_panca","cumin","garlic_powder","coriander","amchur"],cuisines:["Peruvian","Nikkei"],nanaNote:"It tastes like sunshine and moderate regret about not adding more."},

  aji_panca:{id:"aji_panca",name:"Ají Panca (Dried)",icon:"🟫",origin:"Peru — grown on the coast, dried to dark red-brown",region:"southamerica",flavor:["smoky","earthy","warm"],intensity:1,form:"Dried paste or powder",summary:"Deep, smoky, and mild — Peru's quiet background chili.",what:"Dried to a dark maroon-brown with mild heat, deep smoky flavour, and earthy notes of dried fruit. Where ají amarillo is bright and fruity, ají panca is dark and grounded.",when:"Use in Peruvian stews, fish braises, and anticuchos marinade. Blend into adobo pastes.",tip:"Like most dried chilies, it benefits from toasting before use. Paste form keeps well refrigerated.",pairings:["aji_amarillo","cumin","dried_oregano","garlic_powder","smoked_paprika"],cuisines:["Peruvian","Bolivian"],nanaNote:"The smoky counterpart to ají amarillo's brightness. They balance each other beautifully."},

  sweet_paprika:{id:"sweet_paprika",name:"Sweet Paprika",icon:"🍎",origin:"Hungary — the cornerstone of Hungarian cuisine",region:"europe",flavor:["warm","bright"],intensity:1,form:"Ground powder",summary:"Gentle, sweet, and earthy red — the foundation of goulash.",what:"Made from fully ripe sweet peppers dried and ground to brilliant red powder. No heat — just sweet, slightly bitter flavour of dried red pepper with tremendous colour-giving ability.",when:"Essential in Hungarian goulash, paprikash, and stuffed peppers. Use in devilled eggs and potato dishes. Add generously — it won't overwhelm.",tip:"More than you think. Then a little more. Bloom in fat first.",pairings:["smoked_paprika","caraway","marjoram","black_pepper","garlic_powder"],cuisines:["Hungarian","Spanish","Turkish","Middle European"],nanaNote:"More than you think. Then a little more. That's the secret."},

  hot_paprika:{id:"hot_paprika",name:"Hot Paprika",icon:"🌶",origin:"Hungary — the fiery sibling of sweet paprika",region:"europe",flavor:["smoky","pungent","warm"],intensity:3,form:"Ground powder",summary:"All the sweet paprika depth, plus real heat — the Hungarian chili powder.",what:"Spicier pepper varieties retaining both the characteristic sweetness and colour of paprika along with significant capsaicin heat. Essential in Hungarian fisherman's soup.",when:"Use alongside sweet paprika when you want heat with colour. Excellent in spiced sausages and chili blends.",tip:"Mix hot and sweet paprika in different ratios rather than reaching for cayenne — you get the paprika flavour profile with adjustable heat.",pairings:["sweet_paprika","smoked_paprika","caraway","cumin","garlic_powder"],cuisines:["Hungarian","Eastern European","Turkish"],nanaNote:"This is what goulash tastes like before it apologises for itself."},

  /* ── WARM AROMATICS ── */
  cassia:{id:"cassia",name:"Cassia",icon:"🟤",origin:"South China — the commercial 'cinnamon' of most grocery stores",region:"eastasia",flavor:["warm","pungent"],intensity:3,form:"Thick bark roll or ground",summary:"The bold, assertive cousin of true cinnamon — what most people grew up with.",what:"Cinnamomum cassia is what fills most 'cinnamon' jars in supermarkets outside Sri Lanka. The bark is thicker and the flavour more pungent, sweet, and less complex than true Ceylon cinnamon.",when:"Use in robust baked goods, cinnamon rolls, and mulled drinks where you want bold cinnamon impact. Works well in Chinese five spice and chai.",tip:"If a recipe calls for 'cinnamon sticks' and you're buying at a standard grocery store, you're buying cassia. Adjust if you switch to Ceylon — use less.",pairings:["star_anise","cloves","cardamom","ginger_powder","allspice"],cuisines:["Chinese","American baking","South Asian","Middle Eastern"],nanaNote:"It's not wrong. It's just louder."},

  black_cardamom:{id:"black_cardamom",name:"Black Cardamom",icon:"🖤",origin:"Eastern Himalayas — Nepal, Sikkim, and Yunnan province",region:"southasia",flavor:["smoky","earthy","warm"],intensity:3,form:"Whole pod",summary:"Smoky, camphor-dark, and almost medicinal — cardamom's mysterious sibling.",what:"Dried over fire, giving it a strong smoky character completely unlike green cardamom. Dark and medicinal — camphor, menthol, and smoke — with none of the sweetness of the green variety.",when:"Add whole to biryani, dal, and north Indian curries. Essential in certain masalas and braises. Remove before serving.",tip:"One pod per pot is often enough. The smokiness is powerful.",pairings:["cumin","coriander","cardamom","cloves","cinnamon"],cuisines:["North Indian","Nepali","Bhutanese"],nanaNote:"Don't confuse it with green cardamom. They share a name and almost nothing else."},

  nutmeg:{id:"nutmeg",name:"Nutmeg",icon:"🟤",origin:"Banda Islands, Indonesia — the seed inside the same fruit that gives us mace",region:"oceania",flavor:["warm","floral"],intensity:2,form:"Whole nut or ground",summary:"Warm, woody, and faintly sweet — indispensable in both savoury and sweet cooking.",what:"The seed of Myristica fragrans. Warm, sweet, and slightly woody with a faint bitterness. Fresh-grated nutmeg is enormously better than pre-ground, which loses its volatile oils within weeks.",when:"Grate over béchamel, cream sauces, and potato gratin. Add to rice pudding, eggnog, and custards. Essential in Italian-style filled pastas.",tip:"Buy whole nuts and a microplane. Pre-ground nutmeg is essentially sawdust.",pairings:["mace","cloves","cinnamon","cardamom","black_pepper"],cuisines:["Italian","French","Dutch","Caribbean","Indonesian"],nanaNote:"There's a whole nutmeg in my kitchen right now. Replenished, but always there."},

  vanilla:{id:"vanilla",name:"Vanilla",icon:"🤍",origin:"Mexico — the only edible fruit of the orchid family",region:"northamerica",flavor:["floral","warm"],intensity:1,form:"Bean, paste, powder, or extract",summary:"Complex, floral, and uniquely American — the world's most beloved flavour.",what:"The cured seed pods of Vanilla planifolia. Real vanilla has hundreds of flavour compounds creating extraordinary depth — floral, woody, creamy, and warm. Pure extract is categorically different from imitation.",when:"Split and scrape beans into custards and ice cream. Add paste to baked goods and whipped cream. A half bean in rice pudding changes everything.",tip:"Save spent pods — simmer in milk, steep in sugar, or add to cream. A 'spent' vanilla bean still has plenty to give.",pairings:["cardamom","cinnamon","mace","saffron","rose_petals"],cuisines:["French pastry","Global dessert","Mexican","Scandinavian","Indian sweets"],nanaNote:"Real vanilla costs what it costs for a reason. Imitation is not the same thing."},

  grains_of_selim:{id:"grains_of_selim",name:"Grains of Selim",icon:"🟫",origin:"West and Central Africa — also called selim pepper or kimba pepper",region:"africa",flavor:["warm","smoky","pungent"],intensity:2,form:"Whole pod or ground",summary:"West Africa's native smoking spice — woody, resinous, and deeply characteristic.",what:"The dried pods and seeds of Xylopia aethiopica. Woody, resinous, vaguely smoky, slightly bitter, with a faint menthol quality. Fundamental to West African cooking and Ethiopian preparations.",when:"Use in West African soups and stews, Ethiopian berbere, and traditional spiced grilled meats. Add to coffee in some West African traditions.",tip:"Grind the whole dried pod — seeds and all. The pod walls contain significant flavour.",pairings:["grains_of_paradise","cubeb_pepper","long_pepper","coriander","cardamom"],cuisines:["West African","Ethiopian","Cameroonian","Senegalese"],nanaNote:"A spice from the continent where spice trading began. Start there."},

  tonka_bean:{id:"tonka_bean",name:"Tonka Bean",icon:"⚫",origin:"Venezuela and Brazil — the seed of Dipteryx odorata",region:"southamerica",flavor:["floral","warm","bright"],intensity:2,form:"Whole dried seed (grate like nutmeg)",summary:"Vanilla, almond, and fresh-cut hay — the most complex flavouring you've never tasted.",what:"Tonka beans have an extraordinary aroma combining vanilla, almond, cherry, and sweet hay from their primary compound coumarin. Widely used in professional kitchens as a vanilla-and-almond substitute.",when:"Grate tiny amounts over desserts, ice cream, and chocolate. A few passes on a microplane over a custard base is transformative.",tip:"Less is profoundly more. A very small amount over a large batch of ice cream is all you need.",pairings:["vanilla","cardamom","mace","rose_petals","cinnamon"],cuisines:["French pastry","Nordic","Venezuelan","Modern European"],nanaNote:"If you find one, use it sparingly and remember it. You'll think about it for a long time afterward."},

  /* ── SEEDS ── */
  caraway:{id:"caraway",name:"Caraway Seed",icon:"🌿",origin:"Europe and Western Asia — cultivated since at least the Neolithic",region:"europe",flavor:["warm","earthy","bright"],intensity:2,form:"Whole seed or ground",summary:"The taste of European rye bread, sauerkraut, and the soul of Alsatian cooking.",what:"Looks and smells like a cousin of cumin, but distinctly its own — anise-like but earthier, with a hint of citrus. Fundamental to German, Scandinavian, and Eastern European cooking.",when:"Essential in rye bread and pumpernickel. Use in sauerkraut, braised red cabbage, and pork dishes. Good in apple-based dishes.",tip:"Toast briefly in a dry pan before using in savoury applications — softens the anise edge and brings out earthier, nuttier qualities.",pairings:["sweet_paprika","coriander","fennel","anise_seed","dill_seed"],cuisines:["German","Scandinavian","Eastern European","Alsatian","Irish"],nanaNote:"It's not cumin. Don't confuse them. The flavour families are related but the destination is completely different."},

  anise_seed:{id:"anise_seed",name:"Anise Seed",icon:"🌱",origin:"Eastern Mediterranean and Southwest Asia",region:"middleeast",flavor:["floral","bright","warm"],intensity:2,form:"Whole seed or ground",summary:"Sweetly licorice-scented and warming — the flavour behind ouzo, absinthe, and pastis.",what:"Small dried fruit of Pimpinella anisum. Sweet, licorice-like flavour similar to fennel and star anise, but rounder and less resinous. One of the oldest known spices.",when:"Use in Mediterranean pastries — Greek koulourakia, Italian biscotti, French anise bread. Add to sausages and spiced cakes.",tip:"Don't confuse with star anise or fennel — all three taste of licorice but are unrelated and not fully interchangeable.",pairings:["fennel","star_anise","coriander","cardamom","caraway"],cuisines:["Greek","Italian","French","Mexican","Middle Eastern"],nanaNote:"It's in pastis, absinthe, ouzo, and sambuca. Whatever you feel about those, you've already tasted this."},

  dill_seed:{id:"dill_seed",name:"Dill Seed",icon:"🌿",origin:"Mediterranean — cultivated since antiquity",region:"europe",flavor:["warm","bright","herb"],intensity:2,form:"Whole seed or ground",summary:"More potent and caraway-like than dill leaf — the pickling spice par excellence.",what:"Dill seed tastes nothing like the feathery fresh herb — it's more pungent and warm, with notes of caraway and anise. Essential spice in dill pickles.",when:"Use in pickling brines for cucumbers, green beans, and carrots. Add to bread and potato dishes. Essential in dill pickles.",tip:"Use the seeds where you want dill flavour to survive cooking; the herb burns out and goes bitter.",pairings:["caraway","fennel","celery_seed","mustard","bay_leaf"],cuisines:["Scandinavian","Eastern European","German","Indian"],nanaNote:"Fresh dill is for finishing. Dill seed is for cooking. Same plant, almost different ingredients."},

  celery_seed:{id:"celery_seed",name:"Celery Seed",icon:"🟡",origin:"Mediterranean — dried seed of wild celery (Apium graveolens)",region:"europe",flavor:["pungent","earthy","herb"],intensity:2,form:"Whole seed or ground",summary:"Intense, concentrated celery bitterness — the umami backbone of stock-making.",what:"Tiny, beige, and powerfully aromatic — far more intense than fresh celery. Provides concentrated celery flavour and a slightly bitter, earthy depth. Key component of Old Bay seasoning.",when:"Add to coleslaw, potato salad, and egg salad. Use in pickles and brines. Essential in clam chowder and seafood stocks. Stir into Bloody Marys.",tip:"Very small amounts go a long way. Half a teaspoon is often plenty. Too much becomes overwhelmingly bitter.",pairings:["dill_seed","mustard","bay_leaf","caraway","old_bay"],cuisines:["American","British","Eastern European","Scandinavian"],nanaNote:"It's what makes a proper coleslaw taste like it was made by someone who knew what they were doing."},

  ajwain:{id:"ajwain",name:"Ajwain (Carom Seed)",icon:"🌿",origin:"South Asia — one of the most intensely flavoured seeds in Indian cooking",region:"southasia",flavor:["pungent","warm","herb"],intensity:3,form:"Whole seed",summary:"Thyme meets cumin at twice the volume — intensely aromatic and unmistakably Indian.",what:"Contains thymol as its primary aromatic compound, giving it a smell almost identical to thyme but far more concentrated. A tiny pinch delivers an unmistakeable, slightly medicinal, powerfully herbal warmth.",when:"Bloom in hot oil at the start of paratha, dal, and vegetable dishes. Essential in certain Indian breads and puris.",tip:"Toast briefly but carefully — it burns faster than most seeds. A very small amount already carries enormous flavour.",pairings:["cumin","coriander","fenugreek","turmeric","mustard"],cuisines:["Indian","Pakistani","Bangladeshi","Sri Lankan"],nanaNote:"It smells like thyme, then announces it isn't. A very confident little seed."},

  sesame_toasted:{id:"sesame_toasted",name:"Toasted Sesame",icon:"🟡",origin:"Africa — one of the oldest oilseed crops, domesticated 3,000 years ago",region:"africa",flavor:["warm","earthy","umami"],intensity:1,form:"Whole toasted seed or tahini",summary:"Nutty, rich, and deepened by heat — the seed that gained power from being roasted.",what:"Sesame seeds are mild raw. Toasting transforms them into something nutty, rich, and aromatic. White and black sesame seeds differ slightly — black is earthier and more bitter.",when:"Scatter over rice, noodles, salads, and stir-fries. Press into hamburger buns and flatbreads. Grind into tahini.",tip:"Toast in a dry pan over medium heat, stirring constantly — they go from golden to burnt in about 20 seconds.",pairings:["gochugaru","sichuan_pepper","ginger_powder","kombu_powder","shichimi"],cuisines:["Japanese","Chinese","Korean","Middle Eastern","West African"],nanaNote:"Don't use raw sesame seeds where toasted ones are called for. The difference is night and day."},

  poppy_seed:{id:"poppy_seed",name:"Poppy Seed",icon:"🔵",origin:"Mediterranean and Central Asia",region:"europe",flavor:["earthy","warm"],intensity:1,form:"Whole seed",summary:"Mild, nutty, and gently crunchy — the baking spice that makes texture as much as flavour.",what:"From the opium poppy but containing no psychoactive compounds in culinary amounts. Mild, nutty, and slightly sweet with an appealing texture. Blue-grey varieties are standard in European baking; white varieties common in India.",when:"Scatter over bagels, bread, and pastries. Fold into muffins and cookies. Make Polish or Czech poppy seed roll filling (makowiec).",tip:"Ground poppy seeds are used in Indian cooking as a thickening agent in kormas and gravies — the ground form tastes richer and more oil-forward.",pairings:["caraway","sesame_toasted","vanilla","cardamom","lemon"],cuisines:["Central European","Indian","Jewish baking","Middle Eastern"],nanaNote:"Every great bagel shop uses more than you expect."},

  annatto:{id:"annatto",name:"Annatto (Achiote)",icon:"🟠",origin:"Tropical Americas — used by the Mayans for millennia before European contact",region:"northamerica",flavor:["earthy","warm"],intensity:1,form:"Seeds, paste, or powder",summary:"Earthy, mild, and vividly orange-red — nature's food dye that also tastes of something.",what:"Seeds of the Bixa orellana shrub primarily used as a natural colourant. Also has a subtle, slightly earthy, nutty flavour. Oil or lard infused with annatto becomes the foundational fat of countless Latin American preparations.",when:"Infuse seeds in hot oil or lard to create achiote oil — the foundational fat of Puerto Rican, Dominican, and Cuban cooking. Use paste in Yucatecan cochinita pibil.",tip:"Don't eat whole annatto seeds — they're woody and unpleasant. The seeds need to be infused in fat to release colour and flavour. Discard after infusing.",pairings:["cumin","dried_oregano","garlic_powder","chipotle","guajillo"],cuisines:["Mexican (Yucatan)","Puerto Rican","Dominican","Cuban","Filipino"],nanaNote:"The orange in your sofrito isn't paprika. It's this."},

  sansho:{id:"sansho",name:"Sansho Pepper",icon:"🟢",origin:"Japan — native to the country, used since ancient times",region:"eastasia",flavor:["bright","floral","pungent"],intensity:2,form:"Ground powder",summary:"Japan's tingly citrus spice — Sichuan pepper's Japanese cousin, cleaner and more floral.",what:"Zanthoxylum piperitum, closely related to Sichuan pepper but distinctly lighter, more citrusy, and with a cleaner, greener tingle. Sprinkled over freshwater eel (unagi) and used in shichimi togarashi.",when:"Sprinkle over grilled unagi, yakitori, and grilled tofu. Add to ramen and noodle dishes. A pinch over miso soup elevates it.",tip:"Fresh or recently ground sansho is essential — the volatile citrus and numbing compounds fade quickly.",pairings:["sichuan_pepper","shichimi","sesame_toasted","ginger_powder","kombu_powder"],cuisines:["Japanese"],nanaNote:"It prickles your tongue gently and then leaves. Very polite heat."},

  nigella_seed:{id:"nigella_seed",name:"Nigella Seed (Kalonji)",icon:"⚫",origin:"Southwest Asia and the Mediterranean",region:"middleeast",flavor:["pungent","herb"],intensity:2,form:"Whole seed",summary:"Peppery, onion-like, and mysteriously herby — the seed that crowns flatbreads across two continents.",what:"Also called black seed, kalonji, or black onion seed. Unrelated to onion. The small black seeds have a complex flavour: peppery, faintly bitter, vaguely herbal, with a slight onion quality. Crunch pleasantly.",when:"Scatter over naan, flatbreads, and bagels before baking. Sprinkle over cheese and yogurt. Essential in panch phoron.",tip:"Nigella doesn't really need toasting — the seed is already fully flavoured.",pairings:["cumin","coriander","mustard","fenugreek","fennel"],cuisines:["South Asian","Middle Eastern","Turkish","Egyptian","Israeli"],nanaNote:"Beautiful seeds. Don't hide them. Put them somewhere they'll be seen."},

  hemp_seed:{id:"hemp_seed",name:"Hemp Seed",icon:"🟢",origin:"Central Asia — cultivated for millennia as fibre and food",region:"southasia",flavor:["earthy","warm"],intensity:1,form:"Hulled seed or whole",summary:"Mild, nutty, and quietly nutritious — the most underused seed in everyday cooking.",what:"Hulled hemp seeds (hemp hearts) have a mild, slightly nutty flavour similar to pine nuts but softer. They contain no psychoactive compounds and are simply a nutritious, mildly flavoured seed with a pleasant texture.",when:"Scatter over salads, yogurt, and oatmeal. Fold into bread and cracker doughs. Blend into smoothies. Press into a coating for fish or tofu. Add to granola.",tip:"Hemp seeds go rancid relatively quickly at room temperature. Store refrigerated and use within a few months of opening.",pairings:["sesame_toasted","poppy_seed","sunflower","flaxseed","caraway"],cuisines:["Contemporary health cooking","Canadian","Eastern European (traditional)"],nanaNote:"A quiet seed. It doesn't announce itself. That's exactly what some dishes need."},

  /* ── ROOTS & RHIZOMES ── */
  ginger_powder:{id:"ginger_powder",name:"Ground Ginger",icon:"🫚",origin:"South and Southeast Asia — traded for over 3,000 years",region:"southasia",flavor:["warm","pungent","bright"],intensity:2,form:"Ground powder",summary:"Concentrated warmth and zing — different enough from fresh ginger to be its own ingredient.",what:"Made from dried ginger rhizomes and has a distinctly different flavour from fresh — more dry, spicy, and warm, with less of the bright citrusy punch. Ground works better in baked goods and dry spice blends.",when:"Use in gingerbread, cookies, cakes, and chai. Add to spice blends, curry powders, and dry rubs. Essential in ras el hanout.",tip:"The substitution ratio is roughly 1/4 teaspoon ground per tablespoon of fresh grated. They're different enough that the result won't be the same.",pairings:["cinnamon","cardamom","turmeric","cloves","allspice"],cuisines:["Global — baking, curries, spice blends"],nanaNote:"The jar marked 'ginger' in the cabinet and the root in the fridge are related but not the same thing. Know which one your recipe wants."},

  galangal:{id:"galangal",name:"Galangal (Dried)",icon:"🟡",origin:"Southeast Asia — related to ginger but very different in character",region:"oceania",flavor:["pungent","bright","floral"],intensity:2,form:"Dried slices or powder",summary:"Ginger's more complex, eucalyptus-scented cousin — essential in Southeast Asian curries.",what:"Alpinia galanga is a rhizome like ginger but with a markedly different flavour — piney, citrusy, and almost medicinal, with a sharp heat more eucalyptus and pepper than ginger's zing.",when:"Essential in Thai curry pastes, tom yum, and satay. Add to Indonesian rendang and Malay gulai. Use dried slices in braises and soups, removing before serving.",tip:"Rehydrate slices in warm water for 30 minutes before use. Don't substitute directly for ginger — the flavours are distinct.",pairings:["lemongrass_dried","makrut_lime_leaf","bird_eye","turmeric","coriander"],cuisines:["Thai","Indonesian","Malaysian","Cambodian"],nanaNote:"It smells like it knows something ginger doesn't. Both are worth keeping."},

  horseradish_powder:{id:"horseradish_powder",name:"Horseradish Powder",icon:"⚪",origin:"Eastern Europe and Central Asia — used as a condiment and spice for millennia",region:"europe",flavor:["pungent"],intensity:3,form:"Dried ground powder",summary:"Sharp sinus-clearing heat that disappears as quickly as it arrives — the root that bites back.",what:"Contains sinigrin which, when tissue is damaged, produces volatile isothiocyanates — the same compounds responsible for mustard's heat. Intensely pungent but volatile — the heat is immediate and fades fast.",when:"Reconstitute with cold water or cream for a prepared horseradish condiment. Stir into mayonnaise and sour cream. Add to Bloody Mary seasoning and beef marinades.",tip:"Use cold liquids to reconstitute — hot water drives off the volatile compounds responsible for the heat, leaving blandness.",pairings:["dill_seed","mustard","celery_seed","black_pepper","dried_dill"],cuisines:["British","German","Eastern European","Ashkenazi Jewish","American"],nanaNote:"It clears the head and focuses the mind. Better than coffee for some things."},

  wasabi_powder:{id:"wasabi_powder",name:"Wasabi Powder",icon:"💚",origin:"Japan — native to mountain stream valleys; now rare and expensive",region:"eastasia",flavor:["pungent"],intensity:3,form:"Dried powder",summary:"Fierce, fleeting, nasal heat — the real thing is so rare that most wasabi isn't.",what:"True wasabi (Wasabia japonica) is rare and expensive. The powder sold in most places is typically European horseradish, mustard, and green food colouring. Real wasabi has a more complex, greener flavour with heat that fades in seconds.",when:"Reconstitute with cold water for use with sushi and sashimi. Add dry powder to mayonnaise and salad dressings.",tip:"Reconstitute by mixing powder with an equal volume of cold water, then let it sit upside-down for 5 minutes — this allows the compounds to develop fully.",pairings:["sansho","ginger_powder","sesame_toasted","horseradish_powder","mustard"],cuisines:["Japanese"],nanaNote:"Most wasabi isn't. The real thing is worth seeking out at least once."},

  fingerroot:{id:"fingerroot",name:"Fingerroot (Dried)",icon:"🟡",origin:"Southeast Asia — a relative of galangal",region:"oceania",flavor:["warm","pungent","bright"],intensity:2,form:"Dried slices or powder",summary:"Floral, peppery, and mildly bitter — a Southeast Asian rhizome with a flavour all its own.",what:"Boesenbergia rotunda, also called krachai or Chinese ginger. Dried form has a concentrated, slightly bitter, floral-peppery flavour. Used in Thai and Indonesian cooking, particularly in fish dishes and curry pastes.",when:"Add to Thai fish curries and soups. Use in certain Indonesian dishes and Cambodian fish preparations.",tip:"It's milder than galangal but has its own distinct floral quality. If you can't find it, galangal is a closer substitute than regular ginger.",pairings:["galangal","lemongrass_dried","makrut_lime_leaf","turmeric","bird_eye"],cuisines:["Thai","Indonesian","Cambodian"],nanaNote:"One of those spices that reveals Southeast Asian cooking is doing things no other tradition does."},

  zedoary:{id:"zedoary",name:"Zedoary (White Turmeric)",icon:"⬜",origin:"Northeast India and Southeast Asia",region:"southasia",flavor:["earthy","pungent","warm"],intensity:2,form:"Dried slices or powder",summary:"Turmeric's bitter, camphor-scented cousin — used before ginger displaced it in medieval Europe.",what:"Curcuma zedoaria, a rhizome closely related to turmeric with pale almost-white flesh. The flavour is bitter, slightly camphor-like, and earthy — quite unlike turmeric's warm earthiness. A major medieval European spice before ginger became widely available.",when:"Use in Indonesian and Indian preparations where it's still current. Add to certain Ayurvedic preparations and fish dishes.",tip:"It's a niche and an acquired taste. Worth experimenting with if you're interested in historical spice use or Southeast Asian cooking beyond the basics.",pairings:["turmeric","galangal","ginger_powder","fingerroot","coriander"],cuisines:["Indonesian","South Indian","Some Southeast Asian"],nanaNote:"It was famous once and then forgotten. History is full of examples like it."},

  /* ── DRIED HERBS ── */
  bay_leaf:{id:"bay_leaf",name:"Bay Leaf",icon:"🍃",origin:"Mediterranean — native to the Laurel family of the Levant",region:"europe",flavor:["herb","earthy","floral"],intensity:1,form:"Whole dried leaf",summary:"The silent architect of stocks and braises — you notice its absence more than its presence.",what:"Bay laurel leaves dry into a spice almost imperceptible alone but that transforms the depth and complexity of anything cooked with it. Turkish bay is most widely used; California bay is stronger.",when:"Add to stocks, stews, braises, and soups. Include in béchamel milk infusion. Use in pickling brines. Always remove before serving.",tip:"If it smells of nothing, it's doing nothing. Buy whole leaves rather than crumbled and replace them annually.",pairings:["dried_thyme","dried_rosemary","black_pepper","celery_seed","dried_oregano"],cuisines:["French","Mediterranean","British","Indian","Worldwide"],nanaNote:"You don't notice the bay leaf. You notice when it isn't there."},

  curry_leaf:{id:"curry_leaf",name:"Curry Leaf (Dried)",icon:"🌿",origin:"South India and Sri Lanka — unrelated to curry powder",region:"southasia",flavor:["herb","warm","pungent"],intensity:2,form:"Dried leaf (fresh much preferred)",summary:"Nutty, aromatic, and irreplaceable — the spice that defines South Indian cooking.",what:"Leaves from the Murraya koenigii tree, nothing to do with curry powder. Citrusy-savory character. Dried curry leaves are significantly weaker than fresh but still carry the characteristic quality.",when:"Bloom in hot oil at the start of South Indian dals, sambhar, and chutneys. Add to raita and yogurt-based dishes.",tip:"If you can find fresh curry leaves, freeze them — they retain far more flavour than dried. The dried version is a last resort.",pairings:["mustard","cumin","turmeric","fenugreek","asafoetida"],cuisines:["South Indian","Sri Lankan","Malaysian Indian","Singaporean"],nanaNote:"The smell when fresh curry leaves hit hot oil is one of the great aromatic moments in cooking."},

  makrut_lime_leaf:{id:"makrut_lime_leaf",name:"Makrut Lime Leaf (Dried)",icon:"💚",origin:"Southeast Asia — native to Thailand, Indonesia, and surrounding regions",region:"oceania",flavor:["bright","floral","herb"],intensity:2,form:"Dried whole leaf (fresh or frozen preferred)",summary:"Intensely citrusy and floral — the leaf that makes Thai curries smell like paradise.",what:"Citrus hystrix leaves have a highly distinctive figure-eight shape and an extraordinarily intense citrus-floral aroma. Dried leaves are weaker than fresh but still aromatic. Both the leaf and the zest are used.",when:"Add dried leaves to Thai green and red curry, tom kha, and Southeast Asian soups. Infuse in coconut milk and cream.",tip:"Dried leaves work in cooked applications where they steep and flavour a liquid. For anything raw or finely shredded, only fresh or frozen will do.",pairings:["lemongrass_dried","galangal","bird_eye","turmeric","galangal"],cuisines:["Thai","Indonesian","Malaysian","Cambodian","Laotian"],nanaNote:"It smells like lime decided to also be a flower. There's nothing quite like it."},

  pandan:{id:"pandan",name:"Pandan Leaf (Dried/Powder)",icon:"💚",origin:"Southeast Asia — native to tropical Asia and the Pacific",region:"oceania",flavor:["floral","herb","warm"],intensity:1,form:"Dried leaf, extract, or powder",summary:"Southeast Asia's vanilla — sweetly grassy, floral, and faintly nutty.",what:"Called the 'vanilla of the East' for its role as the primary dessert flavouring across Southeast Asia. Uniquely sweet, grassy, and floral with a hint of basmati-like nuttiness.",when:"Add a dried leaf to rice while cooking for Southeast Asian fragrance. Use powder or extract in kuih, cakes, and coconut desserts.",tip:"The extract can vary enormously in quality. Fresh or frozen leaves are best for savoury rice.",pairings:["coconut","cardamom","vanilla","lemongrass_dried","galangal"],cuisines:["Malaysian","Singaporean","Indonesian","Thai","Filipino"],nanaNote:"It turns rice an imperceptibly pale green and makes it smell extraordinary. There's no substitute."},

  dried_oregano:{id:"dried_oregano",name:"Dried Oregano",icon:"🌿",origin:"Mediterranean — the most important wild herb of Greece, Turkey, and Italy",region:"europe",flavor:["herb","pungent","warm"],intensity:2,form:"Dried leaf",summary:"Earthy, slightly peppery, and robust — the herb that improves with drying.",what:"One of the rare herbs that becomes more flavourful dried rather than less. Essential oils concentrate into something more assertive and warm. Greek and Turkish oregano is most pungent; Mexican oregano has a more citrusy, lemon-verbena quality.",when:"Essential in pizza sauce, tomato sauces, and Greek salads. Use in lamb and chicken marinades. Add to za'atar blends.",tip:"Rub dried oregano between your palms over the dish to bruise and release the essential oils. This simple step makes a noticeable difference.",pairings:["dried_thyme","bay_leaf","smoked_paprika","garlic_powder","fennel"],cuisines:["Greek","Italian","Turkish","Mexican","Middle Eastern"],nanaNote:"It smells better out of the jar than anything should. That's why Greek food smells the way it does."},

  dried_thyme:{id:"dried_thyme",name:"Dried Thyme",icon:"🌿",origin:"Mediterranean — cultivated since ancient times",region:"europe",flavor:["herb","earthy","warm"],intensity:2,form:"Dried leaf",summary:"The quiet essential — woody, earthy, and the herb that holds French cooking together.",what:"More resinous and concentrated than fresh thyme, with notes of pine, earth, and a faint camphor quality. Performs beautifully in long braises where fresh herbs would burn out.",when:"Add to braises, stews, soups, and stocks. Use in rubs for chicken, lamb, and pork. Essential in herbes de Provence and bouquet garni.",tip:"About a third as much dried as you'd use fresh. For finishing dishes, fresh thyme is preferable.",pairings:["bay_leaf","dried_rosemary","dried_oregano","black_pepper","garlic_powder"],cuisines:["French","Mediterranean","British","American Southern"],nanaNote:"A pinch in nearly everything. That's not laziness — that's understanding what thyme does."},

  dried_rosemary:{id:"dried_rosemary",name:"Dried Rosemary",icon:"🌿",origin:"Mediterranean — the herb of remembrance and roasts",region:"europe",flavor:["herb","pungent","warm"],intensity:3,form:"Dried sprig or crumbled",summary:"Resinous, piney, and assertive — the herb that announces itself in any dish.",what:"Dried rosemary is intense — the oils concentrate powerfully when moisture is removed. The pine-resin quality becomes dominant. Used with a light hand it's extraordinary; used carelessly it overwhelms.",when:"Use in lamb and chicken marinades, potato roasts, and focaccia. Infuse in olive oil. Add to bread and pasta doughs.",tip:"Grind dried rosemary before adding to dishes that need it well-distributed — whole dried leaves can be sharp to bite into.",pairings:["dried_thyme","garlic_powder","black_pepper","fennel","lemon"],cuisines:["Italian","French Provençal","Greek","British","Spanish"],nanaNote:"It's never subtle, so don't use it subtly. Use it with intention."},

  dried_sage:{id:"dried_sage",name:"Dried Sage",icon:"🌿",origin:"Mediterranean coasts",region:"europe",flavor:["herb","earthy","pungent"],intensity:2,form:"Dried leaf or rubbed/ground",summary:"Musky, earthy, and impossible to mistake — the herb of brown butter and British stuffing.",what:"Intensely earthy and musky with slight camphor notes. Powerful enough to stand up to rich, fatty foods (pork, butter, cream) and traditional in both British Christmas stuffing and Italian saltimbocca.",when:"Brown in butter for sage butter sauce over pasta and gnocchi. Use in pork and sausage seasonings. Add to stuffings and poultry brines.",tip:"Dried sage is about twice as strong as fresh. Use half the amount. Rub between your fingers before adding to release essential oils.",pairings:["dried_thyme","dried_rosemary","black_pepper","nutmeg","allspice"],cuisines:["Italian","British","American traditional","German"],nanaNote:"Brown butter + sage + pasta. Three things, one of the best dishes you'll ever make."},

  dried_tarragon:{id:"dried_tarragon",name:"Dried Tarragon",icon:"🌿",origin:"Central Asia — the defining herb of classic French cuisine",region:"europe",flavor:["herb","floral","bright"],intensity:1,form:"Dried leaf",summary:"Anise-sweet and quietly elegant — the French herb that elevates chicken into something more.",what:"Gentle anise character that's more elegant and less assertive than fennel. The dried form is noticeably weaker than fresh — this is one of the herbs most worth buying fresh.",when:"Use in béarnaise sauce (essential), chicken tarragon braise, and cream sauces. Add to vinaigrettes and egg salads.",tip:"This is one herb genuinely worth finding fresh if possible. Dried tarragon in cold applications is a poor substitute.",pairings:["fennel","bay_leaf","dried_thyme","anise_seed","caraway"],cuisines:["French","Belgian","Eastern European","Russian"],nanaNote:"It's what béarnaise smells like. That smell is reason enough to know it."},

  epazote:{id:"epazote",name:"Epazote (Dried)",icon:"🌿",origin:"Mexico and Central America — used since pre-Columbian times",region:"northamerica",flavor:["herb","pungent","earthy"],intensity:3,form:"Dried leaf",summary:"Pungent, medicinal, and uniquely Mexican — the herb that makes black beans taste like themselves.",what:"Dysphania ambrosioides has a powerfully distinctive, almost turpentine-like pungency. Used primarily with black beans in Mexican cooking — traditionally not just for flavour but to reduce gas-producing qualities.",when:"Add a sprig to black bean pots — it's traditional and genuinely effective. Use in green salsa and certain tamale preparations.",tip:"Less is more until you know the herb. Start with a small amount and adjust.",pairings:["chipotle","ancho","guajillo","cumin","dried_oregano"],cuisines:["Mexican","Guatemalan","Central American"],nanaNote:"It smells like it might be doing something good for you. It probably is."},

  dried_mint:{id:"dried_mint",name:"Dried Mint",icon:"🌿",origin:"Mediterranean — one of the oldest cultivated herbs",region:"middleeast",flavor:["herb","bright","floral"],intensity:2,form:"Dried leaf",summary:"Cool, fresh, and versatile — the herb that bridges sweet and savoury across two continents.",what:"More concentrated, slightly duller version of fresh mint's bright cool character. Lacks the volatile freshness of the leaf but retains real flavour for cooked applications.",when:"Essential in Middle Eastern fattoush, yogurt-based dips, and Turkish lentil soup. Add to lamb dishes, meatballs, and falafel. Brew as herbal tea.",tip:"For raw, cold preparations, only fresh mint will do. Dried mint is for cooked dishes and warm infusions.",pairings:["sumac","za_atar","dried_oregano","cumin","dried_lime"],cuisines:["Middle Eastern","Turkish","Greek","Iranian","British mint sauce"],nanaNote:"The English add it to lamb sauce. The Levantines add it to everything. Both are right."},

  kasuri_methi:{id:"kasuri_methi",name:"Kasuri Methi",icon:"🌿",origin:"Northwest India and Pakistan — dried leaves of the fenugreek plant",region:"southasia",flavor:["herb","warm","earthy"],intensity:2,form:"Dried crushed leaf",summary:"Grassy, maple-sweet, and distinctive — the finishing herb of North Indian restaurant kitchens.",what:"The dried leaf of the fenugreek plant — almost nothing like the seed. Grassy, slightly bitter, carrying a characteristic sweet maple quality. The secret ingredient crushed over butter chicken at the last minute.",when:"Crumble over butter chicken, dal makhani, and paneer dishes just before serving. Add to bread doughs and roti for a distinctive flavour.",tip:"Rub between your palms before adding — this bruises the dried leaf and releases the essential oils. Add at the very end of cooking.",pairings:["fenugreek","cumin","coriander","turmeric","garam_masala"],cuisines:["North Indian","Pakistani","Punjabi"],nanaNote:"That smell from a good Indian restaurant kitchen — the one you can't quite place — often, it's this."},

  dried_dill:{id:"dried_dill",name:"Dried Dill Weed",icon:"🌿",origin:"Mediterranean — cultivated since antiquity",region:"europe",flavor:["herb","bright","floral"],intensity:1,form:"Dried feathery leaf",summary:"Feathery, delicately anise-like, and distinctly Scandinavian — gentler than dill seed.",what:"Dried dill weed has a delicate, slightly anise-like, grassy flavour. It's gentler than dill seed and best used in applications where you want a soft dill presence without the seed's more assertive heat.",when:"Use in yogurt and sour cream sauces, potato dishes, cucumber salads, and seafood. Add to herb dips and cream cheese spreads.",tip:"Buy dill weed in small quantities and replace often — it loses aroma faster than almost any other dried herb.",pairings:["dill_seed","celery_seed","mustard","lemon","bay_leaf"],cuisines:["Scandinavian","Eastern European","Greek","Russian","Jewish deli"],nanaNote:"The Scandinavians understand dill better than anyone. When in doubt, look to them."},

  marjoram:{id:"marjoram",name:"Marjoram",icon:"🌿",origin:"Mediterranean — native to Cyprus and Turkey, related to oregano",region:"europe",flavor:["herb","floral","warm"],intensity:1,form:"Dried leaf",summary:"Sweeter, more delicate oregano — the Mediterranean herb that restraint built.",what:"Origanum majorana — sweeter, more floral, and gentler than oregano. Works well in dishes where you want herb flavour without dominance. Common in German and Central European cooking.",when:"Add to sausages, meat loaf, and pâté. Use in herb stuffings and egg dishes. A traditional component of certain Central European spice blends.",tip:"More delicate than oregano — add toward the end of cooking. Long cooking dulls it.",pairings:["dried_thyme","dried_sage","caraway","sweet_paprika","bay_leaf"],cuisines:["German","Austrian","Hungarian","Italian","French"],nanaNote:"Oregano, but quiet. There's a place for quiet."},

  savory:{id:"savory",name:"Savory (Dried)",icon:"🌿",origin:"Mediterranean — summer and winter savory, both ancient",region:"europe",flavor:["herb","pungent","warm"],intensity:2,form:"Dried leaf",summary:"Peppery, resinous, and the traditional companion to all things bean.",what:"Summer savory is milder and slightly sweeter; winter savory is more pungent and resinous. Both have a peppery, thyme-like character. Summer savory is called the 'bean herb' across many European traditions.",when:"Add to bean and lentil dishes, sausages, and stuffings. Use in Provençal spice blends. Add to marinades and rubs for lamb and pork.",tip:"Winter savory is more assertive — use less than you would summer savory. Both are worth having.",pairings:["dried_thyme","marjoram","dried_sage","bay_leaf","black_pepper"],cuisines:["French Provence","German","Bulgarian","Eastern European"],nanaNote:"Put it in every pot of beans. You will never go back."},

  lemongrass_dried:{id:"lemongrass_dried",name:"Lemongrass (Dried)",icon:"🌾",origin:"South and Southeast Asia — cultivated throughout the tropics",region:"oceania",flavor:["bright","floral","herb"],intensity:2,form:"Dried sliced stalk or powder",summary:"Citrusy, floral, and grassy — the scent of Southeast Asian cooking.",what:"A tall grass with a tightly packed, woody stalk. Fresh lemongrass has a bright, citrusy, floral aroma — dried retains much of this but becomes more concentrated. The dried form is useful when fresh isn't available.",when:"Add dried stalks to Thai soups, broths, and braises. Rehydrate in warm water before using in curry pastes. Use ground powder in spice rubs for seafood and chicken.",tip:"Freeze fresh lemongrass instead of drying it — frozen retains far more volatile aromatic compounds.",pairings:["galangal","makrut_lime_leaf","bird_eye","ginger_powder","turmeric"],cuisines:["Thai","Vietnamese","Indonesian","Malaysian","Cambodian"],nanaNote:"The smell of this in a curry paste is the exact smell that makes people stop and say, what is that?"},

  dried_basil:{id:"dried_basil",name:"Dried Basil",icon:"🌿",origin:"South Asia and Africa — domesticated and spread by trade",region:"europe",flavor:["herb","floral","warm"],intensity:1,form:"Dried leaf",summary:"A pale shadow of fresh — but still useful as a background herb in cooked applications.",what:"Dried basil loses most of the fresh herb's bright, peppery, anise-clove character. What remains is a gentler, more earthy herb flavour with its place in tomato sauces.",when:"Add to long-simmered tomato sauces early in cooking. Use in Italian spice blends for meat rubs. Stir into pizza dough.",tip:"For raw preparations or as a finishing herb, dried basil won't substitute for fresh. For early-cook tomato sauces, dried is workable.",pairings:["dried_oregano","dried_thyme","garlic_powder","fennel","black_pepper"],cuisines:["Italian","French","Mediterranean","American Italian"],nanaNote:"The fresh is better. We both know it. But we use what we have."},

  lovage_seed:{id:"lovage_seed",name:"Lovage Seed",icon:"🟡",origin:"Southern Europe — used since Roman times",region:"europe",flavor:["pungent","herb","earthy"],intensity:3,form:"Whole seed or ground",summary:"Intensely celery-like and powerfully aromatic — the forgotten herb of European kitchens.",what:"Levisticum officinale — the seed is the most potent part, very similar to celery seed but more complex with slightly more anise and bitterness. Used by Romans and largely forgotten since.",when:"Use where you'd use celery seed — stocks, soups, stews, bread. Add to spice rubs for beef and lamb.",tip:"Treat it like celery seed — small amounts make a significant contribution. Roughly twice as intense.",pairings:["celery_seed","dill_seed","caraway","bay_leaf","black_pepper"],cuisines:["British","Northern European"],nanaNote:"Romans loved it. That's reason enough."},

  /* ── SOUR & TART ── */
  amchur:{id:"amchur",name:"Amchur (Mango Powder)",icon:"🟡",origin:"North India — made from unripe green mangoes, dried and ground",region:"southasia",flavor:["bright"],intensity:1,form:"Ground powder",summary:"Tangy, fruity, and uniquely Indian — souring power without any moisture.",what:"Made from green mango slices dried and ground to a pale yellowish powder. Sour and slightly fruity — similar to tamarind but lighter, with a more distinctly fruity character. Invaluable as a dry souring agent.",when:"Dust over chaat and street food snacks. Add to dry spice rubs. Stir into chutneys. Works as a dry substitute for lemon juice in spice blends.",tip:"Use it like salt, adjusting until the acidity is right. Blends invisibly into dry preparations.",pairings:["cumin","coriander","chaat_masala","garam_masala","kashmiri_chili"],cuisines:["North Indian","Pakistani","Chaat street food"],nanaNote:"It makes things taste brighter without making them taste wetter. That's more useful than it sounds."},

  kokam:{id:"kokam",name:"Kokam",icon:"🟣",origin:"Western Ghats coastal India — the fruit of Garcinia indica",region:"southasia",flavor:["bright","earthy"],intensity:2,form:"Dried fruit rind",summary:"Sour, fruity, and distinctly coastal Indian — tamarind's tropical sibling.",what:"Dried rind of a small purple-black fruit native to the Konkan coast. Fruity, tart, and slightly sweet with a cooling quality different from tamarind or citrus. Primary souring agent of Goan and Konkani cooking.",when:"Add to Goan fish curries, dal kokam, and coconut-based coastal dishes. Excellent in solkadhi (a cooling pink drink).",tip:"Soak 3-4 kokam pieces in warm water for 10-15 minutes and use the liquid rather than the fruit itself.",pairings:["coconut","cumin","coriander","turmeric","ginger_powder"],cuisines:["Goan","Konkani","Maharashtrian coastal"],nanaNote:"Tamarind gets all the attention, but on the Konkan coast, this is what souring means."},

  tamarind_powder:{id:"tamarind_powder",name:"Tamarind Powder",icon:"🟫",origin:"Africa — now central to Indian, Southeast Asian, and Latin American cooking",region:"africa",flavor:["bright","earthy"],intensity:2,form:"Compressed block, paste, or powder",summary:"Sweet, sour, and deeply fruity — the backbone of souring across three continents.",what:"Pulp from the pod of Tamarindus indica — sweet, intensely tart, and deeply flavoured. Used from India to Thailand to Mexico to West Africa. Essential in Worcestershire sauce and HP sauce.",when:"Dissolve in warm water and add to chutneys, curries, and pad thai. Use in tamarind-date chutney for chaat. Essential in Worcestershire sauce production.",tip:"The powder reconstitutes easily but tends to taste more sour and less complex than block tamarind. For important applications, use the block.",pairings:["cumin","coriander","amchur","kokam","jaggery"],cuisines:["Indian","Thai","Vietnamese","West African","Mexican","British sauces"],nanaNote:"It makes sweet things more interesting and sour things more rich. That's a rare skill."},

  barberry:{id:"barberry",name:"Barberry (Zereshk)",icon:"🔴",origin:"Iran and the Himalayas — the jewel of Persian rice dishes",region:"middleeast",flavor:["bright"],intensity:2,form:"Dried whole berry",summary:"Tiny, tart, and jewel-red — the spice that makes Persian rice shimmer.",what:"Berberis vulgaris berries, small and intensely sour. In Persian cooking, scattered through rice dishes to provide bright pops of acidity and beautiful colour. Similar to dried cranberry or sumac but more tart.",when:"Scatter over Persian jewelled rice (zereshk polo). Add to chicken and lamb preparations. Stir into grain salads and pilafs for colour and tartness.",tip:"Soak briefly in cold water to soften slightly before using — they're very tart dry.",pairings:["saffron","dried_lime","sumac","rose_petals","cinnamon"],cuisines:["Persian","Iranian","Afghan","Azerbaijani"],nanaNote:"They look like tiny rubies and taste like someone distilled winter fruit into a spice. Extraordinary in rice."},

  anardana:{id:"anardana",name:"Anardana (Pomegranate Seeds)",icon:"💜",origin:"Iran and Afghanistan — dried seeds of wild pomegranate",region:"middleeast",flavor:["bright","earthy"],intensity:2,form:"Whole dried seed or ground",summary:"Tart, complex, and faintly sweet — the pomegranate as a dry spice.",what:"Wild pomegranate seeds sun-dried to a dark, wrinkled mass. The flavour is tart, fruity, and slightly resinous — similar to sumac but earthier and more complex. Used as a souring agent in North Indian cooking.",when:"Crush and add to chutney, stuffed parathas, and North Indian curries. Use in spice blends for chole (chickpea curry).",tip:"The dried seeds can be very hard — grind in a spice grinder before use.",pairings:["amchur","sumac","cumin","coriander","garam_masala"],cuisines:["North Indian","Pakistani","Afghan","Iranian"],nanaNote:"The pomegranate is already the jewel of the fruit world. Dried and ground, it becomes something else entirely."},

  hibiscus:{id:"hibiscus",name:"Dried Hibiscus (Roselle)",icon:"🌺",origin:"West Africa and South Asia — now grown throughout the tropics",region:"africa",flavor:["bright","floral"],intensity:2,form:"Dried calyx",summary:"Tart, cranberry-red, and floral — the spice that doubles as a spectacular natural dye.",what:"Hibiscus sabdariffa calyces used as a souring spice and beverage across Africa, the Caribbean, and Mexico (where it's called jamaica). Intensely tart and fruity — like cranberry with a floral rose note and brilliant crimson colour.",when:"Steep in warm water for agua de jamaica or karkade tea. Add ground to spice rubs. Use in sauces for duck and pork where you want fruit acidity and colour.",tip:"It bleeds its colour dramatically — even a small amount will turn pale liquids deep crimson.",pairings:["rose_petals","tamarind_powder","ginger_powder","cinnamon","vanilla"],cuisines:["Mexican","West African","Sudanese","Caribbean","Egyptian"],nanaNote:"It makes water look like it came from a story. And it tastes like something worth telling."},

  mahlab:{id:"mahlab",name:"Mahlab",icon:"⬜",origin:"Mediterranean and the Middle East — the kernel of the St. Lucie cherry",region:"middleeast",flavor:["floral","warm","bright"],intensity:2,form:"Whole kernel or ground",summary:"Cherry-almond, bitter-sweet, and distinctly festive — the spice of Eastern Mediterranean sweet breads.",what:"The tiny kernel of Prunus mahaleb with an extraordinary flavour combining cherry, almond, rose, and a pleasant bitterness. Used almost exclusively in sweet breads and pastries across Greece, Turkey, Lebanon, and surrounding countries.",when:"Add to Greek tsoureki Easter bread, Turkish çörek, Lebanese ka'ak biscuits, and various Middle Eastern festive pastries.",tip:"Buy whole and grind fresh — ground mahlab loses its cherry-almond character quickly. Store whole kernels sealed in the freezer.",pairings:["vanilla","cardamom","rose_petals","mastic","cinnamon"],cuisines:["Greek","Turkish","Lebanese","Syrian","Armenian"],nanaNote:"It smells like Easter morning in a Greek household. If you know, you know."},

  /* ── GUMS, RESINS & SPECIAL ── */
  asafoetida:{id:"asafoetida",name:"Asafoetida (Hing)",icon:"🟡",origin:"Iran and Afghanistan — dried resin of Ferula plants",region:"middleeast",flavor:["pungent","umami"],intensity:3,form:"Lump resin or compounded powder",summary:"Sulphurous raw, miraculous cooked — the onion-garlic substitute of Jain cooking.",what:"Dried latex sap of a giant fennel relative. Raw, it smells intensely of sulfur and rotting onion. Bloomed in hot oil for a few seconds, it transforms into a deep, savory, onion-garlic depth. Used by Jain and Brahmin communities as a substitute for onion and garlic.",when:"Add a tiny pinch to hot oil at the very beginning of cooking — 5 to 10 seconds before anything else. It blooms rapidly. Essential in South Indian dals and pickles.",tip:"The smell before cooking is genuinely unpleasant. Do not judge it by this. A pinch in hot oil is transformative. Store in an extremely airtight container.",pairings:["mustard","cumin","curry_leaf","fenugreek","turmeric"],cuisines:["South Indian","Jain","Brahmin","North Indian"],nanaNote:"It smells wrong and tastes right. This is a pattern in cooking worth getting used to."},

  mastic:{id:"mastic",name:"Mastic",icon:"🤍",origin:"Chios Island, Greece — the only place true mastic is produced",region:"europe",flavor:["floral","pungent","bright"],intensity:2,form:"Crystalline tears (resin droplets)",summary:"Piney, resinous, and uniquely Mediterranean — the original chewing gum of the ancient world.",what:"Resinous sap that crystallizes on the bark of Pistacia lentiscus trees on Chios Island. Piney, resinous, slightly sweet, and faintly medicinal. Used in Greek cooking, Turkish desserts, and throughout the Eastern Mediterranean.",when:"Grind with a pinch of sugar (prevents clumping) and add to Greek spoon sweets, loukoumades, and certain breads. Essential in Greek stretchy ice cream (kaimaki).",tip:"Grind it in the freezer for a few minutes first — warm mastic sticks to everything and clumps. Freezing makes it brittle and grindable.",pairings:["rose_petals","cardamom","mahlab","vanilla","cinnamon"],cuisines:["Greek","Turkish","Lebanese","Egyptian","Cypriot"],nanaNote:"Chios mastic has its own PDO designation. There is no substitute. The island matters."},

  kala_namak:{id:"kala_namak",name:"Kala Namak (Black Salt)",icon:"⚫",origin:"South Asia — volcanic salt from the Himalayas",region:"southasia",flavor:["pungent","umami"],intensity:2,form:"Whole crystal or ground",summary:"Sulfurous, eggy, and strangely essential — the salt that makes plant-based foods taste like eggs.",what:"Indian volcanic salt containing sulfur compounds that give it a distinctly egg-like, sulphurous aroma and flavour. Despite being called 'black salt', the ground form is actually pinkish-grey. Essential in South Asian street food and plant-based egg cooking.",when:"Sprinkle over chaat, fruits, and street food snacks. Add to tofu scrambles and vegan egg dishes. Use in raita and lassi for complexity.",tip:"Start with a very small amount — the sulfur character is strong and easy to over-apply. It fades significantly with heat, so add mostly at the end.",pairings:["amchur","cumin","chaat_masala","dried_mint","tamarind_powder"],cuisines:["Indian","Pakistani","Vegan/plant-based"],nanaNote:"It tastes of eggs without any eggs. That's either magic or very good chemistry."},

  porcini_powder:{id:"porcini_powder",name:"Porcini Powder",icon:"🍄",origin:"Europe and North America — dried Boletus edulis mushroom",region:"europe",flavor:["umami","earthy"],intensity:2,form:"Dried powder",summary:"Concentrated forest umami — the seasoning that makes everything taste like it simmered all day.",what:"Made from dried porcini mushrooms ground to a fine, intensely fragrant powder. One of the most potent natural umami enhancers available — richer and more complex than MSG in flavour terms.",when:"Stir a teaspoon into pasta sauces, risottos, and meat braises. Add to beef and mushroom rubs. A pinch in mashed potatoes is extraordinary.",tip:"A teaspoon in a braise sauce does what a whole dried porcini mushroom does — use it as a concentrated flavour additive.",pairings:["dried_rosemary","dried_thyme","black_pepper","smoked_paprika","bay_leaf"],cuisines:["Italian","French","European broadly","Modern home cooking"],nanaNote:"It's cheating in the best possible way. A teaspoon does what an hour of reduction can't."},

  kombu_powder:{id:"kombu_powder",name:"Kombu Powder",icon:"🌊",origin:"Japan and Korea — dried kelp seaweed from cold northern waters",region:"eastasia",flavor:["umami","earthy"],intensity:2,form:"Dried strip or powder",summary:"Pure umami from the sea — the invisible foundation of Japanese dashi stock.",what:"Dried kelp extraordinarily rich in glutamates — the compounds responsible for umami. One of the two key ingredients in Japanese dashi stock. A tiny piece transforms nearly any liquid into something that tastes deeper and more complete.",when:"Add a small strip to bean pots and stocks to improve flavour. Stir powder into broths, soups, and braises. Add to pickling brines.",tip:"Don't boil kombu — steep in water approaching 60°C for 30 minutes, then remove. Boiling causes it to release bitter compounds.",pairings:["porcini_powder","sesame_toasted","ginger_powder","sansho","white_pepper"],cuisines:["Japanese","Korean","Plant-based cooking"],nanaNote:"It has almost no flavour of its own. It just makes everything around it taste more like itself. That's a remarkable quality."},

  long_pepper_extract:{id:"long_pepper_extract",name:"Pepper Extract Powder",icon:"🔥",origin:"Various — concentrated capsicum extract for controlled heat",region:"europe",flavor:["pungent"],intensity:3,form:"Powder or oil",summary:"Heat without flavour — used by professionals when pure Scoville units are the goal.",what:"Concentrated capsaicin extract in powder or liquid form, often derived from extremely hot peppers. Used in commercial hot sauce production and by chefs who need precise, controlled heat without the flavour of a specific chili.",when:"Use in laboratory-precision applications. Add drops of extract oil to hot sauce or spice blends when calibrating heat.",tip:"Treat this like a chemical. Use gloves. A drop can make a gallon of soup inedible. This is not a cooking spice — it's a flavour tool.",pairings:["smoked_paprika","cumin","chipotle","cayenne","garlic_powder"],cuisines:["Commercial food production","Professional kitchens"],nanaNote:"I have never needed this. If you do, you probably know exactly why."},

  /* ── FLORAL ── */
  rose_petals:{id:"rose_petals",name:"Dried Rose Petals",icon:"🌹",origin:"Iran, Turkey, Morocco — Damask rose (Rosa damascena) is most prized",region:"middleeast",flavor:["floral","bright"],intensity:1,form:"Dried petals, powder, or water",summary:"Softly perfumed, faintly sweet, and ancient — the floral touch in Persian and Moroccan cooking.",what:"Dried rose petals from aromatic varieties used as a spice in Persian (advieh), North African (ras el hanout), and Indian cooking. Delicate — floral, slightly sweet, with a hint of bitterness.",when:"Scatter over rice, desserts, and salads. Add to ras el hanout and advieh blends. Use in Persian and Middle Eastern sweets. Add to lamb marinades for fragrance.",tip:"Buy food-grade petals specifically sold for culinary use. Ornamental roses are often treated with pesticides.",pairings:["cardamom","saffron","cinnamon","barberry","mastic"],cuisines:["Persian","Moroccan","Turkish","Indian","Middle Eastern"],nanaNote:"It makes food smell like a gift. Use it when something deserves that."},

  lavender_culinary:{id:"lavender_culinary",name:"Culinary Lavender",icon:"💜",origin:"Mediterranean — Provence, southern France, and the Balkans",region:"europe",flavor:["floral","herb","bright"],intensity:2,form:"Dried flowers",summary:"Intensely perfumed and easy to overdo — herbes de Provence's most memorable member.",what:"Culinary lavender (Lavandula angustifolia) is the backbone of herbes de Provence and has found a renewed following in modern baking and cocktail culture. The flavour is intensely floral with a slight camphor quality. Used sparingly it's elegant; used heavily it tastes like soap.",when:"Add a pinch to herbes de Provence blends for lamb and chicken. Use in shortbread, honey-based desserts, and cocktails. Add to crème brûlée in very small amounts.",tip:"The soap line is real and close. Start with a quarter of what you think is a small amount.",pairings:["dried_thyme","dried_rosemary","fennel","rose_petals","vanilla"],cuisines:["French Provençal","British modern baking","Scandinavian"],nanaNote:"A pinch. Not a pinch and then a bit more. A pinch."},

  jasmine_dried:{id:"jasmine_dried",name:"Dried Jasmine Flowers",icon:"🌸",origin:"South Asia and the Middle East — Jasminum sambac and J. officinale",region:"southasia",flavor:["floral","bright"],intensity:1,form:"Dried flowers",summary:"Intensely perfumed, delicately sweet, and used where subtlety matters.",what:"The dried flowers of aromatic jasmine varieties have an intensely sweet, heady floral aroma. Most commonly used for jasmine tea and in Southeast Asian sweets.",when:"Infuse in warm cream, milk, or syrup for desserts. Add to cocktails and floral-forward syrups. Use in jasmine rice preparations.",tip:"The aroma is highly volatile — infuse in low-temperature liquids rather than adding to high-heat cooking.",pairings:["rose_petals","cardamom","pandan","vanilla","elderflower"],cuisines:["Chinese","Thai","Indian","Middle Eastern"],nanaNote:"It makes a cup of hot water into something that deserves attention."},

  chamomile_culinary:{id:"chamomile_culinary",name:"Chamomile Flowers",icon:"🌼",origin:"Europe and Western Asia",region:"europe",flavor:["floral","bright","herb"],intensity:1,form:"Dried flowers",summary:"Honey-apple, gently bitter, and calming — the floral herb that earns its place in savoury cooking.",what:"Culinary chamomile has a flavour often described as honey, apple, and mild floral bitterness. Beyond its well-known role in tea, used in modernist and European cooking to add delicate floral depth to sauces and desserts.",when:"Steep in warm cream for panna cotta and custard. Add to cocktail syrups and sorbets. Use in honey-chamomile glazes for chicken and pork.",tip:"Steep, don't boil — boiling makes chamomile bitter. 10 minutes in 70°C liquid is usually optimal.",pairings:["lavender_culinary","vanilla","rose_petals","elderflower","cardamom"],cuisines:["European modern","Scandinavian","British","Moroccan"],nanaNote:"It tastes like the idea of being comfortable. That's not nothing."},

  elderflower:{id:"elderflower",name:"Dried Elderflower",icon:"🌿",origin:"Europe and North America — Sambucus nigra",region:"europe",flavor:["floral","bright"],intensity:1,form:"Dried flowers or cordial",summary:"Delicately muscat-floral and uniquely European — a summer scent captured for year-round use.",what:"Elderflower has a distinctive lychee-like, grapey floral aroma. The dried flowers are less aromatic than fresh but still useful for infusions and baking. Elderflower cordial is the most common commercial form.",when:"Steep dried flowers in warm cream, sugar syrup, or fruit juice. Add to gooseberry and apple preserves — elderflower and gooseberry is a classic European pairing.",tip:"Dried elderflower is significantly weaker than fresh. Use about twice as much dried. Or use a high-quality elderflower cordial.",pairings:["chamomile_culinary","lavender_culinary","rose_petals","vanilla","jasmine_dried"],cuisines:["British","Scandinavian","Central European","Modern European"],nanaNote:"June in a jar. That's what it is."},

  /* ── AFRICAN SINGLES ── */
  uda_pepper:{id:"uda_pepper",name:"Uda Pepper (Grains of Selim)",icon:"🟫",origin:"West and Central Africa — Xylopia aethiopica",region:"africa",flavor:["smoky","warm","pungent"],intensity:2,form:"Whole dried pod",summary:"Woody, smoky, and resinous — the native African pepper that flavoured a continent before black pepper arrived.",what:"Dried pods and seeds of a tall African tree. Woody and resinous with some smokiness, a slight eucalyptus quality, and warmth. The primary pepper in West African cooking before the Columbian exchange.",when:"Add whole to West African pepper soup, peanut stew, and certain grilled meats. Use in Nigerian soups. Grind into spice blends for meat and fish.",tip:"Crack the pods rather than using whole — the seeds inside carry concentrated flavour.",pairings:["grains_of_paradise","calabash_nutmeg","grains_of_selim","coriander","allspice"],cuisines:["Nigerian","Ghanaian","Cameroonian","West African broadly"],nanaNote:"Before black pepper, this was pepper. History has layers."},

  calabash_nutmeg:{id:"calabash_nutmeg",name:"Calabash Nutmeg (Ehuru)",icon:"🟤",origin:"West Africa — the seed of Monodora myristica",region:"africa",flavor:["warm","floral","pungent"],intensity:2,form:"Whole seed or ground",summary:"West Africa's native nutmeg — warmer, more resinous, and with its own distinct character.",what:"Monodora myristica (called ehuru in Igbo) is unrelated to true nutmeg but fills a similar aromatic role in West African cooking. Warm, slightly resinous, with floral notes and a peppery warmth.",when:"Grind and add to Nigerian pepper soup spice blend and traditional West African preparations. Use in spice blends for grilled meats.",tip:"Toast briefly before grinding to develop the aromatic oils. The hard seed needs a robust spice grinder.",pairings:["uda_pepper","grains_of_paradise","coriander","cumin","allspice"],cuisines:["Nigerian","West African"],nanaNote:"Every continent has developed its own answer to similar questions in cooking. This is West Africa's answer to nutmeg."},

  korarima:{id:"korarima",name:"Korarima (Ethiopian Cardamom)",icon:"💚",origin:"Ethiopia and East Africa — Aframomum corrorima",region:"africa",flavor:["floral","warm","earthy"],intensity:3,form:"Whole pod or ground",summary:"Ethiopia's native cardamom — more earthy and resinous than green cardamom, intensely aromatic.",what:"A large-podded relative of cardamom native to highland Ethiopia. Warm, earthy, and floral with camphor and eucalyptus notes. Fundamental to Ethiopian spiced butter (niter kibbeh) and the berbere spice blend.",when:"Essential in Ethiopian niter kibbeh and berbere. Add to tej (Ethiopian honey wine). Use in East African spiced meat and lentil dishes.",tip:"Only one or two pods are needed — it's intensely aromatic. Remove whole pods before serving.",pairings:["berbere","cumin","coriander","fenugreek","black_cardamom"],cuisines:["Ethiopian","Eritrean","East African"],nanaNote:"Green cardamom is elegant and fragrant. This is wilder and more ancient. Both are correct."},

  dawadawa:{id:"dawadawa",name:"Dawadawa (Locust Bean)",icon:"⚫",origin:"West Africa — fermented seeds of the African locust bean (Parkia biglobosa)",region:"africa",flavor:["umami","pungent","earthy"],intensity:3,form:"Dried fermented seed or powder",summary:"Funky, intensely savory, and unreplaceable — West Africa's answer to fish sauce and miso.",what:"Traditional West African condiment made from fermented locust bean seeds. Intensely umami, pungent, and deeply savoury — similar in concept to miso paste or fish sauce but with its own distinct African character.",when:"Add to West African soups, stews, and sauces wherever depth is needed. Traditional in egusi soup and groundnut stew.",tip:"A very small amount goes a long way — it's intensely flavoured. Refrigerate after opening.",pairings:["uda_pepper","grains_of_paradise","calabash_nutmeg","bird_eye","coriander"],cuisines:["Nigerian","Ghanaian","Malian","West African broadly"],nanaNote:"It's the umami of a continent that didn't need to borrow the concept from anyone else."},

  hwentia:{id:"hwentia",name:"Hwentia (Grains of Selim Pod)",icon:"🟫",origin:"Ghana and West Africa — the outer pod of Xylopia aethiopica",region:"africa",flavor:["smoky","earthy","warm"],intensity:2,form:"Dried pod (used whole in soups)",summary:"Distinctly Ghanaian — the smoky pod spice that defines Ghanaian palm nut soup.",what:"Hwentia refers specifically to the Ghanaian culinary use of the grains of selim pod. In Ghanaian cooking it's added whole to stews and soups, particularly palm nut soup, for its distinctive smoky, resinous depth.",when:"Add whole to Ghanaian palm nut soup, light soup, and ground nut soup. Use in other West African slow-cooked preparations.",tip:"It's used whole in Ghanaian cooking — not ground. The pod releases its flavour slowly.",pairings:["uda_pepper","calabash_nutmeg","dawadawa","grains_of_paradise","bird_eye"],cuisines:["Ghanaian","West African"],nanaNote:"If someone's grandmother made it with hwentia, don't substitute. It won't be the same."},

  selim_grains:{id:"selim_grains",name:"Selim Pepper (Kimba)",icon:"🟫",origin:"West Africa — the seed within grains of selim pods",region:"africa",flavor:["warm","pungent","smoky"],intensity:2,form:"Whole dried seed",summary:"The inner seed of the selim pod — more concentrated and peppery than the whole pod.",what:"The seeds within Xylopia aethiopica pods, separated from the pod walls and used for a more concentrated, peppery flavour. Used in certain West African spice traditions where the seed character is preferred over the whole pod.",when:"Grind as a pepper substitute or into spice blends. Use in coffee preparations in West African tradition. Add to spice rubs.",tip:"Grind fresh — the volatile compounds fade relatively quickly once the seeds are ground.",pairings:["grains_of_paradise","cubeb_pepper","coriander","long_pepper","uda_pepper"],cuisines:["West African","Ethiopian"],nanaNote:"It's both a spice and a piece of history."},

  /* ── SOUTHEAST ASIAN ── */
  kencur:{id:"kencur",name:"Kencur (Sand Ginger)",icon:"🟡",origin:"Southeast Asia — particularly Java, Indonesia",region:"oceania",flavor:["pungent","floral","warm"],intensity:3,form:"Dried slices or powder",summary:"Camphor-scented, resinous, and intense — a Southeast Asian rhizome unlike anything else.",what:"Kaempferia galanga, also called lesser galangal, is a rhizome with a distinctly camphor-like, eucalyptus-scented flavour sharper and more medicinal than either ginger or galangal. Fundamental to certain Balinese and Javanese spice pastes.",when:"Use in Balinese base gede and base wangen spice pastes. Add to certain Indonesian spice rubs. Essential in jamu herbal drinks.",tip:"Use sparingly — the camphor quality is very strong. A small amount contributes; a large amount medicates.",pairings:["galangal","lemongrass_dried","turmeric","fingerroot","makrut_lime_leaf"],cuisines:["Balinese","Javanese","Indonesian"],nanaNote:"Balinese cooking is different from Thai cooking is different from Javanese cooking. Kencur is one of the reasons why."},

  belacan_powder:{id:"belacan_powder",name:"Belacan (Shrimp Paste)",icon:"🟫",origin:"Southeast Asia — fermented shrimp paste essential in Malay cooking",region:"oceania",flavor:["umami","pungent"],intensity:3,form:"Dried block or powder",summary:"Funky, intense, and irreplaceable — the fermented shrimp backbone of Southeast Asian cooking.",what:"Fermented shrimp paste with overwhelming pungency raw and extraordinary savoury depth when cooked. Roasting or dry-frying transforms the raw shrimp smell into complex savoury umami. Essential in sambal, laksa, and Malay curry pastes.",when:"Toast or dry-fry before using — this transforms the raw pungency into cooked umami. Use in sambal belacan, laksa paste, and Malay curry pastes.",tip:"Toast in a dry pan until slightly darkened and fragrant — open a window. Worth it.",pairings:["lemongrass_dried","galangal","makrut_lime_leaf","bird_eye","turmeric"],cuisines:["Malaysian","Singaporean","Indonesian","Thai"],nanaNote:"Raw it smells alarming. Cooked it explains why Malay food tastes the way it does."},

  vietnamese_coriander:{id:"vietnamese_coriander",name:"Vietnamese Coriander (Rau Ram)",icon:"🌿",origin:"Southeast Asia — particularly Vietnam, Cambodia, and Malaysia",region:"oceania",flavor:["herb","pungent","bright"],intensity:2,form:"Dried leaf",summary:"Peppery, citrusy, and distinctive — the herb that features in laksa and Vietnamese salads.",what:"Persicaria odorata — peppery, citrusy, and unlike regular coriander (cilantro) in every way. A different plant entirely. Features in certain Vietnamese salads and the laksa of Malaysia and Singapore.",when:"Use dried in spice blends or infusions. Fresh: add to laksa, Vietnamese salads, and as a garnish for soups.",tip:"Genuinely difficult to find dried and worth seeking out fresh if you're cooking the dishes that call for it.",pairings:["lemongrass_dried","makrut_lime_leaf","galangal","belacan_powder","bird_eye"],cuisines:["Vietnamese","Malaysian","Singaporean","Cambodian"],nanaNote:"It grows prolifically in Southeast Asian gardens. If you have a warm spot, grow it instead of buying it."},

  torch_ginger:{id:"torch_ginger",name:"Torch Ginger Bud (Dried)",icon:"🌺",origin:"Southeast Asia — Etlingera elatior, native to Malaysia and Indonesia",region:"oceania",flavor:["floral","bright","herb"],intensity:1,form:"Dried bud or powder",summary:"Floral, gingery, and uniquely tropical — the flower bud used in laksa and Malay cooking.",what:"The flower bud of the torch ginger plant, used fresh or dried in Malaysian, Indonesian, and Thai cooking. The flavour is gently floral and gingery with a slightly tart, herbal quality. Iconic in Penang laksa.",when:"Add to Penang asam laksa and nasi ulam. Use in Malaysian rojak and Malay herb preparations. Slice fresh bud into salads.",tip:"Fresh or frozen torch ginger buds are significantly better than dried. Seek out frozen versions at Southeast Asian grocery stores.",pairings:["lemongrass_dried","galangal","belacan_powder","makrut_lime_leaf","turmeric"],cuisines:["Malaysian","Penang specifically","Indonesian","Thai"],nanaNote:"Penang laksa without this bud isn't quite right. Some ingredients aren't optional."},

  peppercorn_long:{id:"peppercorn_long",name:"Long Pepper Dried",icon:"🟫",origin:"North India and Nepal — the ancient trade pepper",region:"southasia",flavor:["warm","pungent","floral"],intensity:3,form:"Whole catkin",summary:"The pepper before black pepper — complex heat with cardamom and ginger notes.",what:"Piper longum dried catkin — pungent heat up front followed by sweetness and a floral finish black pepper lacks. The dominant spice in ancient Rome and medieval Europe before black pepper displaced it.",when:"Grind over cured meats, game, and rich braises. Use in Ethiopian berbere and medieval-inspired spice blends. Excellent over chocolate.",tip:"Grind fine — coarsely ground can be gritty. Works beautifully with black pepper in a blend.",pairings:["black_pepper","long_pepper","cinnamon","cardamom","ginger_powder"],cuisines:["Ethiopian","South Asian historical","Moroccan","Medieval European"],nanaNote:"The original. Worth understanding what replaced it and why."},

  salam_leaf:{id:"salam_leaf",name:"Salam Leaf (Indonesian Bay)",icon:"🌿",origin:"Indonesia and Malaysia — Syzygium polyanthum",region:"oceania",flavor:["herb","earthy","floral"],intensity:1,form:"Dried leaf",summary:"Indonesian bay leaf — milder than European bay, with a subtle, herby depth.",what:"The dried leaf of Syzygium polyanthum, used in Indonesian and Malaysian cooking as a bay leaf substitute. The flavour is milder and less assertive than European bay, with a gentle herby quality and slight bitterness.",when:"Add to Indonesian soups, stews, and rice dishes. Use in rendang and gulai. Essential in certain Indonesian spice pastes as a base leaf.",tip:"European bay leaf is not the same thing and not an ideal substitute — they're from entirely different plant families. The salam leaf has a softer, less medicinal quality.",pairings:["galangal","lemongrass_dried","fingerroot","turmeric","kencur"],cuisines:["Indonesian","Malaysian","Balinese"],nanaNote:"Every cuisine has its own version of 'add a leaf to the pot and let it work quietly.' This is Indonesia's."},

  /* ── SOUTH ASIAN BLENDS ── */
  garam_masala:{id:"garam_masala",name:"Garam Masala",icon:"✨",origin:"North India — 'warming spice mix'",region:"southasia",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"North India's most important spice blend — complex, warming, and added at the end.",what:"Not a single blend but a family — every household, region, and cook has their own version. Common components: cumin, coriander, cardamom, cinnamon, cloves, black pepper, and nutmeg.",when:"Add at the very end of cooking — stir in a teaspoon right before serving for maximum aromatic impact. Use in curries and biryanis.",tip:"The best garam masala is made fresh from whole spices toasted and ground. The old jar at the back is the third-best.",pairings:["cumin","coriander","cardamom","turmeric","kashmiri_chili"],cuisines:["North Indian","Pakistani","Bangladeshi","British Indian"],nanaNote:"Add it last, just before the table. That's when it does its best work."},

  panch_phoron:{id:"panch_phoron",name:"Panch Phoron",icon:"✨",origin:"Bengal — the Bengali five-spice blend",region:"southasia",flavor:["blend","pungent","floral"],intensity:2,form:"Whole seed blend",summary:"Five whole seeds in equal proportion — the aromatic foundation of Bengali cooking.",what:"Equal parts fenugreek seed, nigella seed, cumin seed, black mustard seed, and fennel seed. Unlike Chinese five spice (which is ground), panch phoron is always used whole and bloomed in oil.",when:"Bloom in hot oil or ghee at the beginning of Bengali dals, vegetable dishes, and fish curries. Essential in Bengali aloo posto.",tip:"Make your own — buy the five seeds separately and combine in equal proportions.",pairings:["turmeric","mustard","nigella","fenugreek","cumin"],cuisines:["Bengali","Bangladeshi","Assamese","Odia"],nanaNote:"Five seeds, equal parts. The ratios are the recipe."},

  chaat_masala:{id:"chaat_masala",name:"Chaat Masala",icon:"✨",origin:"North India — the seasoning blend of street food",region:"southasia",flavor:["blend","bright","pungent"],intensity:2,form:"Ground blend",summary:"Tangy, funky, and vibrantly sour — the seasoning that makes street food taste like street food.",what:"Complex blend containing amchur, cumin, coriander, kala namak (black salt), ajwain, ginger powder, dried mint, and chili. Simultaneously sour, salty, funky, and aromatic.",when:"Sprinkle over chaat, samosas, bhel puri, and dahi puri. Dust over sliced fruit. Add to raita and lassi.",tip:"Make your own for the freshest flavour — the amchur oxidises and aromatics fade quickly in commercial blends.",pairings:["amchur","kala_namak","cumin","dried_mint","tamarind_powder"],cuisines:["North Indian","Pakistani","Street food broadly"],nanaNote:"It makes plain things extraordinary. That's the whole point of street food."},

  sambar_powder:{id:"sambar_powder",name:"Sambar Powder",icon:"✨",origin:"South India — the defining spice blend of Tamil Nadu",region:"southasia",flavor:["blend","warm","pungent"],intensity:2,form:"Ground blend",summary:"The complex backbone of South India's essential lentil vegetable stew.",what:"Typically contains roasted coriander seeds, cumin, black pepper, chili, turmeric, curry leaves, and mustard seeds. Added to the sambar stew that accompanies idli, dosa, and rice throughout South India.",when:"Add to sambar along with tamarind water and cooked lentils. Use as a base spice blend for South Indian vegetable dishes.",tip:"South Indian sambar powder is different from North Indian curry powder — don't substitute. Each family has a preferred version.",pairings:["turmeric","curry_leaf","mustard","asafoetida","tamarind_powder"],cuisines:["Tamil","Kannada","Andhra","South Indian broadly"],nanaNote:"It smells of South India's kitchens in the morning. Once you know it, you recognise it anywhere."},

  biryani_masala:{id:"biryani_masala",name:"Biryani Masala",icon:"✨",origin:"Mughal India — the spice blend of royal court rice dishes",region:"southasia",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"The aromatic heart of biryani — more floral and complex than everyday garam masala.",what:"A garam masala variant optimised for long-cooked layered rice preparations. Typically higher proportions of cardamom, saffron, mace, and rose petals. More floral and perfumed than everyday garam masala.",when:"Layer with rice and marinated meat in dum cooking. Add to biryani gravy base.",tip:"Biryani deserves good spices. Use this as an occasion to make your own blend from freshly toasted whole spices.",pairings:["saffron","rose_petals","cardamom","mace","cumin"],cuisines:["Hyderabadi","Lucknowi","Mughal-style","Pakistani","Bengali"],nanaNote:"A biryani made with care and the right spices is one of the great dishes of the world. Don't rush it."},

  curry_powder:{id:"curry_powder",name:"Curry Powder (British-style)",icon:"✨",origin:"British India — a colonial invention standardising complex regional masalas",region:"europe",flavor:["blend","warm","earthy"],intensity:2,form:"Ground blend",summary:"The Western world's gateway to Indian spice — a useful simplification that has its own tradition now.",what:"Commercial curry powder was essentially invented by the British to replicate Indian flavours. Typically contains coriander, cumin, turmeric, fenugreek, and various chilies. Has generated its own cuisine: British Indian, Japanese curry, and Caribbean curries.",when:"Use in British curries, kedgeree, and mulligatawny. Essential in Japanese curry (adapted). Add to Caribbean curry goat and chicken.",tip:"No single Indian dish uses curry powder — they use specific masalas. That said, curry powder has its own legitimate culinary tradition.",pairings:["turmeric","cumin","coriander","garam_masala","ginger_powder"],cuisines:["British Indian","Japanese adapted","Caribbean","South African"],nanaNote:"It isn't authentic to anything. It also tastes good in the things it belongs to. Both things are true."},

  tandoori_masala:{id:"tandoori_masala",name:"Tandoori Masala",icon:"✨",origin:"Punjab and Northwest India — the seasoning blend of tandoor oven cooking",region:"southasia",flavor:["blend","smoky","warm"],intensity:2,form:"Ground blend",summary:"The vibrant, slightly smoky blend behind India's most iconic grilled dishes.",what:"Designed to be mixed with yogurt to create a marinade for chicken, lamb, and paneer cooked in a tandoor oven. Typically contains kashmiri chili, cumin, coriander, garam masala, and garlic powder.",when:"Mix into thick yogurt to create tandoori marinade. Marinate protein for at least 4 hours or overnight. Use as a rub even without a tandoor — high-heat oven or grill mimics the effect.",tip:"The vivid orange-red of good tandoori chicken comes from kashmiri chili — not food colouring, which is sometimes used commercially.",pairings:["kashmiri_chili","cumin","coriander","garam_masala","cardamom"],cuisines:["Punjabi","North Indian","Pakistani","British Indian"],nanaNote:"The yogurt and spices do most of the work. Let them marinate overnight and get out of the way."},

  tikka_masala:{id:"tikka_masala",name:"Tikka Masala Blend",icon:"✨",origin:"Disputed — possibly created in Britain or adapted from North Indian cooking",region:"europe",flavor:["blend","warm","bright"],intensity:1,form:"Ground blend",summary:"Creamy, mild, and tomato-sweet — the world's most popular curry blend.",what:"The basis for one of the world's best-selling curry sauces. Typically milder, slightly sweeter, and more tomato-friendly than other masalas, designed to work in a cream-and-tomato sauce.",when:"Use to season chicken tikka before grilling. Mix into cream and tomato sauce. Works as a mild, accessible spice blend for less heat-tolerant preferences.",tip:"Mild enough that good-quality commercial versions are widely available and perfectly serviceable.",pairings:["garam_masala","kashmiri_chili","cumin","coriander","cardamom"],cuisines:["British Indian","Widely globalised"],nanaNote:"Whether or not it's 'authentic', it makes a lot of people very happy. That counts for something."},

  /* ── EAST ASIAN BLENDS ── */
  chinese_five_spice:{id:"chinese_five_spice",name:"Chinese Five Spice",icon:"✨",origin:"China — reflects the five flavours of traditional Chinese medicine",region:"eastasia",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"Warm, anise-forward, and distinctly Chinese — five flavours balanced into one.",what:"Typically contains star anise, cloves, cinnamon or cassia, Sichuan pepper, and fennel seeds. The defining blend of Cantonese roasted meats, red-braised pork, and Peking duck.",when:"Rub onto pork belly before roasting. Add to red-braised pork and Cantonese char siu marinade.",tip:"A small amount goes a long way — star anise and cloves are dominant. Start with half a teaspoon.",pairings:["star_anise","sichuan_pepper","cassia","cloves","ginger_powder"],cuisines:["Chinese","Taiwanese","Cantonese","Vietnamese influenced"],nanaNote:"It smells like roast pork belly before you've even bought the pork."},

  shichimi:{id:"shichimi",name:"Shichimi Togarashi",icon:"✨",origin:"Japan — a seven-spice blend from Edo period",region:"eastasia",flavor:["blend","pungent","warm","floral"],intensity:2,form:"Ground/flake blend",summary:"Seven spices that together make ramen, udon, and grilled meats sing.",what:"Contains togarashi chili, sansho, dried citrus peel, black and white sesame seeds, ginger, and nori. Complex, lightly spicy, citrusy, and nutty. The standard Japanese table condiment.",when:"Sprinkle over ramen, udon, yakitori, and grilled meat. Add to miso soup and rice. Dust over edamame.",tip:"It deteriorates quickly — buy in small quantities. Better yet, make your own.",pairings:["sansho","sesame_toasted","ginger_powder","sichuan_pepper","togarashi"],cuisines:["Japanese"],nanaNote:"There's a reason every Japanese ramen shop keeps a jar of this on every table."},

  japanese_curry:{id:"japanese_curry",name:"Japanese Curry Powder",icon:"✨",origin:"Japan — adapted from British curry powder via colonial India routes",region:"eastasia",flavor:["blend","warm","earthy"],intensity:1,form:"Ground blend or roux block",summary:"Mild, sweet-savoury, and distinctly Japanese — curry adapted into something comforting and entirely new.",what:"Evolved from British curry powder adopted in the Meiji era. Notably milder and sweeter, often made into a brick roux. Has its own character — caramelised onion sweetness, earthy warmth, and a glossy thick texture distinct from South Asian curries.",when:"The most common form is pre-made curry roux blocks. Use the powder to season soups and coatings for katsu.",tip:"Japanese curry powder and Indian curry powder are quite different. Japanese is milder and slightly sweeter by design.",pairings:["turmeric","cumin","coriander","ginger_powder","allspice"],cuisines:["Japanese"],nanaNote:"Japanese curry is its own thing. It grew up, moved to a different country, and became someone else."},

  togarashi:{id:"togarashi",name:"Togarashi (Japanese Chili)",icon:"🌶",origin:"Japan — the standard Japanese dried chili",region:"eastasia",flavor:["smoky","pungent"],intensity:2,form:"Whole dried or ground",summary:"Japan's everyday dried chili — clean heat with a slightly fruity edge.",what:"The Japanese term for dried chili pepper. In single-spice form typically a small, moderately hot chili with a relatively clean heat and faint fruity quality. The base spice in shichimi togarashi.",when:"Add whole to oil infusions and dashi broths. Use ground in coatings and spice rubs. Add to ponzu and tsuyu sauces for heat.",tip:"Japanese chilies are typically moderate in heat — if you substitute another chili, use less.",pairings:["sansho","sesame_toasted","ginger_powder","kombu_powder","white_pepper"],cuisines:["Japanese"],nanaNote:"The ingredient behind the ingredient. Most Japanese seasoning starts here."},

  furikake:{id:"furikake",name:"Furikake",icon:"✨",origin:"Japan — a 20th century seasoning blend",region:"eastasia",flavor:["blend","umami","herb"],intensity:1,form:"Dried flake blend",summary:"The Japanese rice seasoning that makes everything better — umami, salt, crunch, and colour in one.",what:"A dry Japanese seasoning blend typically containing dried fish (bonito or salmon), nori seaweed, sesame seeds, salt, and sometimes dried shiso or egg. Most commonly sprinkled over rice. Dozens of varieties exist.",when:"Sprinkle over steamed rice. Add to rice balls (onigiri). Use as a seasoning for popcorn and roasted vegetables.",tip:"Quality varies enormously. The best furikake has proper bonito shavings and real nori, not artificial flavours.",pairings:["sesame_toasted","kombu_powder","sansho","ginger_powder","shichimi"],cuisines:["Japanese"],nanaNote:"It makes plain rice the best plain rice. Don't underestimate it."},

  /* ── MIDDLE EASTERN & NORTH AFRICAN BLENDS ── */
  baharat:{id:"baharat",name:"Baharat",icon:"✨",origin:"Arab world — the name simply means 'spices' in Arabic",region:"middleeast",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"The all-purpose spice blend of the Arab world — warm, complex, and deeply aromatic.",what:"Not a single recipe but a family of blends — each country and household has its own version. Common components: allspice, black pepper, coriander, cinnamon, cumin, and cloves. Turkish baharat often includes dried mint.",when:"Season lamb, beef, and chicken before grilling or braising. Add to rice and grain pilafs. A teaspoon transforms simple meat dishes.",tip:"Make your own to suit the cuisine you're cooking — Turkish, Gulf, and Lebanese baharat all differ meaningfully.",pairings:["cumin","coriander","allspice","cinnamon","black_pepper"],cuisines:["Lebanese","Syrian","Turkish","Gulf Arab","Iraqi"],nanaNote:"It's 'the spices.' Sometimes that's all the definition you need."},

  hawaij:{id:"hawaij",name:"Hawaij",icon:"✨",origin:"Yemen — brought by Yemeni Jewish immigrants to Israel",region:"middleeast",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"Yemeni gold — a warming spice blend made for coffee and meat in equal measure.",what:"Exists in two distinct versions: one for coffee (cardamom, ginger, cinnamon, cloves) and one for meat and rice (cumin, coriander, turmeric, black pepper). Both essential to Yemeni and Israeli cooking.",when:"Coffee hawaij: add to coffee grounds before brewing. Meat hawaij: season lamb, chicken, and vegetable dishes. Add to rice and soups.",tip:"The two versions are not interchangeable — double-check which type a recipe requires.",pairings:["cardamom","cumin","turmeric","coriander","cinnamon"],cuisines:["Yemeni","Israeli","Mizrahi Jewish"],nanaNote:"A Yemeni grandmother's spice blend that ended up in every Israeli kitchen. Migration does that."},

  dukkah:{id:"dukkah",name:"Dukkah",icon:"✨",origin:"Egypt — the word comes from the Arabic for 'to crush'",region:"africa",flavor:["blend","earthy","warm"],intensity:1,form:"Coarsely ground blend",summary:"Nutty, herby, and textured — the Egyptian condiment that's best with just bread and olive oil.",what:"An Egyptian blend of nuts (hazelnuts, almonds, or both), sesame seeds, coriander, and cumin, coarsely ground to a crumbly mixture. The texture is essential — it should have some crunch.",when:"Serve with bread and olive oil as a starter. Crust fish or chicken before baking. Scatter over hummus and yogurt.",tip:"Don't over-process — the texture is what makes dukkah different from spice powder. Pulse in a food processor rather than blending.",pairings:["cumin","coriander","sesame_toasted","smoked_paprika","sumac"],cuisines:["Egyptian","North African","Australian modern"],nanaNote:"Bread, oil, dukkah. That's it. Sometimes a great dish has three words."},

  advieh:{id:"advieh",name:"Advieh",icon:"✨",origin:"Iran — the Persian spice blend for rice and meat",region:"middleeast",flavor:["blend","floral","warm"],intensity:1,form:"Ground blend",summary:"Fragrant, floral, and more delicate than most Middle Eastern blends — the perfume of Persian rice.",what:"Typically containing rose petals, cinnamon, cardamom, cumin, and dried lime or angelica. More floral and refined than similar blends from neighbouring cuisines. Used in both rice preparations and meat dishes.",when:"Add to Persian rice pilaf for fragrant depth. Use in lamb and chicken stews. Stir into Persian meatballs.",tip:"Rose petals are not optional in a proper advieh — they provide the distinctive floral character.",pairings:["rose_petals","cardamom","dried_lime","saffron","cinnamon"],cuisines:["Persian","Iranian","Afghan"],nanaNote:"Persian cooking is the cooking of a civilization. Advieh smells like history."},

  chermoula:{id:"chermoula",name:"Chermoula (Dry Blend)",icon:"✨",origin:"North Africa — Morocco, Tunisia, and Algeria",region:"africa",flavor:["blend","herb","bright"],intensity:2,form:"Dry spice blend",summary:"The Moroccan marinade blend — bright, herby, and the seasoning that defines North African fish and chicken.",what:"Classic chermoula is a wet marinade of fresh herbs, lemon, garlic, and spices. As a dry blend it typically contains cumin, coriander, paprika, turmeric, cayenne, and dried herbs.",when:"Rub onto fish before grilling — the essential Moroccan fish preparation. Use on chicken and lamb. Mix dry blend with olive oil and lemon for a wet marinade.",tip:"Fresh chermoula (the herb paste version) is better than any dry blend. Make the wet version when you can.",pairings:["cumin","coriander","smoked_paprika","turmeric","dried_mint"],cuisines:["Moroccan","Tunisian","Algerian","Libyan"],nanaNote:"The smell of fresh chermoula on fish just before the grill is one of the great moments of North African cooking."},

  /* ── AFRICAN BLENDS ── */
  berbere:{id:"berbere",name:"Berbere",icon:"✨",origin:"Ethiopia and Eritrea — the country's defining spice blend",region:"africa",flavor:["blend","smoky","warm","pungent"],intensity:3,form:"Ground blend",summary:"Bold, complex, and fiery — the blend that defines Ethiopian cuisine.",what:"The cornerstone spice blend of Ethiopian and Eritrean cooking. Typically contains korarima (Ethiopian cardamom), fenugreek, grains of paradise, coriander, rue, ajwain, cinnamon, and various dried chilies. The heat is significant, the complexity enormous.",when:"Essential in doro wat, misir wat, and tibs. Add to stews and braises. Mix with butter or oil as a base.",tip:"Store-bought berbere rarely matches homemade. An Ethiopian grocery store's blend is likely far superior.",pairings:["korarima","fenugreek","cumin","grains_of_paradise","coriander"],cuisines:["Ethiopian","Eritrean"],nanaNote:"Injera and berbere. That's a complete story told in two ingredients."},

  mitmita:{id:"mitmita",name:"Mitmita",icon:"✨",origin:"Ethiopia — a hotter, more aromatic sibling to berbere",region:"africa",flavor:["blend","pungent","floral"],intensity:3,form:"Ground blend",summary:"Ethiopia's fiery finishing spice — bird's eye chili meets cardamom at maximum intensity.",what:"A very hot Ethiopian blend dominated by bird's eye chilies with korarima, cloves, cardamom, and other spices. Hotter and more fragrant than berbere, used as a finishing condiment rather than a cooking base.",when:"Sprinkle over kitfo and tibs before serving. Use as a table condiment. Add to berbere-based dishes for more fire.",tip:"Use as a finishing spice — its aromatic compounds are volatile. Best added at the end or at the table.",pairings:["berbere","korarima","grains_of_paradise","cloves","cardamom"],cuisines:["Ethiopian","Eritrean"],nanaNote:"It's the one you put on the table for people who think berbere isn't hot enough."},

  colombo:{id:"colombo",name:"Colombo Powder",icon:"✨",origin:"French Caribbean islands — Martinique, Guadeloupe, and Réunion",region:"northamerica",flavor:["blend","warm","earthy"],intensity:2,form:"Ground blend",summary:"The Caribbean's Indian-influenced curry blend — proof of how spice traditions cross oceans.",what:"The curry blend of the French Caribbean, introduced by South Indian indentured workers in the 19th century. Typically contains coriander, cumin, turmeric, mustard, pepper, and other spices. Colombo de poulet and de porc are among the defining foods of Martinique.",when:"Use in chicken, pork, and goat Caribbean colombo stews. Season vegetables and seafood with it.",tip:"It's neither Indian curry powder nor Moroccan spice — it's its own evolved thing.",pairings:["turmeric","cumin","coriander","allspice","dried_thyme"],cuisines:["Martiniquais","Guadeloupéenne","Réunionnais","French Caribbean"],nanaNote:"It's what happens when Indian spices spend 200 years in the Caribbean. Fascinating."},

  niter_kibbeh_spice:{id:"niter_kibbeh_spice",name:"Niter Kibbeh Spice Blend",icon:"✨",origin:"Ethiopia — spices for Ethiopia's foundational spiced clarified butter",region:"africa",flavor:["blend","warm","floral"],intensity:2,form:"Whole and ground spices",summary:"The aromatic heart of Ethiopian cooking — spices that flavour the fat that flavours everything else.",what:"Niter kibbeh is Ethiopian spiced clarified butter — ghee infused with korarima, nigella, fenugreek, turmeric, black cumin, cinnamon, and other spices. The resulting butter is the cooking fat for much of Ethiopian cuisine.",when:"Used to make niter kibbeh — slowly melting butter with these spices, straining, and using the flavoured fat as a cooking medium. Enriches doro wat, tibs, and countless other preparations.",tip:"Making proper niter kibbeh takes time but keeps for weeks and transforms everything cooked in it.",pairings:["korarima","berbere","fenugreek","turmeric","nigella"],cuisines:["Ethiopian","Eritrean"],nanaNote:"When fat is seasoned, everything cooked in it is seasoned. The Ethiopians understood this first."},

  /* ── EUROPEAN BLENDS ── */
  herbes_de_provence:{id:"herbes_de_provence",name:"Herbes de Provence",icon:"✨",origin:"Provence, southern France — a 1970s commercial codification of traditional herbs",region:"europe",flavor:["blend","herb","floral"],intensity:1,form:"Dried herb blend",summary:"Summer in southern France — lavender, thyme, and rosemary in proportions that make grilled lamb transcendent.",what:"Typically includes thyme, rosemary, savory, marjoram, and lavender. The lavender component is a 20th-century addition for commercial export. Works beautifully with anything that goes on a grill in the Mediterranean manner.",when:"Rub onto lamb chops, chicken, and rabbit before grilling or roasting. Add to ratatouille and Provençal vegetable dishes.",tip:"Don't use lavender-heavy versions in savoury applications where you don't want floral notes.",pairings:["dried_thyme","dried_rosemary","lavender_culinary","savory","dried_oregano"],cuisines:["French Provençal","Corsican","Southern French broadly"],nanaNote:"It smells like a market in Aix-en-Provence. Which means it smells like where cooking gets things right."},

  quatre_epices:{id:"quatre_epices",name:"Quatre Épices",icon:"✨",origin:"France — the four-spice blend of French charcuterie and baking",region:"europe",flavor:["blend","warm","pungent"],intensity:2,form:"Ground blend",summary:"Four spices, one purpose — the blend that seasons every great pâté and terrine.",what:"Traditionally contains ground white or black pepper, nutmeg, cloves, and ginger. Some versions substitute cinnamon or allspice. The foundational blend for French charcuterie — pâté, terrine, rillettes, and saucisson all rely on it.",when:"Add to all pâté and terrine preparations. Season sausages and meat farces. Use in certain slow braises and gingerbread.",tip:"Make your own and adjust the pepper-to-sweet-spice ratio to your taste.",pairings:["nutmeg","cloves","white_pepper","ginger_powder","allspice"],cuisines:["French","Belgian","French charcuterie tradition"],nanaNote:"The smell of a proper pâté maison. Every farmhouse terrine starts here."},

  pickling_spice:{id:"pickling_spice",name:"Pickling Spice",icon:"✨",origin:"British and Northern European tradition",region:"europe",flavor:["blend","pungent","warm","bright"],intensity:2,form:"Whole spice blend",summary:"The blend that turns vinegar into preservation, history, and flavour.",what:"Typically contains mustard seeds, coriander seeds, dill seed, allspice, cloves, bay leaves, black peppercorns, and dried chilies. Added to vinegar brines for cucumber pickles, pickled onions, chutney, and corned beef.",when:"Add to brine when making pickled vegetables and chutneys. Use in corned beef preparation.",tip:"Use whole, not ground — you want the spices to flavour the brine without making it cloudy.",pairings:["dill_seed","mustard","bay_leaf","allspice","celery_seed"],cuisines:["British","American","German","Eastern European"],nanaNote:"A jar of proper pickles starts with knowing this blend."},

  mulling_spice:{id:"mulling_spice",name:"Mulling Spice",icon:"✨",origin:"Medieval Europe — the tradition of warming and spicing wine and ale",region:"europe",flavor:["blend","warm","floral"],intensity:1,form:"Whole spice blend",summary:"Winter warmth in a sachet — the blend that makes cider and wine smell like December.",what:"Typically contains cinnamon sticks, cloves, dried orange peel, star anise, and sometimes cardamom, allspice, or nutmeg. Simmered in red wine, cider, or fruit juice. The tradition goes back to Roman times.",when:"Simmer in red wine for vin chaud/Glühwein. Add to warm apple cider. Use to season poached pears.",tip:"Steep at low heat for at least 20 minutes, then keep warm without boiling — boiling drives off the alcohol and kills aromatics.",pairings:["cinnamon","cloves","star_anise","allspice","cardamom"],cuisines:["British","German","French","Scandinavian","Austrian"],nanaNote:"It smells like a decision to stay inside. A good decision."},

  mixed_spice:{id:"mixed_spice",name:"British Mixed Spice",icon:"✨",origin:"Britain — the traditional spice blend for Christmas baking",region:"europe",flavor:["blend","warm","floral"],intensity:1,form:"Ground blend",summary:"Britain's answer to garam masala — the warming blend behind every Christmas cake and pudding.",what:"Typically contains cinnamon, coriander, nutmeg, cloves, ginger, and allspice. Essential flavouring for Christmas cake, Christmas pudding, and mince pies.",when:"Add to Christmas cake and pudding batter. Use in mince pies, hot cross buns, and gingerbread.",tip:"British mixed spice may need to be ordered outside the UK. Making your own from the component spices takes five minutes.",pairings:["cinnamon","nutmeg","allspice","cloves","ginger_powder"],cuisines:["British","Australian baking","New Zealand"],nanaNote:"Every Christmas cake made in Britain for 200 years has had this in it. That's a good record."},

  /* ── AMERICAS BLENDS ── */
  jerk_seasoning:{id:"jerk_seasoning",name:"Jerk Seasoning",icon:"✨",origin:"Jamaica — the Maroon communities of the Blue Mountains",region:"northamerica",flavor:["blend","smoky","pungent","warm"],intensity:3,form:"Dry rub or wet paste",summary:"Jamaica's fire and soul — allspice heat, scotch bonnet rage, and wood smoke.",what:"Authentic jerk contains scotch bonnet or habanero chili, allspice (the most important single ingredient), thyme, garlic, scallions, ginger, cinnamon, and cloves. Inseparable from its cooking method — low and slow over pimento (allspice) wood.",when:"Rub onto chicken and pork before grilling or smoking. Use as a seasoning for shrimp, fish, and tofu.",tip:"Allspice is the non-negotiable flavour — more than the chili, it's what makes jerk taste like jerk.",pairings:["allspice","dried_thyme","cinnamon","cloves","ginger_powder"],cuisines:["Jamaican","Caribbean"],nanaNote:"It needs fire and smoke to become itself. Don't try to make it in an oven."},

  old_bay:{id:"old_bay",name:"Old Bay Seasoning",icon:"✨",origin:"Maryland, USA — created in 1939 by German immigrant Gustav Brunn",region:"northamerica",flavor:["blend","pungent","herb"],intensity:2,form:"Ground blend",summary:"The Chesapeake Bay in a tin — celery salt, paprika, and a dozen more spices that define Mid-Atlantic seafood.",what:"A proprietary blend known to contain celery salt, paprika, black pepper, red pepper, and various other spices. The defining seasoning for blue crabs in Maryland and an American culinary institution.",when:"Season steamed crabs and shrimp. Add to boiling water for crab and lobster. Use in seafood dips, devilled eggs, and potato chips.",tip:"Make a homemade version: celery salt, sweet paprika, black pepper, cayenne, dry mustard, ground bay leaf, and mace.",pairings:["celery_seed","sweet_paprika","mustard","bay_leaf","cayenne"],cuisines:["American Mid-Atlantic","Chesapeake seafood tradition"],nanaNote:"Maryland crabs without Old Bay are just crabs. The tin matters."},

  creole_seasoning:{id:"creole_seasoning",name:"Creole Seasoning",icon:"✨",origin:"Louisiana, USA — New Orleans and surrounding parishes",region:"northamerica",flavor:["blend","pungent","herb"],intensity:2,form:"Ground blend",summary:"The taste of New Orleans — paprika, garlic, onion, and herbs that define Louisiana cooking.",what:"Typically contains paprika, garlic powder, onion powder, dried oregano, dried thyme, cayenne, black pepper, and white pepper. The foundational seasoning for étouffée, gumbo, jambalaya.",when:"Season shrimp for étouffée. Add to gumbo and jambalaya. Rub onto chicken and fish before searing.",tip:"Creole and Cajun seasonings overlap but differ — Creole is generally slightly more refined and herb-forward; Cajun tends hotter.",pairings:["sweet_paprika","garlic_powder","dried_thyme","dried_oregano","cayenne"],cuisines:["New Orleans","Louisiana Creole","American Southern"],nanaNote:"It's not just seasoning. It's a civilization's accumulated knowledge of what food should taste like."},

  cajun_seasoning:{id:"cajun_seasoning",name:"Cajun Seasoning",icon:"✨",origin:"Louisiana bayou country — the rural Acadian communities",region:"northamerica",flavor:["blend","pungent","smoky"],intensity:3,form:"Ground blend",summary:"Bayou fire — pepper-forward, direct, and unapologetically bold.",what:"Paprika-heavy, pepper-forward, and typically hotter than Creole seasoning. Components include paprika, cayenne, garlic powder, black and white pepper, onion powder, and dried herbs. Reflects the bold, direct flavours of rural Louisiana cooking.",when:"Use on blackened fish and chicken. Season dirty rice and red beans. For blackening — high-heat cast iron with Cajun seasoning produces a spectacular crust.",tip:"For blackened preparations, use a dry, very hot cast iron pan. The spice blend forms an intensely flavoured crust in about 90 seconds per side.",pairings:["smoked_paprika","cayenne","garlic_powder","dried_thyme","black_pepper"],cuisines:["Cajun Louisiana","American Southern","Bayou country"],nanaNote:"The 'blackened' technique is not burning. There's a difference. High heat, short time, proper seasoning."},

  adobo_seasoning:{id:"adobo_seasoning",name:"Adobo Seasoning",icon:"✨",origin:"Latin America and the Caribbean — widely used in Puerto Rican, Dominican, and Cuban cooking",region:"northamerica",flavor:["blend","pungent","earthy"],intensity:2,form:"Ground blend",summary:"The everyday seasoning of Latin Caribbean kitchens — simple, complete, and essential.",what:"Typically contains garlic powder, onion powder, dried oregano, black pepper, turmeric (for colour), and salt. Used as an all-purpose meat and vegetable seasoning.",when:"Season chicken, pork, and beef before cooking. Add to rice and bean dishes.",tip:"Commercial Goya adobo is salty — factor this in when using it.",pairings:["sazon","annatto","garlic_powder","dried_oregano","cumin"],cuisines:["Puerto Rican","Dominican","Cuban","Latin American broadly"],nanaNote:"Half the flavour of Puerto Rican cooking comes from this and sofrito. That's the whole foundation."},

  sazon:{id:"sazon",name:"Sazón",icon:"✨",origin:"Puerto Rico and Latin Caribbean — the colour and depth blend",region:"northamerica",flavor:["blend","earthy","warm"],intensity:1,form:"Ground blend",summary:"Latin Caribbean cooking's golden secret — annatto-orange, savoury, and the reason the rice is that colour.",what:"Typically contains annatto (for colour), garlic powder, cumin, coriander, and various other seasonings. The annatto gives everything a vivid orange-red hue.",when:"Add to rice for golden colour and depth. Use in sofrito-based preparations. Season beans, meat, and poultry.",tip:"Make your own from annatto, cumin, garlic powder, and oregano — commercial versions work but fresh is better.",pairings:["annatto","adobo_seasoning","garlic_powder","cumin","dried_oregano"],cuisines:["Puerto Rican","Dominican","Cuban","Latin American"],nanaNote:"It's why the rice is that colour. And why it tastes like Sunday."},

  chili_powder_blend:{id:"chili_powder_blend",name:"American Chili Powder",icon:"✨",origin:"American Southwest — a 19th century invention",region:"northamerica",flavor:["blend","smoky","warm"],intensity:2,form:"Ground blend",summary:"The Texan invention that became America's most versatile spice blend.",what:"Typically contains ground dried chilies (often ancho and guajillo), cumin, garlic powder, oregano, and sometimes paprika. Codified in Texas in the late 1800s for chili con carne.",when:"Foundation seasoning for American chili con carne. Use in taco meat, enchilada sauce, and Tex-Mex preparations.",tip:"American chili powder is mild enough to use generously. 1-2 tablespoons per pound of meat is not excessive.",pairings:["cumin","garlic_powder","smoked_paprika","dried_oregano","cayenne"],cuisines:["American Southwest and Tex-Mex","Texan","American broadly"],nanaNote:"It made its own cuisine. That's worth respecting."},

  sofrito_blend:{id:"sofrito_blend",name:"Sofrito Spice Blend",icon:"✨",origin:"Spain and Latin America — the aromatic base of much of the cooking world",region:"northamerica",flavor:["blend","herb","earthy"],intensity:1,form:"Dried blend",summary:"The aromatic foundation — the base that everything else is built on.",what:"Sofrito in its classic form is a fresh paste of onion, garlic, tomato, and peppers cooked in oil. The dry blend form contains dried, ground equivalents — used when convenience matters more than freshness.",when:"Use as a quick seasoning base for rice, beans, and stews. Add to braises and soups.",tip:"The fresh version — onion, garlic, ají dulce, culantro, and recao — is better in every way. Make a batch and freeze in ice cube trays.",pairings:["adobo_seasoning","sazon","annatto","dried_oregano","garlic_powder"],cuisines:["Puerto Rican","Dominican","Cuban","Spanish","Latin American"],nanaNote:"Every great dish in this tradition has sofrito somewhere underneath it."},

  /* ── OTHER BLENDS & FINISHING ── */
  khmeli_suneli:{id:"khmeli_suneli",name:"Khmeli-Suneli",icon:"✨",origin:"Georgia (country) — the defining blend of Georgian cuisine",region:"europe",flavor:["blend","floral","herb","warm"],intensity:2,form:"Ground blend",summary:"Georgia's aromatic masterpiece — fenugreek, marigold petals, and herbs in complex harmony.",what:"'Dried spices' in Georgian. Typically contains fenugreek, coriander, dill, marigold petals (calendula), basil, parsley, and various herbs. The marigold gives it a distinctive floral-earthy character unlike any other blend.",when:"Season walnut-based sauces and Georgian stews. Use in chakhokhbili and chicken preparations. A teaspoon transforms simple bean dishes.",tip:"The calendula/marigold component is key — don't substitute with saffron or turmeric for colour. The flavour is different.",pairings:["fenugreek","coriander","dried_basil","caraway","dried_tarragon"],cuisines:["Georgian","Armenian","Azerbaijani"],nanaNote:"Georgian food is underrated by people who haven't tried it. This spice blend is part of the reason."},

  recado_negro:{id:"recado_negro",name:"Recado Negro (Black Recado)",icon:"⬛",origin:"Yucatan, Mexico — the charred spice paste of Yucatecan cuisine",region:"northamerica",flavor:["blend","smoky","earthy"],intensity:2,form:"Paste (from charred ingredients)",summary:"Almost burned and completely intentional — Yucatan's deeply charred spice paste.",what:"Made from chilhuacle negro and spices toasted until nearly burnt, then ground into a paste. The flavour is intensely smoky and complex — dark enough to colour everything brown-black. The seasoning for relleno negro, one of Yucatan's signature dishes.",when:"Use in relleno negro and Yucatecan turkey preparations. Add to slow-braised meats. Use in small amounts to add smoky depth to moles.",tip:"The near-burning of the ingredients is intentional and essential — don't stop toasting before the colour is very dark.",pairings:["mulato","chipotle","allspice","cumin","dried_oregano"],cuisines:["Yucatecan","Mexican regional"],nanaNote:"It only makes sense in context. Yucatan makes its own rules, and they're good ones."},

  za_atar_blend:{id:"za_atar_blend",name:"Za'atar Blend (Commercial)",icon:"✨",origin:"Levant — widely available commercial version",region:"middleeast",flavor:["blend","herb","bright"],intensity:1,form:"Ground blend",summary:"The pantry-friendly version of the Levantine classic — always useful, never the same twice.",what:"Commercial za'atar blends use a consistent ratio of dried thyme or oregano, sumac, sesame, and salt. While every family blend differs, the commercial versions offer consistent, broadly appropriate flavour.",when:"Use anywhere za'atar is called for when making your own blend isn't feasible. Works in all the same applications — bread dipping, meat rubs, and finishing.",tip:"Check the ingredient list and buy ones where sumac and sesame are genuinely present, not just flavouring.",pairings:["sumac","aleppo","sesame_toasted","dried_oregano","nigella"],cuisines:["Lebanese","Palestinian","Syrian","Israeli","Jordanian"],nanaNote:"Even the commercial version beats not having it at all."},

  ras_el_hanout_premium:{id:"ras_el_hanout_premium",name:"Premium Ras el Hanout",icon:"✨",origin:"Morocco — high-end spice merchant versions",region:"africa",flavor:["blend","warm","floral"],intensity:2,form:"Ground blend",summary:"The ambitious version — rose petals, ras el hanout, and the promise of complexity.",what:"Premium ras el hanout versions from quality Moroccan spice merchants contain rose petals, dried lavender, cubeb pepper, grains of paradise, and other expensive components that mass-market versions omit. The difference is significant.",when:"Use in special occasion tagines, whole roasted lamb, and dishes where ras el hanout is a featured flavour.",tip:"For everyday use, any quality ras el hanout works. For a special meal, it's worth sourcing the premium version.",pairings:["cinnamon","rose_petals","cardamom","cumin","grains_of_paradise"],cuisines:["Moroccan","Algerian","Tunisian"],nanaNote:"The gap between the jar from the supermarket and the one from the souk is significant. Both are ras el hanout. Only one is the real thing."},

  garlic_powder:{id:"garlic_powder",name:"Garlic Powder",icon:"🧄",origin:"Global — dehydrated garlic is produced worldwide",region:"europe",flavor:["pungent","earthy"],intensity:2,form:"Ground powder",summary:"Concentrated allium depth — milder and sweeter than fresh, with its own distinct character.",what:"Garlic powder is made from dehydrated garlic ground into powder. It's not a substitute for fresh garlic — it has a different, mellower, slightly sweeter flavour that works better in certain applications like dry rubs and spice blends where fresh garlic would burn.",when:"Use in dry rubs, spice blends, and chili powders. Add to compound butter and spice mixes. Excellent in chili powder and Cajun seasoning.",tip:"Garlic powder burns easily in hot oil — it's best used in preparations where it doesn't get direct high heat. For cooked aromatics, fresh garlic is always better.",pairings:["smoked_paprika","cayenne","dried_oregano","cumin","black_pepper"],cuisines:["Global — universal in spice blends"],nanaNote:"Fresh garlic in the pan. Garlic powder in the dry rub. They're different jobs."},

  onion_powder:{id:"onion_powder",name:"Onion Powder",icon:"🧅",origin:"Global — dehydrated onion processed worldwide",region:"europe",flavor:["pungent","earthy","umami"],intensity:1,form:"Ground powder",summary:"Concentrated allium sweetness — the background note in almost every American spice blend.",what:"Dehydrated onion ground into a powder with a mellower, slightly sweeter flavour than fresh onion. Like garlic powder, it's not a substitute for fresh but serves a specific purpose in dry spice applications.",when:"Add to all dry spice blends, rubs, and seasoning mixes. Use in Cajun, Creole, and American BBQ blends. Add to compound butter and flavoured salts.",tip:"A blend of onion and garlic powder in a 2:1 ratio is the backbone of most American seasoning blends.",pairings:["garlic_powder","smoked_paprika","cayenne","dried_thyme","black_pepper"],cuisines:["American","BBQ tradition","Tex-Mex","Global spice blends"],nanaNote:"Nobody puts it in the spotlight. That's not what it's for."},

  smoked_salt:{id:"smoked_salt",name:"Smoked Salt",icon:"🌊",origin:"Various — cold-smoked sea salt from different wood sources",region:"europe",flavor:["smoky","umami"],intensity:2,form:"Flaky or coarse crystal",summary:"Salt with smoke memory — a finishing salt that adds campfire depth without any fire.",what:"Sea salt cold-smoked over various woods (oak, applewood, cherry, hickory) to absorb the aromatic smoke compounds. The result is a finishing salt with genuine smoky character that dissolves into food and delivers those compounds directly.",when:"Finish grilled meats, roasted vegetables, and eggs. Add to chocolate desserts for surprising depth. Use in popcorn, compound butters, and caramels.",tip:"Use as a finishing salt, not a cooking salt — the smoke compounds are volatile and cook off at high temperatures. Add after cooking.",pairings:["smoked_paprika","chipotle","black_pepper","garlic_powder","cumin"],cuisines:["Scandinavian","American BBQ","Modern European","Fusion"],nanaNote:"It's the closest you get to smoking something without actually smoking it. A useful shortcut."},

  sumac_powder:{id:"sumac_powder",name:"Sumac Powder (Fine Ground)",icon:"🔴",origin:"Middle East and Mediterranean — fine-ground version of dried Rhus coriaria berries",region:"middleeast",flavor:["bright"],intensity:1,form:"Finely ground powder",summary:"The more versatile form of sumac — same sourness, more easily distributed.",what:"Finely ground sumac (as opposed to the coarser standard grind) distributes more evenly in doughs, batters, and spice blends where the coarser version would be uneven. Same tart, fruity, slightly astringent flavour.",when:"Use in bread doughs and flatbread preparations. Add to spice rubs where even distribution matters. Use in salad dressings and marinades where you want the tartness integrated.",tip:"The coarser grind is better for finishing dishes (more textural interest). Fine ground is better for integrated preparations.",pairings:["za_atar","aleppo","cumin","coriander","dried_mint"],cuisines:["Lebanese","Turkish","Syrian","Persian","Israeli"],nanaNote:"Same spice, different purpose. The fineness matters more than you'd think."},

  grains_of_paradise_ground:{id:"grains_of_paradise_ground",name:"Ground Grains of Paradise",icon:"🟠",origin:"West Africa — pre-ground for convenience",region:"africa",flavor:["pungent","warm","bright"],intensity:2,form:"Ground powder",summary:"West Africa's native pepper in ground form — gingery, peppery, citrusy, and ready to use.",what:"Pre-ground grains of paradise for use in applications where grinding whole seeds isn't convenient. The flavour is more muted than freshly ground but still carries the distinctive citrus-pepper-ginger profile.",when:"Add directly to spice blends, rubs, and sauces. Use in recipes calling for white pepper when you want something more complex. Sprinkle over finished dishes.",tip:"Whole and freshly ground is better — the volatile citrus compounds fade quickly. But ground still delivers the general character.",pairings:["black_pepper","white_pepper","coriander","cardamom","ginger_powder"],cuisines:["West African","Ethiopian","Craft beverages","Modern European"],nanaNote:"Even pre-ground, it's more interesting than black pepper. That says something about how good it is whole."},

  /* ── ADDITIONAL SINGLES ── */
  juniper_berry:{id:"juniper_berry",name:"Juniper Berry",icon:"🔵",origin:"Northern Europe and North America — the berry of Juniperus communis",region:"europe",flavor:["bright","earthy","pungent"],intensity:2,form:"Dried whole berry",summary:"Pine-resinous, tart, and distinctly Nordic — the spice that defines gin and Scandinavian game.",what:"Juniper berries are the female seed cones of the juniper shrub — small, purple-black, and intensely aromatic with a piney, slightly citrusy, resinous flavour. They're the primary botanical in gin and essential to Scandinavian, German, and Alpine cooking.",when:"Crush lightly and add to game marinades, sauerkraut, and choucroute garnie. Use in cured meat and venison preparations. Add to brines and pâté mixtures.",tip:"Lightly crush the berries to release the oils — don't grind them into powder. Too many become medicinal and overwhelming. Four to six per pot is usually enough.",pairings:["caraway","bay_leaf","black_pepper","dried_sage","allspice"],cuisines:["Scandinavian","German","Austrian Alpine","French Alsatian","Game cooking"],nanaNote:"It smells like a cold forest and tastes like something the forest would approve of."},

  szechuan_ash:{id:"szechuan_ash",name:"Sichuan Numbing Powder Blend",icon:"🟣",origin:"Sichuan province, China — a prepared blend for maximum numbing effect",region:"eastasia",flavor:["pungent","floral","smoky"],intensity:3,form:"Ground blend",summary:"Pre-blended Sichuan pepper for maximum mala — the shortcut to the numbing experience.",what:"A prepared blend of toasted and ground Sichuan pepper, sometimes combined with salt and other aromatics for convenient seasoning of mapo tofu, dan dan noodles, and spiced meats.",when:"Use directly over finished Sichuan dishes. Add to chili oils. Season grilled meats and tofu.",tip:"Even this convenience blend is best used fresh — the numbing compounds are still volatile.",pairings:["gochugaru","star_anise","sichuan_pepper","cumin","chinese_five_spice"],cuisines:["Sichuan Chinese","Hunanese"],nanaNote:"It exists because the numbing is that good. Convenience products don't get created for things nobody wants."},

  dried_grapefruit_peel:{id:"dried_grapefruit_peel",name:"Dried Citrus Peel",icon:"🍊",origin:"Various — dried and ground outer rind of citrus fruits",region:"europe",flavor:["bright","floral"],intensity:1,form:"Dried peel or ground",summary:"Concentrated citrus brightness — the aromatic oil of the fruit preserved in dry form.",what:"The dried outer rind of citrus fruits — orange, lemon, grapefruit, or lime — contains the essential oils responsible for citrus aroma. When dried and ground, these oils are concentrated. Used extensively in spice blends, baking, and beverages.",when:"Add to mulling spice and holiday blends. Use in shichimi togarashi. Add to spice rubs where citrus brightness is wanted without moisture. Fold into pastry doughs and cookie batters.",tip:"The dried peel is more concentrated than fresh zest — use about a third as much as you would fresh zest.",pairings:["cardamom","star_anise","cinnamon","ginger_powder","sansho"],cuisines:["European baking","Japanese seasoning","Craft beverages","Global"],nanaNote:"A little in a spice blend is like a window opening in a closed room."},

  long_pepper_whole:{id:"long_pepper_whole",name:"Tellicherry Black Pepper",icon:"⚫",origin:"Tellicherry, Kerala, India — premium large-berry black pepper",region:"southasia",flavor:["pungent","warm","floral"],intensity:2,form:"Whole large peppercorn",summary:"The premium grade of black pepper — larger berry, longer vine-ripening, more complex flavour.",what:"Tellicherry peppercorns are black pepper berries allowed to ripen longer on the vine before harvest, developing larger berries and a more complex flavour profile — fruitier, more aromatic, and with more complex heat than standard black pepper.",when:"Use whole in a pepper grinder as your everyday black pepper. Grind over finished dishes where pepper is a featured flavour. Essential in steak au poivre.",tip:"Keep a dedicated grinder of Tellicherry for finishing dishes where pepper is noticed. Use standard black pepper for cooking.",pairings:["coriander","cardamom","cloves","cinnamon","mace"],cuisines:["Global — wherever black pepper is a hero ingredient"],nanaNote:"It's just pepper. But it's the best pepper. The extra week on the vine matters."},

  white_cardamom:{id:"white_cardamom",name:"White Cardamom (Bleached)",icon:"⬜",origin:"Guatemala and India — bleached version of green cardamom",region:"southasia",flavor:["floral","warm"],intensity:1,form:"Whole pod",summary:"Green cardamom's paler, milder sibling — used where appearance matters as much as flavour.",what:"White cardamom is simply green cardamom that has been bleached to remove the green colour. The flavour is milder and slightly less complex than green cardamom — the bleaching process affects some of the volatile oils.",when:"Use in Scandinavian baking and certain Middle Eastern sweet preparations where a lighter appearance is desirable. Add to white-coloured desserts and cream sauces.",tip:"For flavour, green cardamom is always better. White cardamom is an aesthetic choice.",pairings:["vanilla","cinnamon","rose_petals","mace","jasmine_dried"],cuisines:["Scandinavian","Swedish baking","Some Middle Eastern desserts"],nanaNote:"It's the same thing, but quieter. Sometimes that's what a dish needs."},

  sumac_lebanese:{id:"sumac_lebanese",name:"Lebanese Sumac (Coarse)",icon:"🔴",origin:"Lebanon — specifically from high-altitude Rhus coriaria harvest",region:"middleeast",flavor:["bright"],intensity:2,form:"Coarse wet-ground",summary:"The most potent and fresh-tasting sumac — coarser, oilier, and more vibrant than standard.",what:"Lebanese sumac ground coarser and with more residual moisture than standard versions. The result is more potent — more tart, more fruity, slightly oilier — and best used where you want sumac to be actually tasted rather than just present.",when:"Use as a condiment alongside lamb and chicken. Sprinkle over fattoush and fatoush generously. Mix with olive oil and serve alongside bread.",tip:"Because it's coarser and moister, it dissolves more slowly in dressings — add early if you want it integrated.",pairings:["za_atar","aleppo","dried_mint","cumin","nigella"],cuisines:["Lebanese","Palestinian","Syrian"],nanaNote:"When someone passes you the sumac at a Lebanese table, take a generous amount. They mean it."},

  malabar_black_pepper:{id:"malabar_black_pepper",name:"Malabar Black Pepper",icon:"⚫",origin:"Malabar Coast, Kerala, India — the original black pepper of spice trade routes",region:"southasia",flavor:["pungent","warm"],intensity:2,form:"Whole peppercorn",summary:"The historic black pepper — earthy, warm, and what built the ancient spice trade.",what:"Malabar black pepper comes from the Malabar coast of Kerala and has been traded since at least 3,000 BCE. The flavour is earthy and warm with less of the brightness that Tellicherry (a Malabar variety picked later) develops. A classic workhouse black pepper.",when:"Use in everyday cooking wherever black pepper is called for. Excellent in stocks, braises, and spice rubs.",tip:"Great everyday pepper for cooking where Tellicherry's premium character would be wasted.",pairings:["coriander","cumin","cardamom","cinnamon","fenugreek"],cuisines:["Global — especially South Asian and European cooking traditions"],nanaNote:"The spice that changed the world. Every pepper grinder descends from this history."},

  long_peppercorn_javanese:{id:"long_peppercorn_javanese",name:"Javanese Long Pepper",icon:"🟫",origin:"Java, Indonesia — Piper retrofractum",region:"oceania",flavor:["warm","pungent","floral"],intensity:3,form:"Whole dried catkin",summary:"The Indonesian cousin of Indian long pepper — slightly sweeter and more complex.",what:"Piper retrofractum is the Indonesian species of long pepper, with a distinctly sweeter, more fruity flavour than the Indian species (Piper longum). Used in Balinese and Javanese cooking as well as in traditional Indonesian medicine.",when:"Grind over meat dishes and rich braises. Use in Indonesian spice pastes alongside galangal and lemongrass. Try in spice blends where you want warmth with complexity.",tip:"Interchangeable with Indian long pepper but has a slightly softer, sweeter character.",pairings:["kencur","galangal","fingerroot","lemongrass_dried","turmeric"],cuisines:["Indonesian","Balinese","Javanese"],nanaNote:"Two plants, same name, different personalities. The archipelago always adds its own flavour."},

  dried_sumac_berry:{id:"dried_sumac_berry",name:"Whole Dried Sumac Berry",icon:"🔴",origin:"Middle East — for grinding or decoration",region:"middleeast",flavor:["bright"],intensity:2,form:"Whole dried berry cluster",summary:"The unprocessed form — grind your own for maximum freshness.",what:"Whole dried sumac berry clusters before grinding. Grinding your own sumac produces a fresher, more potent result than pre-ground sumac, though it's rarely necessary. Also used as a visual garnish in certain presentations.",when:"Grind just before using for maximum potency. Use whole clusters as a visual garnish in fine dining presentations.",tip:"Grind in a spice grinder with a small amount of salt to prevent clumping — this is traditional and extends shelf life.",pairings:["za_atar","aleppo","cumin","dried_mint","coriander"],cuisines:["Lebanese","Turkish","Syrian","Fine dining"],nanaNote:"Grinding your own is rarely worth it for everyday cooking. For a special dish, it is."},

  szechuan_oil_flakes:{id:"szechuan_oil_flakes",name:"Sichuan Chili Crisp",icon:"🌶",origin:"Sichuan province, China — crispy chili oil preparation",region:"eastasia",flavor:["smoky","pungent","umami"],intensity:2,form:"Oil-preserved crispy flakes",summary:"The condiment that became a global phenomenon — crispy, oily, numbing, and endlessly versatile.",what:"Sichuan chili crisp combines dried chilies, Sichuan pepper, garlic, shallots, and other aromatics fried in oil until crispy. The result is simultaneously a spice preparation, a condiment, and an oil. Brands like Lao Gan Ma popularized it globally.",when:"Spoon over rice, noodles, dumplings, and eggs. Add to stir-fry bases. Stir into mayonnaise and yogurt. Use as a finishing condiment on anything that needs lift.",tip:"The crispy bits are as important as the oil — don't just pour the oil, spoon the whole thing.",pairings:["sichuan_pepper","gochugaru","sesame_toasted","ginger_powder","star_anise"],cuisines:["Chinese","Taiwanese","Global fusion"],nanaNote:"It went from a Sichuan grandmother's recipe to a global pantry staple in about ten years. There's a reason."},

  /* ── FINAL BATCH — REGIONAL & SPECIALTY ── */
  aleppo_turkish:{id:"aleppo_turkish",name:"Pul Biber (Turkish Aleppo)",icon:"🫙",origin:"Turkey — the Turkish-grown version of Aleppo pepper",region:"middleeast",flavor:["smoky","warm","bright"],intensity:2,form:"Coarse flakes",summary:"The Turkish cousin of Aleppo pepper — slightly hotter, equally oily and fruity.",what:"Pul biber is what Aleppo pepper became after production in Syria became difficult — Turkish-grown red pepper flakes processed similarly. Slightly hotter than Aleppo but with the same oily, fruity, complex character.",when:"Use exactly as you would Aleppo pepper. Sprinkle over dishes at the table. Bloom in olive oil. Finish hummus and labneh.",tip:"Keep refrigerated for the same reasons as Aleppo — the oil content makes it go rancid faster at room temperature.",pairings:["sumac","cumin","smoked_paprika","za_atar","aleppo"],cuisines:["Turkish","Syrian","Lebanese","Greek","Italian"],nanaNote:"If you can't find Aleppo, this is the closest thing."},

  miso_powder:{id:"miso_powder",name:"Miso Powder",icon:"🟡",origin:"Japan — dehydrated fermented soybean paste",region:"eastasia",flavor:["umami","earthy"],intensity:2,form:"Dried powder",summary:"Concentrated fermented soybean umami — miso's depth in a dry, shelf-stable form.",what:"Miso paste dehydrated into a powder, concentrating its salty, savoury, fermented depth. Doesn't replace fresh miso for soups but extremely useful in spice rubs, marinades, and anywhere you want miso character without moisture.",when:"Add to spice rubs for salmon, chicken, and pork. Stir into compound butters. Use in popcorn seasoning and flavoured salts. Add to salad dressings and vinaigrettes.",tip:"It's saltier than it seems — account for it in overall seasoning.",pairings:["sesame_toasted","ginger_powder","kombu_powder","sansho","shichimi"],cuisines:["Japanese","Plant-based cooking","Modern fusion"],nanaNote:"Miso soup needs the real thing. Spice rubs need this."},

  bonito_flakes:{id:"bonito_flakes",name:"Katsuobushi (Bonito Flakes)",icon:"🌊",origin:"Japan — shaved dried fermented skipjack tuna",region:"eastasia",flavor:["umami","smoky","earthy"],intensity:2,form:"Dried shaved flakes",summary:"The second ingredient in dashi — smoky, fishy, and the umami heart of Japanese cooking.",what:"Katsuobushi is skipjack tuna that has been smoked, fermented, and dried until rock-hard, then shaved into paper-thin flakes. Combined with kombu it makes dashi, the foundational stock of Japanese cuisine. The flakes also 'dance' when placed on hot food from the rising steam.",when:"Essential in making dashi stock. Use as a topping for okonomiyaki, takoyaki, and rice. Add to furikake blends. Use in Japanese-style salad dressings.",tip:"Always add bonito flakes at the end — never boil them for more than a minute in dashi, or the stock becomes bitter.",pairings:["kombu_powder","sansho","sesame_toasted","shichimi","miso_powder"],cuisines:["Japanese"],nanaNote:"It moves when you put it on hot food. That never stops being wonderful."},

  dried_shrimp:{id:"dried_shrimp",name:"Dried Shrimp",icon:"🦐",origin:"Southeast Asia, East Asia, and West Africa — universal dried seafood product",region:"eastasia",flavor:["umami","pungent"],intensity:3,form:"Whole dried or ground",summary:"Concentrated oceanic umami — small, funky, and more powerful than its size suggests.",what:"Small shrimp dried until shelf-stable, intensifying their umami and developing a complex, slightly fermented quality. Used in East Asian, Southeast Asian, West African, and Latin American cooking as a flavour booster.",when:"Add to fried rice, pad thai, and Asian noodle soups. Grind and add to West African stews. Use in Malaysian and Indonesian spice pastes. Add to Mexican preparations.",tip:"Soak in warm water before use in most applications — this softens them and removes excess salt. The soaking water is also useful.",pairings:["belacan_powder","lemongrass_dried","bird_eye","dawadawa","turmeric"],cuisines:["Chinese","Southeast Asian broadly","West African","Mexican coastal","Vietnamese"],nanaNote:"Every coastal culture has worked out that dried shrimp can save a dish. This is not a coincidence."},

  licorice_root:{id:"licorice_root",name:"Licorice Root (Dried)",icon:"🪵",origin:"Mediterranean and Central Asia — the root of Glycyrrhiza glabra",region:"europe",flavor:["floral","bright","earthy"],intensity:2,form:"Dried stick or powder",summary:"Sweet, anise-like, and deeply distinctive — the original licorice before it became candy.",what:"The dried root of Glycyrrhiza glabra, naturally 50 times sweeter than sugar from its compound glycyrrhizin. The flavour is sweet, anise-like, and slightly earthy-woody. Used in Traditional Chinese Medicine, Ayurveda, and some European culinary traditions.",when:"Add to spiced broths and stocks for sweetness and depth. Use in certain spiced teas and beverages. Add to marinades for duck and pork.",tip:"The sweetness is very powerful. Use sparingly — a small piece in a braise is usually enough.",pairings:["star_anise","fennel","cinnamon","cardamom","vanilla"],cuisines:["Chinese medicinal","Italian","Scandinavian","Herbal traditions"],nanaNote:"The plant the candy was named after is quite different from the candy. Worth knowing."},

  dried_chipotle_whole:{id:"dried_chipotle_whole",name:"Chipotle (Whole Dried)",icon:"💨",origin:"Mexico — whole smoke-dried jalapeño",region:"northamerica",flavor:["smoky","warm"],intensity:2,form:"Whole dried smoked pod",summary:"The whole pod form of chipotle — more complex and controllable than the powder.",what:"The whole dried form of smoke-cured jalapeño allows for more controlled use — you can add a whole pod to a braise, reconstitute it in water, or grind it yourself. The flavour is more nuanced than powder because it hasn't oxidized.",when:"Add whole to braises, stocks, and soups. Soak in boiling water and blend into sauces. Remove before serving if you want the flavour without the texture.",tip:"Soak in boiling water for 20 minutes before blending. The soaking water is itself useful — smoky and flavourful, use it in the sauce.",pairings:["ancho","guajillo","cumin","cinnamon","garlic_powder"],cuisines:["Mexican","Tex-Mex","American BBQ"],nanaNote:"The whole pod gives you options the powder doesn't. Always worth having a few in the cupboard."},

  carob_powder:{id:"carob_powder",name:"Carob Powder",icon:"🟤",origin:"Mediterranean — the pod of Ceratonia siliqua",region:"europe",flavor:["earthy","warm","floral"],intensity:1,form:"Ground powder",summary:"Sweet, faintly chocolatey, and distinctly its own thing — not a substitute, an ingredient.",what:"Carob is the ground dried pod of a Mediterranean tree. Its flavour is earthy, slightly sweet, and reminiscent of chocolate but distinctly different — less bitter, slightly more herbal. It was the 'sweetener of the ancient world' before cane sugar.",when:"Use in spice blends as a sweet-earthy note. Add to North African preparations. Use in baking where you want chocolate-adjacent depth without caffeine or bitterness.",tip:"Carob is not chocolate. Treating it as a chocolate substitute always disappoints. Treat it as its own ingredient.",pairings:["cinnamon","allspice","ginger_powder","vanilla","cardamom"],cuisines:["Mediterranean","North African","Traditional European","Health food"],nanaNote:"It was the sweetener before sweetener. That history should earn some respect."},

  black_lime_persian:{id:"black_lime_persian",name:"Black Lime (Fully Dried)",icon:"⚫",origin:"Persia — the deeply darkened version of dried loomi",region:"middleeast",flavor:["bright","earthy","floral"],intensity:3,form:"Whole black dried fruit",summary:"The darkest, most intensely fermented form of dried lime — concentrated Silk Road sourness.",what:"Black limes (as opposed to the lighter tan-coloured loomi) have been dried longer, developing an almost black exterior and a more intense, fermented, complex sour flavour with deeper earthy notes. Used in the same applications as lighter loomi but with more intensity.",when:"Use in Persian and Gulf preparations wherever dried lime is called for, but in smaller quantities. The flavour is more concentrated.",tip:"One black lime can do the work of two tan loomi in a braise. Start with less.",pairings:["saffron","sumac","barberry","cumin","cardamom"],cuisines:["Persian","Iraqi","Gulf Arab"],nanaNote:"Darker isn't always stronger. In this case it is."},

  pink_himalayan_salt:{id:"pink_himalayan_salt",name:"Pink Himalayan Salt",icon:"🪨",origin:"Khewra Salt Mine, Pakistan — 250 million year old ancient sea salt",region:"southasia",flavor:["umami","earthy"],intensity:1,form:"Fine or coarse crystal",summary:"Ancient mineral-rich salt — with a mild flavour difference and a beautiful colour.",what:"Himalayan pink salt gets its colour from trace minerals including iron oxide. The flavour is marginally different from regular table salt — slightly more mineral, marginally less sodium-forward. Used both as a cooking salt and a finishing salt.",when:"Use as a finishing salt for visual impact on darker dishes. Cook with it in the same way as any sea salt. Use in spice rubs where a mineral note is desired.",tip:"The health claims surrounding it are largely marketing. It's good salt. But so is good sea salt.",pairings:["black_pepper","dried_herbs","smoked_salt","garlic_powder","sumac"],cuisines:["Global"],nanaNote:"It's salt. Good salt. But mostly it's salt. Don't let the colour distract you from seasoning properly."},

  long_pepper_grains:{id:"long_pepper_grains",name:"Cubeb Tailed Pepper",icon:"🟤",origin:"Java and the Spice Islands — the pepper with a tail",region:"oceania",flavor:["pungent","floral","warm"],intensity:2,form:"Whole dried berry with pedicel",summary:"Java's piney pepper — distinctly aromatic, medicinal, and medieval in character.",what:"Piper cubeba looks like black pepper but each berry retains its 'tail' (the pedicel). The flavour is pungent but distinctly aromatic — piney, eucalyptus, and almost camphor. Used extensively in North African and medieval European cooking.",when:"Use in Moroccan spice blends and ras el hanout. Crush over game meats and lamb. Experiment in medieval European recipes.",tip:"It's more aromatic and less straightforwardly 'peppery' than black pepper. Use less, taste more.",pairings:["grains_of_paradise","long_pepper","black_pepper","allspice","cinnamon"],cuisines:["North African","Moroccan","Medieval European","Indonesian"],nanaNote:"If black pepper is a commoner, cubeb is an eccentric aristocrat. Both have their uses."},

  saffron_threads_spanish:{id:"saffron_threads_spanish",name:"Spanish Saffron",icon:"🌺",origin:"La Mancha, Spain — Crocus sativus",region:"europe",flavor:["floral","bright","earthy"],intensity:1,form:"Thread",summary:"The European saffron — earthier than Persian, essential in paella and bouillabaisse.",what:"Spanish saffron (particularly from La Mancha, with its own DO designation) has a slightly different flavour profile from Persian saffron — earthier, with a slightly more muted sweetness and more pronounced hay-like quality. Essential in paella and bouillabaisse.",when:"Steep in warm (not boiling) white wine or stock for paella. Add to bouillabaisse. Use in risotto Milanese. Season Catalan rice dishes.",tip:"For paella specifically, Spanish saffron is more authentic and slightly better-suited than Persian saffron.",pairings:["smoked_paprika","garlic_powder","dried_oregano","fennel","white_pepper"],cuisines:["Spanish","French Provençal","Italian","Catalan"],nanaNote:"Persian saffron and Spanish saffron are both wonderful and slightly different. Knowing the difference is knowing the cuisine."},

  chipotle_morita:{id:"chipotle_morita",name:"Chipotle Morita",icon:"🟣",origin:"Mexico — a specific variety of dried smoked jalapeño",region:"northamerica",flavor:["smoky","warm","bright"],intensity:2,form:"Dried whole pod",summary:"The fruitier, less smoked chipotle — darker, more complex, and with more jalapeño character.",what:"Chipotle morita is a specific type of chipotle dried for a shorter time than the standard meco variety. It's darker purple-red, fruitier, slightly less smoky, and more tender. The flavour has more of the original jalapeño character.",when:"Use in sauces, salsas, and braised preparations where you want fruity smoke rather than pure campfire. Excellent in mole and adobo.",tip:"The morita is easier to rehydrate than meco chipotle due to its shorter drying time.",pairings:["ancho","guajillo","pasilla","cumin","garlic_powder"],cuisines:["Mexican","Tex-Mex","Southwestern"],nanaNote:"There are at least seven types of chipotle. That's how much the detail matters in Mexican cooking."},

  smoked_chili_blend:{id:"smoked_chili_blend",name:"Smoked Chili Blend",icon:"✨",origin:"Contemporary — combining the best of Mexican and Spanish smoky traditions",region:"northamerica",flavor:["blend","smoky","warm"],intensity:2,form:"Ground blend",summary:"The best of two traditions — Mexican dried chilies and Spanish smoked paprika in one.",what:"A contemporary blend combining ground ancho, guajillo, or pasilla with Spanish smoked paprika for a spice blend that delivers both Mexican chili depth and the campfire quality of pimentón. A practical everyday all-rounder.",when:"Use in spice rubs for chicken, pork, and beef. Add to chili and bean preparations. Season roasted vegetables.",tip:"Easy to make at home: 2 parts ancho powder, 1 part smoked paprika, 1 part guajillo. Adjust to taste.",pairings:["cumin","garlic_powder","dried_oregano","cayenne","coriander"],cuisines:["American fusion","Contemporary cooking","Tex-Mex","BBQ"],nanaNote:"It doesn't have a tradition. It has a purpose. That's enough."},

  vadouvan:{id:"vadouvan",name:"Vadouvan (French Curry)",icon:"✨",origin:"South India via French colonial Pondicherry — a Franco-Indian masala",region:"europe",flavor:["blend","warm","pungent"],intensity:2,form:"Dried blend (roasted shallot and spice)",summary:"The most elegant curry blend — Indian spices roasted with French shallots into something quietly extraordinary.",what:"Vadouvan is a French take on Indian curry, developed in the Pondicherry region when it was a French colony. It combines curry spices (cumin, coriander, turmeric, fenugreek) with caramelised shallots and garlic, dried and ground together. The result is aromatic, slightly sweet, and more refined than standard curry powder.",when:"Use in upscale French-influenced preparations. Excellent in shellfish bisques and cream sauces. Add to roasted cauliflower and squash. Use in refined vegetable dishes.",tip:"Its sweetness from the caramelised shallot base makes it particularly good with naturally sweet vegetables and shellfish.",pairings:["turmeric","cumin","coriander","fenugreek","cardamom"],cuisines:["French Indian","Modern European","Contemporary French"],nanaNote:"It's what happens when France decides to engage seriously with Indian spice. Very polite. Very good."},

  sarawak_pepper:{id:"sarawak_pepper",name:"Sarawak White Pepper",icon:"⬜",origin:"Sarawak, Malaysia — protected GI product",region:"oceania",flavor:["pungent","earthy"],intensity:2,form:"Whole berry or ground",summary:"Malaysia's premium white pepper — milder and more aromatic than most white peppers, with a clean heat.",what:"Sarawak white pepper (from Malaysian Borneo) undergoes an extended washing process that removes bitterness and some of the harsher fermented notes associated with other white peppers. The result is a cleaner, rounder, less pungent white pepper.",when:"Use in cream sauces, white soups, and preparations where white pepper is specifically needed but gentleness is important. Excellent in Sarawak-style laksa.",tip:"The cleaner flavour makes it interchangeable with standard white pepper in most applications, and noticeably better in delicate preparations.",pairings:["white_pepper","ginger_powder","galangal","lemongrass_dried","makrut_lime_leaf"],cuisines:["Malaysian","Sarawakian","Southeast Asian broadly","European fine dining"],nanaNote:"Even within a category — white pepper — there is best and there is everything else."},

  piment_doux:{id:"piment_doux",name:"Piment Doux (Sweet Basque Pepper)",icon:"🍎",origin:"French Basque Country — the milder relative of piment d'Espelette",region:"europe",flavor:["warm","bright"],intensity:1,form:"Ground powder",summary:"The Basque sweet pepper — all the warmth of Espelette without any heat.",what:"Piment doux is the non-spicy version of Basque red pepper — sweet, slightly smoky, and with the characteristic Basque pepper flavour without any capsaicin heat. Used in Basque cooking alongside piment d'Espelette.",when:"Use in Basque preparations where you want colour and pepper flavour without heat. Blend with Espelette in different ratios to dial in heat. Use as sweet paprika in Basque-inspired dishes.",tip:"Mixing piment doux with piment d'Espelette in different ratios is the traditional way of controlling heat in Basque dishes.",pairings:["espelette","smoked_paprika","dried_thyme","fennel","garlic_powder"],cuisines:["Basque","French","Spanish"],nanaNote:"Heat can be added. It's harder to subtract. Starting with the sweet version gives you control."},

  calabrian_chili:{id:"calabrian_chili",name:"Calabrian Chili",icon:"🌶",origin:"Calabria, southern Italy — the 'nduja chili of Italian cuisine",region:"europe",flavor:["smoky","pungent","bright"],intensity:2,form:"Dried flakes or in oil",summary:"Italy's fiery southern secret — fruity, oily, and the heat behind 'nduja and Calabrian cooking.",what:"Calabrian chili is a specific type of Italian chili grown in Calabria, the toe of Italy's boot. Processed into either dried flakes or a paste preserved in oil. The flavour is fruity, moderately spicy, and with an underlying richness from the olive oil preservation.",when:"Add to pasta sauces, pizza, and Italian-style braises. Stir into aioli, compound butter, and ricotta. Use in anything where you want Italian heat that isn't just 'hot.'",tip:"The oil-packed version is both a chili and a flavoured oil — use both the peppers and the oil.",pairings:["smoked_paprika","fennel","dried_oregano","aleppo","garlic_powder"],cuisines:["Calabrian Italian","Southern Italian broadly","Modern Italian"],nanaNote:"Southern Italy runs hot in more ways than one. This is the flavour of that heat."},

  szechuan_doubanjiang:{id:"szechuan_doubanjiang",name:"Doubanjiang Powder",icon:"🟥",origin:"Sichuan province, China — fermented broad bean chili paste, dried",region:"eastasia",flavor:["umami","pungent","smoky"],intensity:3,form:"Dried powder",summary:"The fermented soul of Sichuan cooking — concentrated broad bean and chili in dry form.",what:"Doubanjiang is the fermented broad bean and chili paste that is called the 'soul of Sichuan cuisine.' Dried into powder, it retains its funky, savoury, complex heat. Essential for mapo tofu, twice-cooked pork, and Sichuan braises.",when:"Use in dry spice blends for Sichuan dishes when fresh doubanjiang isn't available. Add to spice rubs for pork and beef. Use sparingly as a seasoning.",tip:"The fresh paste version is significantly better than the powder. Use the powder only when you don't have access to the paste.",pairings:["sichuan_pepper","gochugaru","ginger_powder","star_anise","chinese_five_spice"],cuisines:["Sichuan Chinese"],nanaNote:"Mapo tofu without doubanjiang isn't mapo tofu. This is the rule, not a preference."},

  hawaiian_sea_salt:{id:"hawaiian_sea_salt",name:"Hawaiian Red Sea Salt (Alaea)",icon:"🔴",origin:"Hawaii — sea salt mixed with volcanic red clay (alaea)",region:"northamerica",flavor:["earthy","umami"],intensity:1,form:"Coarse crystal",summary:"Iron-red Hawaiian finishing salt — mineral, gentle, and distinctly of its place.",what:"Alaea red salt gets its colour and mineral character from volcanic red clay (alaea) that is mixed into the salt. The result is a salt with a mildly earthy, mineral quality and a beautiful red colour. Used traditionally in Hawaiian cooking for certain preparations.",when:"Use as a finishing salt for poke, grilled fish, and Hawaiian preparations. Season traditional Hawaiian dishes including kalua pork. Use as a visual finishing element.",tip:"It's a seasoning salt with place-specific character — use it in preparations where you want that Hawaiian connection or as a beautiful finishing salt.",pairings:["sesame_toasted","ginger_powder","soy","garlic_powder","smoked_paprika"],cuisines:["Hawaiian","Pacific Rim","Poke and raw fish preparations"],nanaNote:"The colour comes from the island. That's what a sense of place tastes like."},

  lemon_myrtle:{id:"lemon_myrtle",name:"Lemon Myrtle",icon:"🌿",origin:"Queensland, Australia — Backhousia citriodora",region:"oceania",flavor:["bright","herb","floral"],intensity:2,form:"Dried leaf or ground",summary:"More lemony than lemon — the Australian native with the highest citral content of any plant.",what:"Lemon myrtle (Backhousia citriodora) is a native Australian plant with a higher citral (the compound responsible for lemon aroma) content than lemon itself. The flavour is intensely citrusy, slightly floral, and with a unique herbal quality.",when:"Use in seafood preparations, poultry, and desserts where lemon flavour is wanted but without the acidity. Add to herbal teas and infusions. Use in Australian native-inspired cooking.",tip:"It's potent — use about a quarter of what you'd use of dried lemon verbena to start.",pairings:["makrut_lime_leaf","lemongrass_dried","elderflower","chamomile_culinary","vanilla"],cuisines:["Australian native","Contemporary Australian","Seafood preparations"],nanaNote:"It smells more like lemon than a lemon does. Australia has several ingredients like this. Most people haven't found them yet."},

  native_pepper:{id:"native_pepper",name:"Tasmanian Pepper (Szechuan-like)",icon:"🟢",origin:"Tasmania, Australia — Tasmannia lanceolata",region:"oceania",flavor:["pungent","bright","floral"],intensity:3,form:"Dried berry or ground",summary:"Australia's native peppercorn — numbing like Sichuan, piney like juniper, and unlike anything else.",what:"Tasmanian mountain pepper (Tasmannia lanceolata) is a native Australian plant whose berries have a unique tingly heat similar to Sichuan pepper but with additional piney, eucalyptus, and fruity notes. One of the most exciting native Australian ingredients.",when:"Grind over red meat, game, and strong-flavoured fish. Use in native Australian spice blends. Experiment as a Sichuan pepper substitute in dishes where you want more complexity.",tip:"The heat builds slowly and persists — more so than Sichuan pepper. Start with less.",pairings:["lemon_myrtle","native_pepper","sichuan_pepper","juniper_berry","black_pepper"],cuisines:["Australian native","Contemporary Australian","Game cooking"],nanaNote:"An entire continent's spice tradition that barely gets any attention. That's changing, slowly."},

  sumac_turkish:{id:"sumac_turkish",name:"Turkish Sumac",icon:"🔴",origin:"Turkey — Rhus coriaria grown and processed in Turkish tradition",region:"middleeast",flavor:["bright"],intensity:2,form:"Ground powder (often more moist than Lebanese)",summary:"The Turkish take on sumac — equally tart but with slightly different processing traditions.",what:"Turkish sumac is processed slightly differently from Lebanese sumac — often ground to a slightly finer texture and sometimes with added salt. The tartness and colour are similar but the Turkish version tends to be more integrated and less overtly moist.",when:"Use in Turkish salads, grilled meat preparations, and yogurt-based dips. Essential in Turkish shepherd's salad and çoban salatası.",tip:"Turkish and Lebanese sumac are interchangeable in most applications. Prefer the unsalted version when available for more control.",pairings:["dried_mint","dried_oregano","black_pepper","aleppo_turkish","cumin"],cuisines:["Turkish","Kurdish","Azerbaijan"],nanaNote:"The same plant, different hands. The place where you grow it and the way you process it changes it slightly. That's not marketing — that's agriculture."},

  /* ── FINAL 30: TO 220 ── */
  fenugreek_leaf:{id:"fenugreek_leaf",name:"Fenugreek Leaf (Fresh Dried)",icon:"🌿",origin:"South Asia and the Mediterranean",region:"southasia",flavor:["herb","warm","earthy"],intensity:2,form:"Dried whole leaf",summary:"The bridge between fenugreek seed's bitterness and kasuri methi's gentleness — less processed, more rustic.",what:"Freshly dried fenugreek leaves, dried quickly rather than the slow-cure of kasuri methi. Slightly more bitter and leafy than kasuri methi, with the same maple-grassy base. Used in North African and South Asian cooking.",when:"Crumble into dals, vegetable curries, and spiced flatbreads. Add to North African spice blends. Use in Moroccan preparations alongside cumin and coriander.",tip:"Less processed than kasuri methi — use it in heartier preparations that can carry a bit more bitterness.",pairings:["fenugreek","kasuri_methi","cumin","turmeric","coriander"],cuisines:["North Indian","Pakistani","North African","Moroccan"],nanaNote:"It's a different conversation than kasuri methi. Both are worth having."},

  black_cumin:{id:"black_cumin",name:"Black Cumin (Kala Jeera)",icon:"⚫",origin:"North India, Central Asia — Bunium persicum, not to be confused with nigella",region:"southasia",flavor:["warm","earthy"],intensity:2,form:"Whole seed or ground",summary:"Cumin's smaller, earthier, more intense cousin — the elite spice of Kashmiri and Persian cooking.",what:"Black cumin (Bunium persicum or Carum carvi var. black) is a smaller, darker seed than regular cumin with a more intense, slightly sweeter, earthier character. Often confused with nigella (which it is not). Used in Kashmiri, Persian, and Central Asian cooking where its refined character is prized.",when:"Use in Kashmiri biryanis and yakhni. Add to Persian rice dishes. Use in Central Asian pilafs. Toast lightly before grinding for full flavour.",tip:"Do not confuse with nigella — they look similar in some contexts but taste completely different. Black cumin is cumin-adjacent; nigella is peppery and herbal.",pairings:["cardamom","saffron","cinnamon","coriander","rose_petals"],cuisines:["Kashmiri","Persian","Central Asian","Afghan"],nanaNote:"The rarest and most refined of the cumin family. Worth seeking out if you cook Kashmiri food seriously."},

  dried_chervil:{id:"dried_chervil",name:"Dried Chervil",icon:"🌿",origin:"Eastern Europe and the Middle East — one of the classic French fines herbes",region:"europe",flavor:["herb","floral","bright"],intensity:1,form:"Dried leaf",summary:"Delicate, anise-soft, and quintessentially French — the most retiring of the fines herbes.",what:"Chervil (Anthriscus cerefolium) has a very delicate, slightly anise-like flavour that sits between flat-leaf parsley and tarragon. It's one of the four classic French fines herbes and loses its character extremely quickly when dried — fresh is enormously better.",when:"Use dried only in cooked preparations. Add to béarnaise alongside dried tarragon. Include in French herb blends and compound butters.",tip:"Dried chervil is a significant downgrade from fresh. If you have access to fresh chervil, use that. The dried version is a convenience, not a preference.",pairings:["dried_tarragon","dried_thyme","bay_leaf","fennel","dried_basil"],cuisines:["French","Belgian","Central European"],nanaNote:"The most overlooked of the fines herbes. Delicate things often are."},

  sumac_salt:{id:"sumac_salt",name:"Sumac Salt",icon:"🔴",origin:"Middle East — a blended finishing condiment",region:"middleeast",flavor:["bright","earthy"],intensity:1,form:"Blended finishing salt",summary:"Tart and mineral — sumac and sea salt combined for an instant finishing condiment.",what:"A simple blend of ground sumac and flaky sea salt, often with a touch of dried thyme or za'atar herbs. Provides the tartness of sumac and the seasoning of salt simultaneously, useful as a finishing condiment.",when:"Use as a finishing sprinkle on grilled meats, fish, avocado, and salads. Serve as a dipping condiment alongside olive oil and bread.",tip:"Make your own — 2 parts sumac to 1 part flaky sea salt, with a pinch of dried thyme if desired. Better than commercial blends.",pairings:["sumac","za_atar","dried_thyme","sesame_toasted","aleppo"],cuisines:["Lebanese","Turkish","Israeli","Modern Middle Eastern"],nanaNote:"It's a shortcut. A good shortcut. Not all shortcuts are wrong."},

  celery_salt:{id:"celery_salt",name:"Celery Salt",icon:"🟡",origin:"Europe and America — celery seed ground with sea salt",region:"europe",flavor:["pungent","herb","earthy"],intensity:2,form:"Blended salt",summary:"The seasoning that defines devilled eggs, Bloody Marys, and Chicago hot dogs.",what:"Celery seed ground with fine sea salt in roughly equal proportions. The celery seed provides its characteristic intense, slightly bitter, umami-adjacent flavour integrated directly into a seasoning salt.",when:"Season devilled eggs and egg salad. Add to Bloody Marys. Essential on a Chicago-style hot dog (with celery salt, sport peppers, tomato, and relish). Use in coleslaw and potato salad.",tip:"Make your own — the ratio is roughly 1:1 celery seed to fine sea salt, or 2:1 for a milder version. Grind fine.",pairings:["celery_seed","dill_seed","mustard","black_pepper","sweet_paprika"],cuisines:["American","British","Eastern European"],nanaNote:"It's the soul of a Bloody Mary. Non-negotiable."},

  dashi_powder:{id:"dashi_powder",name:"Dashi Powder (Instant)",icon:"🌊",origin:"Japan — instant form of Japan's foundational stock",region:"eastasia",flavor:["umami","earthy","smoky"],intensity:2,form:"Powder",summary:"Instant dashi stock — the most convenient form of Japan's foundational umami liquid.",what:"A blend of dried bonito, kombu, and sometimes other umami ingredients, ground into an instant powder. While inferior to properly made dashi, it's a practical everyday ingredient that captures the fundamental character of the stock.",when:"Dissolve in hot water for quick miso soup, noodle broths, and dipping sauces. Use as a seasoning powder in stir-fries and braises. Add to egg dishes for Japanese flavour.",tip:"Don't boil it — dissolve in hot (not boiling) water to preserve the delicate flavour compounds.",pairings:["kombu_powder","bonito_flakes","miso_powder","sansho","sesame_toasted"],cuisines:["Japanese","Plant-adapted Japanese"],nanaNote:"Proper dashi takes 30 minutes. Instant dashi takes 30 seconds. Both have their place."},

  allium_black:{id:"allium_black",name:"Black Garlic Powder",icon:"⚫",origin:"Korea and global — slowly fermented whole garlic heads",region:"eastasia",flavor:["umami","earthy","floral"],intensity:2,form:"Dried powder",summary:"Sweet, molasses-dark, and deeply savoury — garlic after a slow transformation into something extraordinary.",what:"Black garlic is made by fermenting whole heads of garlic at controlled temperature and humidity for weeks until the cloves turn black and develop a complex, sweet-savory character with notes of balsamic, tamarind, and mild garlic. The powder concentrates all of this.",when:"Add to spice rubs and marinades for beef and lamb. Stir into compound butters. Use in sauces where you want savory depth without raw garlic's pungency.",tip:"Black garlic powder doesn't substitute directly for garlic powder — it's sweeter, more complex, and less sharp. It adds a different kind of depth.",pairings:["smoked_paprika","porcini_powder","miso_powder","sumac","black_pepper"],cuisines:["Korean","Modern European","Contemporary Asian fusion"],nanaNote:"Patience turned into a spice. Forty days of fermentation in a powder."},

  szechuan_cumin_blend:{id:"szechuan_cumin_blend",name:"Xi'an Cumin-Chili Blend",icon:"✨",origin:"Xi'an, China — the spice blend of the Muslim quarter street food",region:"eastasia",flavor:["blend","warm","pungent"],intensity:2,form:"Ground blend",summary:"Xi'an's famous street spice — heavy cumin, chili, and sesame that coats lamb skewers.",what:"The spice blend characteristic of Xi'an Muslim quarter cooking — heavy on cumin, dried chili flakes, sesame seeds, and salt. Used to coat lamb skewers (yang rou chuan) as they grill over charcoal. One of China's great street food seasonings.",when:"Press onto lamb, beef, and chicken skewers before or during grilling. Sprinkle over roasted cauliflower and eggplant. Add to stir-fried lamb dishes.",tip:"The ratio is roughly 2 parts cumin to 1 part chili flakes to 1 part sesame seeds, plus salt and a touch of Sichuan pepper.",pairings:["cumin","chile_de_arbol","sesame_toasted","sichuan_pepper","black_pepper"],cuisines:["Hui Chinese","Xi'an street food","Muslim Chinese"],nanaNote:"The smell of lamb skewers in the Xi'an night market is one of the great smells of the world. This is that smell."},

  peppercorn_blend:{id:"peppercorn_blend",name:"Mixed Peppercorn Blend",icon:"✨",origin:"Various — a convenience blend of multiple pepper varieties",region:"europe",flavor:["blend","pungent","floral"],intensity:2,form:"Whole mixed peppercorns",summary:"Four peppers together — practical, versatile, and better than single-pepper monotony.",what:"A blend typically containing black, white, green, and pink peppercorns in a single grinder. Provides complexity from multiple pepper types — the sharpness of black, the earthiness of white, the fresh brightness of green, and the delicate fruitiness of pink.",when:"Use in a dedicated pepper grinder for everyday finishing. Use in steak au poivre where multi-layered pepper heat is desirable.",tip:"Pink peppercorns can jam some grinders — check yours handles them before loading a full mix.",pairings:["black_pepper","white_pepper","pink_peppercorn","green_peppercorn","coriander"],cuisines:["French","American","Global"],nanaNote:"A good blend is better than bad individual peppers. A great individual pepper is better than a mediocre blend. Know which situation you're in."},

  green_peppercorn:{id:"green_peppercorn",name:"Green Peppercorn (Dried)",icon:"🟢",origin:"India and Southeast Asia — unripe Piper nigrum berries",region:"southasia",flavor:["pungent","bright","floral"],intensity:2,form:"Freeze-dried or brine-packed whole berry",summary:"Black pepper's fresh, uncured self — brighter, more floral, and with a greener heat.",what:"Green peppercorns are simply black peppercorns harvested before they ripen. Freeze-dried versions retain the fresh character best. The flavour is more vegetally bright than black pepper, with less of the resinous depth.",when:"Use in French pepper sauce (sauce au poivre vert). Crush over duck confit and grilled steak. Add to Thai preparations where fresh pepper berries would be used.",tip:"Freeze-dried green peppercorns are better than brine-packed for most applications — the brine adds saltiness that changes the dish's seasoning.",pairings:["black_pepper","white_pepper","pink_peppercorn","peppercorn_blend","cream"],cuisines:["French","Thai","Vietnamese","Contemporary"],nanaNote:"Fresh peppercorns off the vine taste nothing like dried ones. Green peppercorns come closest to that experience."},

  smoked_cumin:{id:"smoked_cumin",name:"Smoked Cumin",icon:"💨",origin:"Contemporary — cumin cold-smoked for extra depth",region:"europe",flavor:["smoky","warm","earthy"],intensity:2,form:"Ground powder",summary:"Cumin's earthy warmth wrapped in woodsmoke — a contemporary spice with immediate usefulness.",what:"Regular cumin that has been cold-smoked, typically over mesquite or oak, before grinding. The result combines cumin's characteristic warmth and earthiness with an additional smoky layer that deepens spice rubs, braises, and sauces.",when:"Use in BBQ spice rubs anywhere cumin and smoked paprika would both appear — this does both at once. Add to chili and bean dishes. Use in spice blends for grilled meats.",tip:"Not a traditional spice from any single cuisine — treat it as a convenient flavour combination for contemporary cooking.",pairings:["smoked_paprika","chipotle","garlic_powder","ancho","coriander"],cuisines:["American BBQ","Contemporary fusion","Southwestern"],nanaNote:"It's not ancient. It's useful. Not everything needs to be ancient."},

  amla_powder:{id:"amla_powder",name:"Amla Powder (Indian Gooseberry)",icon:"🟢",origin:"India — dried powder of Phyllanthus emblica fruit",region:"southasia",flavor:["bright","earthy"],intensity:2,form:"Dried powder",summary:"Intensely sour, slightly astringent, and rich in history — Ayurveda's most celebrated fruit as a spice.",what:"Amla (Indian gooseberry) dried and powdered. The flavour is intensely sour with a slightly bitter, astringent finish and a secondary sweetness that emerges after the initial sourness. One of the most important plants in Ayurvedic tradition.",when:"Add to chutneys and preserves. Use as a souring agent in place of amchur when you want something slightly more complex. Add to Ayurvedic spice preparations. Fold into spice blends for chaat.",tip:"Amla powder can be used like amchur but has a more complex, slightly astringent character. It also discolours preparations so use cautiously in light-coloured dishes.",pairings:["amchur","tamarind_powder","cumin","kala_namak","dried_mint"],cuisines:["North Indian","Ayurvedic tradition","Chaat street food"],nanaNote:"A fruit that tastes like a lesson. Intensely sour, then sweet, then lingering. Like most worthwhile things."},

  turmeric_black:{id:"turmeric_black",name:"Black Pepper-Turmeric Blend",icon:"🟡",origin:"South Asia — traditional co-preparation for bioavailability",region:"southasia",flavor:["warm","pungent","earthy"],intensity:2,form:"Blended powder",summary:"The ancient bio-hack — turmeric and black pepper together as they've been taken for centuries.",what:"A blend of ground turmeric and black pepper. Piperine in black pepper increases curcumin's bioavailability by up to 2,000%. This combination has been used in South Asian cooking and medicine for centuries — it appears in golden milk and many traditional preparations.",when:"Add to golden milk and turmeric lattes. Use in any preparation where turmeric is featured — the black pepper intensifies its effect. Add to curry bases.",tip:"A 20:1 ratio of turmeric to black pepper is traditional. The pepper should be present but not dominant.",pairings:["turmeric","ginger_powder","cardamom","cinnamon","coconut"],cuisines:["South Asian","Ayurvedic","Contemporary health"],nanaNote:"The ancient formulation had science behind it before science knew what science was."},

  laksa_spice:{id:"laksa_spice",name:"Laksa Spice Paste",icon:"✨",origin:"Singapore and Malaysia — the spice blend of the region's most complex noodle soup",region:"oceania",flavor:["blend","pungent","warm","floral"],intensity:2,form:"Paste or dried blend",summary:"The complex spice paste behind the most aromatic noodle soup in the world.",what:"Laksa paste combines dried shrimp or belacan, galangal, lemongrass, makrut lime leaf, turmeric, chili, and often candlenut. Each variation — Singaporean curry laksa, Penang asam laksa, Sarawak laksa — has its own version of the paste.",when:"Use as the base for laksa noodle soup. Fry in oil until fragrant before adding coconut milk or tamarind broth. Use as a seasoning for seafood and chicken.",tip:"Store-bought laksa paste varies enormously. Good brands from Singapore are worth seeking out for convenience.",pairings:["belacan_powder","lemongrass_dried","galangal","makrut_lime_leaf","turmeric"],cuisines:["Singaporean","Malaysian","Indonesian","Peranakan"],nanaNote:"There is no simple version of laksa. The complexity is the point."},

  recao:{id:"recao",name:"Recao (Culantro, Dried)",icon:"🌿",origin:"Caribbean and Central America — Eryngium foetidum",region:"northamerica",flavor:["herb","pungent"],intensity:2,form:"Dried leaf",summary:"Cilantro's more intense, heat-stable Caribbean cousin — the herb in every good sofrito.",what:"Recao (also called culantro or shadow beni) is a tropical herb with a flavour similar to cilantro but much more intense and far more heat-stable. Used widely in Caribbean, Central American, and Southeast Asian cooking. An essential component of Puerto Rican sofrito.",when:"Add to sofrito along with cilantro. Use in Trinidad green seasoning. Add to Caribbean stews and rice dishes.",tip:"Fresh recao is far better than dried. If you're in a Caribbean neighborhood, look for it fresh — it freezes well.",pairings:["sofrito_blend","dried_oregano","garlic_powder","adobo_seasoning","sazon"],cuisines:["Puerto Rican","Trinidad","Caribbean broadly","Central American"],nanaNote:"It smells like cilantro decided to become more serious about its work."},

  sumac_with_herbs:{id:"sumac_with_herbs",name:"Sumac & Herb Blend",icon:"✨",origin:"Levant — a contemporary blend popular in modern Middle Eastern cooking",region:"middleeast",flavor:["blend","bright","herb"],intensity:1,form:"Ground blend",summary:"Sumac's tartness extended with herbs — a quick shortcut to Levantine flavour.",what:"A blend of sumac, dried thyme or oregano, sesame seeds, and sometimes dried parsley or marjoram. A broader, more complex version of the core za'atar concept that leans more toward salad and vegetable seasoning.",when:"Use as a finishing seasoning for salads and roasted vegetables. Sprinkle over labneh and white cheeses. Add to olive oil for bread dipping.",tip:"Make your own from your existing spice rack — this kind of blend is better fresh.",pairings:["sumac","za_atar","dried_oregano","dried_mint","sesame_toasted"],cuisines:["Lebanese","Israeli","Modern Middle Eastern","Mediterranean fusion"],nanaNote:"A blend that exists because sumac is that good that people keep finding new ways to use it."},

  dried_fenugreek_flower:{id:"dried_fenugreek_flower",name:"Fenugreek Flower (Dried)",icon:"🌼",origin:"South Asia — the flower head of Trigonella foenum-graecum",region:"southasia",flavor:["floral","warm","earthy"],intensity:1,form:"Dried flower head",summary:"Fenugreek's gentle floral face — all the maple sweetness with less of the bitterness.",what:"The dried flower of the fenugreek plant has a gentler, more floral version of fenugreek's maple-like aroma without the seed's assertive bitterness. A rare and interesting ingredient in certain regional South Asian cooking traditions.",when:"Add to certain regional South Asian preparations where subtle fenugreek flavour is desired. Use in Ayurvedic herbal preparations. Crush and add to honey and ghee preparations.",tip:"A specialty ingredient not widely available. The leaves (kasuri methi) are a more practical substitute for most purposes.",pairings:["kasuri_methi","fenugreek","turmeric","cumin","cardamom"],cuisines:["Regional South Asian","Ayurvedic tradition"],nanaNote:"The seed gets all the fame. The flower is quieter and possibly more interesting."},

  salt_preserved_lemon:{id:"salt_preserved_lemon",name:"Preserved Lemon Powder",icon:"🟡",origin:"North Africa — the quintessential Moroccan ingredient, powdered",region:"africa",flavor:["bright","floral","umami"],intensity:2,form:"Dried powder",summary:"Preserved lemon's funk and brightness in dry form — the Moroccan ingredient made shelf-stable.",what:"Preserved lemon (whole lemons cured in salt and their own juice for weeks) develops a complex, deeply flavoured rind unlike fresh lemon. Dried and ground into powder, the result carries that fermented, floral-salty character in a convenient shelf-stable form.",when:"Add to spice rubs and dry marinades for chicken and lamb. Stir into hummus and yogurt. Use in North African-inspired spice blends and compound butters.",tip:"Start with half of what you'd use of fresh lemon zest — it's more concentrated and has the additional fermented dimension.",pairings:["cumin","coriander","ras_el_hanout","chermoula","smoked_paprika"],cuisines:["Moroccan","North African","Modern Mediterranean"],nanaNote:"Preserved lemons take a month to make. The powder takes a moment to use. Not the same experience, but close enough to be useful."},

  black_sesame:{id:"black_sesame",name:"Black Sesame",icon:"⚫",origin:"Africa and South Asia — the darker-hued sibling of white sesame",region:"asia",flavor:["earthy","warm","umami"],intensity:2,form:"Whole seed or paste",summary:"Earthier, more bitter, and more dramatic than white sesame — the visual and flavour statement.",what:"Black sesame seeds (Sesamum indicum) have their hull intact, giving them a more pronounced, slightly bitter, deeply nutty flavour compared to hulled white sesame. Used in East Asian sweets, Japanese cooking, and increasingly in contemporary baking.",when:"Toast and scatter over sushi, rice bowls, and noodle dishes. Use in Japanese black sesame paste sweets. Add to bread doughs and cracker coatings for dramatic visual contrast.",tip:"Don't substitute directly for white sesame — the more pronounced bitterness can dominate dishes where white sesame would be mild.",pairings:["sesame_toasted","ginger_powder","sansho","shichimi","miso_powder"],cuisines:["Japanese","Chinese","Korean","Contemporary baking"],nanaNote:"It turns anything it touches dramatically black. In cooking, sometimes spectacle is a legitimate goal."},

  kaffir_lime_zest:{id:"kaffir_lime_zest",name:"Makrut Lime Zest (Dried)",icon:"💚",origin:"Southeast Asia — the zest of Citrus hystrix fruit",region:"oceania",flavor:["bright","floral"],intensity:3,form:"Dried zest",summary:"The lime that smells like a flower — the zest is even more potent than the leaf.",what:"The dried outer rind of the makrut lime fruit, which is knobby and bumpy rather than smooth. Even more intensely aromatic than the leaf, with an extraordinary floral-citrus character. Used in Thai and Indonesian cooking.",when:"Add to curry pastes and spice blends where you want intense citrus-floral character. Use in Thai preparations calling for lime zest. Add to spice rubs for seafood.",tip:"Use very sparingly — it's more potent than any other citrus zest. A tiny amount in a curry paste goes a long way.",pairings:["makrut_lime_leaf","lemongrass_dried","galangal","bird_eye","turmeric"],cuisines:["Thai","Indonesian","Malaysian","Cambodian"],nanaNote:"The leaf is extraordinary. The zest is more extraordinary. They're from the same fruit, making different arguments."},

  dried_rose_hip:{id:"dried_rose_hip",name:"Dried Rose Hip",icon:"🔴",origin:"Europe, North Africa, and Asia — the fruit of Rosa canina and related species",region:"europe",flavor:["bright","floral","earthy"],intensity:2,form:"Dried whole or ground",summary:"Tart, fruity, and vitamin-rich — the wild fruit that becomes a souring spice.",what:"Rose hips are the seed pods of rose plants, harvested after the first frost when they're most flavorful. Dried and ground, they provide a tart, slightly floral, berry-like flavour used in Scandinavian, Turkish, and North African cooking.",when:"Use as a souring agent in Scandinavian fruit soups and sauces. Add to Turkish rose hip tea. Grind into North African spice blends. Use in game and venison preparations.",tip:"Remove the seeds and hairs from whole rose hips before use — the hairs can irritate the mouth and digestive system.",pairings:["hibiscus","barberry","rose_petals","cinnamon","cardamom"],cuisines:["Scandinavian","Turkish","North African","Central European"],nanaNote:"Wild food that tastes like something the forest is giving you. That quality doesn't have a substitute."},

  vietnamese_cinnamon:{id:"vietnamese_cinnamon",name:"Vietnamese Cinnamon (Saigon)",icon:"🪵",origin:"Vietnam — Cinnamomum loureiroi, the most intense cinnamon variety",region:"eastasia",flavor:["warm","pungent","floral"],intensity:3,form:"Ground bark or stick",summary:"The most intense cinnamon in the world — sweeter, spicier, and more complex than cassia.",what:"Vietnamese cinnamon (Cinnamomum loureiroi) is the highest in volatile oils of any commercial cinnamon variety. The flavour is intensely sweet, spicy, and complex — more cinnamon than cinnamon, with a warmth that builds and lingers. Sometimes called Saigon cinnamon.",when:"Use in recipes where bold cinnamon character is wanted — rolls, cookies, and spiced beverages. Use less than standard cassia — it's approximately twice as strong.",tip:"Because of its intensity, start with half the amount the recipe calls for if substituting for cassia or Ceylon.",pairings:["star_anise","cloves","cardamom","allspice","ginger_powder"],cuisines:["Vietnamese (pho)","American baking","Spiced beverages"],nanaNote:"It smells like cinnamon turned up to full volume. Some dishes need exactly that."},

  maqaw_pepper:{id:"maqaw_pepper",name:"Maqaw Pepper (Taiwan Mountain Pepper)",icon:"🟤",origin:"Taiwan — Litsea cubeba, native to Taiwan's indigenous mountain communities",region:"eastasia",flavor:["bright","floral","warm"],intensity:2,form:"Dried berry or ground",summary:"Taiwan's indigenous pepper — lemon-citrusy, floral, and with the gentlest of numbing qualities.",what:"Maqaw (Litsea cubeba) is a pepper-like spice from Taiwan's indigenous communities with a distinctly citrusy, lemon-floral character and a very mild numbing effect. Used in traditional Aboriginal Taiwanese cooking and increasingly in contemporary Taiwanese cuisine.",when:"Grind over grilled pork, venison, and mountain boar in traditional preparations. Add to contemporary Taiwanese spice blends. Use in spice rubs for chicken and pork.",tip:"It's subtle — use more than you would Sichuan pepper. The citrus-lemon character fades quickly; use relatively fresh.",pairings:["sichuan_pepper","sansho","lemon_myrtle","native_pepper","ginger_powder"],cuisines:["Taiwanese Aboriginal","Contemporary Taiwanese"],nanaNote:"Every indigenous culinary tradition has spices like this one — specific to the landscape, rarely exported. Worth knowing they exist."},

  gandule_seasoning:{id:"gandule_seasoning",name:"Gandules (Pigeon Pea) Spice",icon:"✨",origin:"Puerto Rico and the Caribbean — the seasoning blend for rice with pigeon peas",region:"northamerica",flavor:["blend","herb","earthy"],intensity:1,form:"Blended seasoning",summary:"The seasoning that makes arroz con gandules — one of Puerto Rico's most beloved dishes.",what:"A convenience seasoning blend for the classic Puerto Rican dish arroz con gandules (rice with pigeon peas). Typically combines annatto, garlic, oregano, and culantro/recao in proportions designed for the dish.",when:"Use specifically for arroz con gandules preparations. Can be used in other Puerto Rican rice and bean dishes.",tip:"Sofrito and sazón used together accomplish what this blend does — making your own from those components gives more control.",pairings:["sazon","adobo_seasoning","sofrito_blend","annatto","garlic_powder"],cuisines:["Puerto Rican"],nanaNote:"Arroz con gandules is the flavor of Christmas in Puerto Rico. This is the spice behind it."},

  baharat_sweet:{id:"baharat_sweet",name:"Sweet Baharat (for Desserts)",icon:"✨",origin:"Middle East — the dessert-oriented variant of baharat",region:"middleeast",flavor:["blend","warm","floral"],intensity:1,form:"Ground blend",summary:"Baharat's sweeter, more delicate cousin — warm spices calibrated for Middle Eastern sweets and pastries.",what:"A baharat variant with higher proportions of cinnamon, cardamom, rose water, and vanilla-adjacent spices relative to the savoury components like black pepper. Used in Middle Eastern pastries, milk puddings, and dessert preparations.",when:"Add to knafeh and qatayef fillings. Season Arab milk puddings and rice desserts. Use in pastry doughs for Middle Eastern sweets.",tip:"Don't use regular baharat (which is savoury-forward) in desserts — this version is calibrated for sweet applications.",pairings:["cardamom","rose_petals","mastic","vanilla","cinnamon"],cuisines:["Lebanese","Syrian","Palestinian","Arab dessert tradition"],nanaNote:"Every cuisine has its dessert spice blend. This is one of the most beautiful."},

  dried_galangal_powder:{id:"dried_galangal_powder",name:"Galangal Powder (Fine Ground)",icon:"🟡",origin:"Southeast Asia — fine-ground dried galangal for spice blends",region:"oceania",flavor:["pungent","bright","floral"],intensity:2,form:"Fine ground powder",summary:"Galangal in its most accessible form — piney, eucalyptus-bright, and ready for blending.",what:"Galangal dried and ground to a fine powder, making it easier to incorporate into spice blends and dry rubs without the texture of whole dried slices. Useful in dry applications where rehydration isn't practical.",when:"Use in dry spice rubs for Southeast Asian preparations. Add to curry powder blends. Use in dry spice mixes for satay and other grilled preparations.",tip:"The powder is more convenient but less complex than dried slices — for sauces and soups, slices rehydrated are better.",pairings:["lemongrass_dried","turmeric","makrut_lime_leaf","bird_eye","coriander"],cuisines:["Thai","Indonesian","Malaysian","Cambodian"],nanaNote:"Convenience matters in a working kitchen. Sometimes the powder is the answer."},

  mountain_pepper_blend:{id:"mountain_pepper_blend",name:"Alpine Spice Blend",icon:"✨",origin:"Austria, Switzerland, and Alpine regions — mountain herbs and spices",region:"europe",flavor:["blend","herb","warm","bright"],intensity:2,form:"Dried blend",summary:"The spices of the mountain kitchen — juniper, caraway, bay, and wild herbs in harmony.",what:"The spice traditions of the Alpine region combine juniper berries, caraway, dried wild herbs (gentian, alpine thyme, mountain savory), and black pepper into blends suited to the cuisine of wild game, cured meats, and robust stews that define alpine cooking.",when:"Use in wild game and venison preparations. Season alpine-style charcuterie and cured meats. Add to hearty mountain stews and potato dishes.",tip:"Each Alpine country and region has its own blend character — Austrian, Swiss, and Bavarian versions all differ.",pairings:["juniper_berry","caraway","bay_leaf","dried_rosemary","black_pepper"],cuisines:["Austrian","Swiss","Bavarian","Alpine broadly"],nanaNote:"Mountain cooking is honest cooking. The spices here reflect that."},

  szechuan_peppercorn_green:{id:"szechuan_peppercorn_green",name:"Green Sichuan Pepper",icon:"🟢",origin:"Sichuan province, China — the younger harvest of Zanthoxylum armatum",region:"eastasia",flavor:["floral","bright","pungent"],intensity:3,form:"Whole dried or ground",summary:"Sichuan pepper's younger, greener, more citrusy version — lighter numbing, brighter flavour.",what:"Green Sichuan peppercorns are harvested younger than the red-brown variety and have a notably different flavour profile — brighter, more citrusy, with a slightly lighter numbing effect and more pronounced green-herbal notes. Used in more delicate Sichuan preparations.",when:"Use in fish preparations and lighter meats where the full red Sichuan pepper would be too heavy. Add to certain Sichuan cold dishes and lighter sauces.",tip:"Green and red Sichuan peppers are not interchangeable — the green is brighter and more delicate. Choose based on application.",pairings:["sichuan_pepper","ginger_powder","white_pepper","star_anise","togarashi"],cuisines:["Sichuan Chinese","Taiwanese","Contemporary Asian"],nanaNote:"The red one numbs. The green one also numbs, but first it makes you notice the citrus."},

  hawaii_blend:{id:"hawaii_blend",name:"Hawaiian Plate Seasoning",icon:"✨",origin:"Hawaii — the fusion spice tradition of the islands",region:"northamerica",flavor:["blend","umami","warm"],intensity:1,form:"Ground blend",summary:"The Pacific melting pot in a blend — Japanese, Chinese, Korean, and Polynesian influences together.",what:"Hawaiian plate seasoning reflects the unique multicultural food history of Hawaii — blending soy-savory elements, sesame, ginger, and garlic from East Asian traditions with local sea salt and sometimes chili. Used on plate lunch preparations.",when:"Season grilled meats and fish for plate lunch-style preparations. Add to rice and noodle dishes. Use as an all-purpose seasoning for Pacific-influenced cooking.",tip:"Make your own: garlic powder, ginger powder, sesame, a pinch of Chinese five spice, and good sea salt.",pairings:["sesame_toasted","ginger_powder","garlic_powder","chinese_five_spice","hawaiian_sea_salt"],cuisines:["Hawaiian","Hawaiian plate lunch tradition","Pacific fusion"],nanaNote:"Hawaii is where every influence that passed through the Pacific landed and learned to get along."},

  dried_chili_threads:{id:"dried_chili_threads",name:"Dried Chili Threads (Silgochu)",icon:"🔴",origin:"Korea — the garnish chili of Korean cuisine",region:"eastasia",flavor:["smoky","bright"],intensity:1,form:"Fine dried threads",summary:"Korea's visual spice — thin, brilliant red threads that garnish and subtly season.",what:"Silgochu are Korean dried red chili threads — the flesh of dried red chilies cut into extremely fine threads. They're mildly spicy and mostly used as a visual garnish, adding a professional finishing touch to Korean dishes.",when:"Garnish bibimbap, japchae, and other Korean presentations. Add to cold noodle dishes. Use as a finishing element on any Korean preparation that needs visual lift.",tip:"They add visual impact and mild chili flavour but are not a substitute for gochugaru. Their primary role is finishing and presentation.",pairings:["gochugaru","sesame_toasted","sansho","shichimi","ginger_powder"],cuisines:["Korean"],nanaNote:"It's the garnish that says someone cared about how the dish looked. That matters."},

  fermented_black_bean:{id:"fermented_black_bean",name:"Fermented Black Bean (Douchi)",icon:"⚫",origin:"China — salted fermented soybean, one of the oldest condiments",region:"eastasia",flavor:["umami","pungent","earthy"],intensity:3,form:"Whole dried fermented beans",summary:"China's oldest umami bomb — salty, funky, and transformative in stir-fries and braises.",what:"Douchi (fermented black beans) are soybeans fermented with salt and sometimes spices until they develop an intensely savoury, slightly funky character. One of the oldest recorded condiments in China, dating back 2,000 years.",when:"Use in classic Cantonese black bean sauce for spare ribs. Add to stir-fries with beef and broccoli. Use in doubanjiang-free Sichuan preparations for umami depth.",tip:"Rinse briefly before use to reduce excess salt. A little goes a long way — a tablespoon seasons a dish for four.",pairings:["sichuan_pepper","ginger_powder","star_anise","white_pepper","garlic_powder"],cuisines:["Cantonese","Sichuan","Hakka","Chinese broadly"],nanaNote:"Two thousand years of fermentation knowledge in a small jar. Respect that."},

};
